function normalize(text) {
  return text
    .toLowerCase()
    .normalize("NFD")
    .replace(/[^\w\s]/g, "")
    .trim();
}

function localizedArtistGenreHint(artistName = "", styleHint = "") {
  const key = artistMatchKey(artistName || "");
  const direct = key ? ARTIST_GENRE_HINT_OVERRIDES[key] : null;
  if (direct && typeof direct === "object") {
    return String(direct[currentLanguage] || direct.pt || direct.en || direct.es || "").trim();
  }
  if (typeof direct === "string") return String(direct).trim();
  if (!styleHint) return "";
  return styleLabelByValue(styleHint);
}

function artistSeedAllowedForStyle(style, artistName) {
  if (textHasForbiddenSignalsForStyle(style, artistName)) return false;
  if (isCuratorBlockedArtistName(artistName)) return false;
  const strictWhitelist = STYLE_STRICT_WHITELISTS[style] || [];
  if (strictWhitelist.length && !strictWhitelist.some((seed) => isArtistMatch(artistName, seed))) {
    return false;
  }
  const blocked = (STYLE_ARTIST_BLOCKLIST[style] || []).some((name) => isArtistMatch(artistName, name));
  if (blocked) return false;
  const styleOverride = allowedStylesForArtist(artistName);
  if (styleOverride.length && !styleOverride.includes(style)) return false;
  return true;
}

function ensureMinimumArtistSeedsPerStyle(minArtists = 20) {
  Object.keys(STYLE_ARTIST_SEEDS).forEach((style) => {
    const pool = new Set((STYLE_ARTIST_SEEDS[style] || []).map((name) => String(name).trim()).filter(Boolean));
    const addMany = (names = []) => names.forEach((name) => name && pool.add(String(name).trim()));

    addMany(STYLE_SEED_BACKFILL[style] || []);
    if (!LOCK_SEED_FROM_CATALOG_STYLES.has(style)) {
      addMany(discoveryCatalog.filter((item) => item.style === style).map((item) => item.name));
      addMany(catalog.filter((track) => track.style === style).map((track) => track.artist));
    }

    if (pool.size < minArtists && !STRICT_FAMILY_SEED_STYLES.has(style)) {
      const family = familyOf(style);
      addMany(FAMILY_SEED_FALLBACK[family] || []);
    }

    const filteredPool = Array.from(pool).filter((artist) => artistSeedAllowedForStyle(style, artist));
    const finalPool = filteredPool.length ? filteredPool : Array.from(pool);
    STYLE_ARTIST_SEEDS[style] = finalPool.slice(0, Math.max(minArtists, finalPool.length));
  });
}

function mapBpmToRange(exactBpm) {
  if (!Number.isFinite(exactBpm) || exactBpm <= 0) return "";
  if (exactBpm >= 175) return "175+";
  if (exactBpm >= 155) return "155-175";
  if (exactBpm >= 145) return "145-155";
  if (exactBpm >= 132) return "132-145";
  if (exactBpm >= 124) return "124-132";
  if (exactBpm >= 110) return "110-124";
  return "60-110";
}

function parseBpmRangeValue(value) {
  const raw = String(value || "").trim();
  if (!raw) return null;
  if (/^\d{2,3}\+$/.test(raw)) {
    const min = Number(raw.replace("+", ""));
    return Number.isFinite(min) ? { min, max: 999 } : null;
  }
  const rangeMatch = raw.match(/^(\d{2,3})\s*-\s*(\d{2,3})$/);
  if (rangeMatch) {
    const min = Number(rangeMatch[1]);
    const max = Number(rangeMatch[2]);
    if (!Number.isFinite(min) || !Number.isFinite(max)) return null;
    return { min: Math.min(min, max), max: Math.max(min, max) };
  }
  if (/^\d{2,3}(?:\.\d+)?$/.test(raw)) {
    const valueNum = Number(raw);
    if (!Number.isFinite(valueNum)) return null;
    const rounded = Math.round(valueNum);
    return { min: rounded, max: rounded };
  }
  return null;
}

function bpmRangesOverlap(a, b) {
  if (!a || !b) return false;
  return a.min <= b.max && b.min <= a.max;
}

const VALID_CONTEXT_VALUES = new Set([
  "warmup",
  "peak",
  "after",
  "foco",
  "estudo",
  "relaxar",
  "criatividade",
  "trabalho",
  "treino",
  "estrada",
  "casa",
  "social",
  "noite"
]);
const VALID_ENERGY_VALUES = new Set(["low", "mid", "high", "extreme"]);
const VALID_VOCAL_VALUES = new Set(["instrumental", "light_vocals", "vocal"]);

function normalizeRecommendationPrefs(prefs = {}) {
  const contextAliases = {
    focus: "foco",
    deep_focus: "foco",
    work: "trabalho",
    creative_work: "trabalho",
    workout: "treino",
    gym: "treino",
    road: "estrada",
    travel: "estrada",
    relax: "relaxar",
    relaxing: "relaxar",
    chill: "relaxar",
    study: "estudo",
    studying: "estudo",
    creative: "criatividade",
    creativity: "criatividade",
    create: "criatividade",
    home: "casa",
    house_home: "casa",
    party: "social",
    friends: "social",
    night: "noite",
    evening: "noite"
  };
  const energyAliases = { medium: "mid", med: "mid" };
  const vocalAliases = { light: "light_vocals", light_vocal: "light_vocals", strong: "vocal", mixed: "" };
  const style = normalizeDatasetStyle(prefs?.style || "");
  const rawContext = normalize(prefs?.context || "");
  const context = contextAliases[rawContext] || rawContext;
  const rawEnergy = normalize(prefs?.energy || "");
  const energy = energyAliases[rawEnergy] || rawEnergy;
  const rawVocals = normalize(prefs?.vocals || "");
  const vocals = vocalAliases[rawVocals] ?? rawVocals;
  const bpm = String(prefs?.bpm || "").trim();

  return {
    ...prefs,
    style: style && STYLE_BPM_RULES[style] ? style : "",
    context: VALID_CONTEXT_VALUES.has(context) ? context : "",
    energy: VALID_ENERGY_VALUES.has(energy) ? energy : "",
    bpm: parseBpmRangeValue(bpm) ? bpm : "",
    vocals: VALID_VOCAL_VALUES.has(vocals) ? vocals : ""
  };
}

function normalizeDatasetStyle(rawStyle = "") {
  const input = String(rawStyle || "").trim();
  if (!input) return "";
  if (STYLE_BPM_RULES[input]) return input;

  const normalized = normalize(input).replace(/\s+/g, " ").trim();
  if (!normalized) return "";
  if (STYLE_BPM_RULES[normalized]) return normalized;

  const underscored = normalized.replace(/\s+/g, "_");
  if (STYLE_BPM_RULES[underscored]) return underscored;

  const compact = normalized.replace(/\s+/g, "");
  if (DATASET_STYLE_ALIASES[compact]) return DATASET_STYLE_ALIASES[compact];
  if (DATASET_STYLE_ALIASES[normalized]) return DATASET_STYLE_ALIASES[normalized];

  if (compact.includes("fullon") && compact.includes("night")) return "full_on_night";
  if (compact.includes("fullon") && compact.includes("morning")) return "full_on_morning";
  if (compact.includes("fullon")) return "full_on";
  if (compact.includes("hitech")) return "hi_tech";
  if (compact.includes("psycore")) return "psycore";
  if (compact.includes("slambient")) return "slambient";
  if (compact.includes("darkexperimental")) return "dark_experimental";
  if (compact.includes("darkprogressive")) return "dark_progressive";
  if (compact.includes("darkpsy")) return "dark_psy";
  if (compact.includes("forest")) return "forest_psy";
  if (compact.includes("progressivepsy")) return "progressive_psy";
  if (compact.includes("psycomercial") || compact.includes("psycommercial") || compact.includes("chacota")) {
    return "psy_comercial";
  }
  if (compact.includes("acidtechno")) return "acid_techno";
  if (compact.includes("hardtechno")) return "hard_techno";
  if (compact.includes("minimaltechno")) return "minimal_techno";
  if (compact.includes("melodictechno")) return "melodic_techno";
  if (compact.includes("industrialtechno")) return "industrial_techno";
  if (compact.includes("peaktimetechno")) return "peak_time_techno";
  if (compact.includes("drumandbass")) return "drum_and_bass";
  if (compact.includes("liquiddnb")) return "liquid_dnb";
  if (compact.includes("jumpup")) return "jump_up";
  if (compact.includes("ukgarage")) return "uk_garage";
  if (compact.includes("futuregarage")) return "future_garage";
  if (compact.includes("goatrance")) return "goa_trance";
  if (compact.includes("upliftingtrance")) return "trance_uplifting";
  if (compact.includes("psytrance")) return "psytrance";
  if (compact === "psy") return "psytrance";
  return "";
}

function parseDatasetDelimitedRows(text, delimiter = ",") {
  const rows = [];
  let row = [];
  let value = "";
  let inQuotes = false;

  for (let index = 0; index < text.length; index += 1) {
    const char = text[index];

    if (char === "\"") {
      if (inQuotes && text[index + 1] === "\"") {
        value += "\"";
        index += 1;
      } else {
        inQuotes = !inQuotes;
      }
      continue;
    }

    if (!inQuotes && char === delimiter) {
      row.push(value);
      value = "";
      continue;
    }

    if (!inQuotes && (char === "\n" || char === "\r")) {
      if (char === "\r" && text[index + 1] === "\n") index += 1;
      row.push(value);
      if (row.some((cell) => String(cell || "").trim())) rows.push(row);
      row = [];
      value = "";
      continue;
    }

    value += char;
  }

  row.push(value);
  if (row.some((cell) => String(cell || "").trim())) rows.push(row);
  return rows;
}

function parseDatasetCsvRecords(text) {
  const safeText = String(text || "").replace(/^\uFEFF/, "");
  if (!safeText.trim()) return [];

  const firstLine = safeText.split(/\r?\n/).find((line) => String(line || "").trim()) || "";
  const commaCount = (firstLine.match(/,/g) || []).length;
  const semicolonCount = (firstLine.match(/;/g) || []).length;
  const delimiter = semicolonCount > commaCount ? ";" : ",";

  const rows = parseDatasetDelimitedRows(safeText, delimiter);
  if (rows.length < 2) return [];

  const headers = rows[0].map((header, headerIndex) => {
    const value = String(header || "").trim();
    return value || `column_${headerIndex}`;
  });

  return rows
    .slice(1)
    .map((cells) => {
      const row = {};
      headers.forEach((header, idx) => {
        row[header] = String(cells[idx] || "").trim();
      });
      return row;
    })
    .filter((row) => Object.values(row).some((value) => String(value || "").trim()));
}

function parseDatasetJsonlRecords(text) {
  const safeText = String(text || "").replace(/^\uFEFF/, "");
  if (!safeText.trim()) return [];
  const rows = [];

  safeText.split(/\r?\n/).forEach((line) => {
    const raw = String(line || "").trim();
    if (!raw) return;
    try {
      const parsed = JSON.parse(raw);
      if (parsed && typeof parsed === "object") rows.push(parsed);
    } catch (_err) {
      // ignora linhas inválidas
    }
  });

  return rows;
}

function datasetRowsFromJsonPayload(payload) {
  if (Array.isArray(payload)) return payload;
  if (!payload || typeof payload !== "object") return [];

  const buckets = ["tracks", "songs", "items", "rows", "artists", "data"];
  for (const bucket of buckets) {
    if (Array.isArray(payload[bucket])) return payload[bucket];
  }
  return [payload];
}

function normalizeDatasetFieldKey(key) {
  return normalize(String(key || "")).replace(/\s+/g, "_");
}

function datasetFieldMap(row) {
  const map = new Map();
  Object.entries(row || {}).forEach(([key, value]) => {
    const normalizedKey = normalizeDatasetFieldKey(key);
    if (!normalizedKey || map.has(normalizedKey)) return;
    map.set(normalizedKey, value);
  });
  return map;
}

function pickDatasetValue(fieldMap, keys = []) {
  for (const key of keys) {
    const normalizedKey = normalizeDatasetFieldKey(key);
    const value = fieldMap.get(normalizedKey);
    const text = String(value == null ? "" : value).trim();
    if (text) return text;
  }
  return "";
}

function parseDatasetBpm(value = "") {
  const raw = String(value || "").trim().replace(",", ".");
  if (!raw) return 0;
  const compact = raw.replace(/[–—]/g, "-");
  if (/^\d{2,3}(?:\.\d+)?$/.test(compact)) return Math.round(Number(compact));
  const rangeMatch = compact.match(/(\d{2,3})(?:\.\d+)?\s*-\s*(\d{2,3})(?:\.\d+)?/);
  if (rangeMatch) {
    const min = Number(rangeMatch[1]);
    const max = Number(rangeMatch[2]);
    if (Number.isFinite(min) && Number.isFinite(max)) return Math.round((min + max) / 2);
  }
  const candidates = Array.from(compact.matchAll(/(\d{2,3})(?:\.\d+)?/g))
    .map((match) => Number(match[1]))
    .filter((num) => Number.isFinite(num) && num >= 60 && num <= 280);
  if (candidates.length === 1) return Math.round(candidates[0]);
  if (candidates.length >= 2) {
    const min = Math.min(...candidates);
    const max = Math.max(...candidates);
    return Math.round((min + max) / 2);
  }
  return 0;
}

function parseDatasetDurationSeconds(value = "") {
  const raw = String(value || "").trim();
  if (!raw) return 0;

  if (/^\d+(?:\.\d+)?$/.test(raw)) {
    const numeric = Number(raw);
    if (!Number.isFinite(numeric) || numeric <= 0) return 0;
    if (numeric > 10000) return Math.round(numeric / 1000);
    return Math.round(numeric);
  }

  const parts = raw.split(":").map((part) => Number(part.trim()));
  if (parts.some((part) => !Number.isFinite(part))) return 0;
  if (parts.length === 2) return parts[0] * 60 + parts[1];
  if (parts.length === 3) return parts[0] * 3600 + parts[1] * 60 + parts[2];
  return 0;
}

function normalizeDatasetReleaseDate(value = "") {
  const raw = String(value || "").trim();
  if (!raw) return "Catálogo dinâmico";
  // Ano sem mês/dia: assume fim do ano para não excluir lançamentos recentes por falta de granularidade.
  if (/^\d{4}$/.test(raw)) return `${raw}-12-31`;
  const parsed = new Date(raw);
  if (Number.isNaN(parsed.getTime())) return raw;
  return parsed.toISOString().slice(0, 10);
}

function extractUrlsFromLooseText(value = "") {
  const raw = String(value || "");
  if (!raw) return [];
  const matches = raw.match(/https?:\/\/[^\s<>()]+/gi) || [];
  return matches
    .map((url) => url.replace(/[),.;]+$/, "").trim())
    .filter(Boolean);
}

function normalizeDatasetSlugToTitle(slug = "", artistName = "") {
  let decoded = String(slug || "").trim();
  if (!decoded) return "";
  try {
    decoded = decodeURIComponent(decoded);
  } catch (_err) {
    // segue com o valor bruto
  }
  let clean = decoded
    .replace(/\.(mp3|wav|flac|aiff|m4a|ogg)$/i, "")
    .replace(/[._]+/g, " ")
    .replace(/-/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  if (!clean) return "";

  const artistRaw = String(artistName || "").trim();
  if (artistRaw && clean.toLowerCase().startsWith(`${artistRaw.toLowerCase()} `)) {
    clean = clean.slice(artistRaw.length).trim();
  }
  if (!clean) return "";

  const titled = clean
    .split(" ")
    .map((part) => {
      if (!part) return part;
      if (/^[a-z]{1,2}$/i.test(part)) return part.toUpperCase();
      return `${part.charAt(0).toUpperCase()}${part.slice(1)}`;
    })
    .join(" ")
    .trim();
  if (!titled || titled.length < 2 || titled.length > 96) return "";
  const compactNumeric = titled.replace(/\s+/g, "");
  if (/^\d+$/.test(compactNumeric)) return "";
  const digitCount = (titled.match(/\d/g) || []).length;
  if (digitCount >= Math.max(4, Math.floor(titled.length * 0.5))) return "";
  if (hasSuspiciousDynamicText(titled) || isLikelyGeneratedTrackTitle(titled)) return "";
  return titled;
}

function extractTrackTitleFromDatasetUrl(rawUrl = "", artistName = "") {
  const value = String(rawUrl || "").trim();
  if (!value) return "";
  try {
    const parsed = new URL(value);
    const host = normalize(parsed.hostname || "");
    const hostAllowed = host.includes("soundcloud") || host.includes("bandcamp");
    if (!hostAllowed) return "";
    const segments = String(parsed.pathname || "")
      .split("/")
      .map((segment) => String(segment || "").trim())
      .filter(Boolean);
    if (!segments.length) return "";

    const normalizedSegments = segments.map((segment) => normalize(segment));
    let slug = "";

    if (host.includes("soundcloud")) {
      // Formato comum: /artist/track; ignora rotas de sets/playlists.
      if (normalizedSegments.includes("sets")) return "";
      slug = segments[segments.length - 1] || "";
    } else if (host.includes("bandcamp")) {
      const idx = normalizedSegments.findIndex((segment) => segment === "track");
      if (idx >= 0 && segments[idx + 1]) slug = segments[idx + 1];
    } else if (host.includes("spotify")) {
      return "";
    } else if (host.includes("youtube") || host.includes("youtu.be")) {
      return "";
    } else {
      const tail = normalizedSegments[normalizedSegments.length - 2] || "";
      if (["track", "faixa", "song", "musica", "release"].includes(tail)) {
        slug = segments[segments.length - 1] || "";
      } else {
        slug = segments[segments.length - 1] || "";
      }
    }

    const slugKey = normalize(slug);
    if (!slug || !slugKey) return "";
    if (
      /\b(artist|artists|search|set|sets|playlist|playlists|album|albums|channel|channels|mix|full|recording|session|live)\b/.test(
        slugKey
      )
    ) {
      return "";
    }

    return normalizeDatasetSlugToTitle(slug, artistName);
  } catch (_err) {
    return "";
  }
}

function deriveDatasetSongCandidate(rawRow = {}, fieldMap = new Map(), artistName = "") {
  const directCandidate = pickDatasetValue(fieldMap, [
    "song",
    "track",
    "track_name",
    "title",
    "faixa",
    "music",
    "featured_track",
    "notable_track",
    "single"
  ]);
  const safeDirect = String(directCandidate || "").trim();
  if (safeDirect && !hasSuspiciousDynamicText(safeDirect) && !isLikelyGeneratedTrackTitle(safeDirect)) {
    return safeDirect;
  }

  const bio = rawRow?.bio && typeof rawRow.bio === "object" ? rawRow.bio : {};
  const urlHints = [
    pickDatasetValue(fieldMap, ["source", "url", "link", "track_url", "reference", "lookup"]),
    String(rawRow?.source || ""),
    String(rawRow?.lookup || ""),
    String(rawRow?.url || ""),
    String(rawRow?.link || ""),
    String(rawRow?.reference || ""),
    String(rawRow?.references || ""),
    String(bio?.primarySources || "")
  ]
    .filter(Boolean)
    .join(" ");

  const urls = extractUrlsFromLooseText(urlHints);
  for (const url of urls) {
    const title = extractTrackTitleFromDatasetUrl(url, artistName);
    if (title) return title;
  }
  return "";
}

function extractDateFromLooseText(value = "") {
  const raw = String(value || "").trim();
  if (!raw) return "";

  const dateMatches = raw.match(/\b(20\d{2}|19\d{2})[-/.](0[1-9]|1[0-2])[-/.](0[1-9]|[12]\d|3[01])\b/g) || [];
  if (dateMatches.length) {
    const normalized = dateMatches
      .map((item) => item.replace(/[/.]/g, "-"))
      .map((item) => {
        const parsed = parseReleaseDateSafe(item);
        return parsed ? parsed.toISOString().slice(0, 10) : "";
      })
      .filter(Boolean)
      .sort();
    if (normalized.length) return normalized[normalized.length - 1];
  }

  const namedDateMatches = raw.match(/\b([0-3]?\d\s+[A-Za-z]{3,9}\s+(20\d{2}|19\d{2}))\b/g) || [];
  if (namedDateMatches.length) {
    const normalized = namedDateMatches
      .map((item) => parseReleaseDateSafe(item))
      .filter(Boolean)
      .map((date) => date.toISOString().slice(0, 10))
      .sort();
    if (normalized.length) return normalized[normalized.length - 1];
  }

  const yearMatches = raw.match(/\b(20\d{2}|19\d{2})\b/g) || [];
  if (yearMatches.length) {
    const latestYear = Math.max(...yearMatches.map((year) => Number(year)));
    if (Number.isFinite(latestYear)) return `${latestYear}-12-31`;
  }

  const parsed = parseReleaseDateSafe(raw);
  if (parsed) return parsed.toISOString().slice(0, 10);
  return "";
}

function extractRecentReleaseDateFromDatasetRow(rawRow = {}, fieldMap = new Map()) {
  const pick = (keys = []) => pickDatasetValue(fieldMap, keys);
  const bio = rawRow?.bio && typeof rawRow.bio === "object" ? rawRow.bio : {};
  const verification = rawRow?.verification && typeof rawRow.verification === "object" ? rawRow.verification : {};
  const bioVerification = bio?.verification && typeof bio.verification === "object" ? bio.verification : {};

  const candidates = [
    pick(["release_date", "released", "date", "year", "ano", "latest_release", "last_release", "recent_release", "recent_releases"]),
    String(rawRow?.recentReleases || ""),
    String(rawRow?.recentRelease || ""),
    String(rawRow?.recent_releases || ""),
    String(rawRow?.latestRelease || ""),
    String(rawRow?.latest_release || ""),
    String(rawRow?.lastRelease || ""),
    String(rawRow?.last_release || ""),
    String(rawRow?.verifiedOn || ""),
    String(verification?.verifiedOn || ""),
    String(bio?.recentReleases || ""),
    String(bio?.recentRelease || ""),
    String(bio?.recent_releases || ""),
    String(bioVerification?.verifiedOn || "")
  ].filter((value) => String(value || "").trim());

  let bestDate = "";
  let bestTimestamp = 0;
  const maxFutureSlackMs = 3 * 24 * 60 * 60 * 1000;
  const now = Date.now();

  candidates.forEach((candidate) => {
    const extracted = extractDateFromLooseText(candidate);
    if (!extracted) return;
    const parsed = parseReleaseDateSafe(extracted);
    if (!parsed) return;
    const timestamp = parsed.getTime();
    if (timestamp > now + maxFutureSlackMs) return;
    if (timestamp > bestTimestamp) {
      bestTimestamp = timestamp;
      bestDate = extracted;
    }
  });

  return bestDate;
}

function registerRecentArtistSignal(style, artistName, releaseDate, source = "dataset") {
  const styleKey = String(style || "").trim();
  const artist = String(artistName || "").trim();
  if (!styleKey || !artist) return;
  if (!STYLE_BPM_RULES[styleKey]) return;

  const parsed = parseReleaseDateSafe(releaseDate);
  if (!parsed) return;
  const normalizedDate = parsed.toISOString().slice(0, 10);

  const key = `${styleKey}::${normalize(artist)}`;
  const existing = recentArtistSignals.get(key);
  if (!existing) {
    recentArtistSignals.set(key, {
      style: styleKey,
      artist,
      releaseDate: normalizedDate,
      source
    });
    return;
  }

  const existingDate = parseReleaseDateSafe(existing.releaseDate);
  if (!existingDate || parsed > existingDate) {
    recentArtistSignals.set(key, {
      style: styleKey,
      artist,
      releaseDate: normalizedDate,
      source
    });
  }
}

function seedStyleArtistFromDataset(style, artistName) {
  const artist = String(artistName || "").trim();
  if (!style || !artist) return false;
  if (isCuratorBlockedArtistName(artist)) return false;
  if (!artistSeedAllowedForStyle(style, artist)) return false;

  if (!Array.isArray(STYLE_ARTIST_SEEDS[style])) STYLE_ARTIST_SEEDS[style] = [];
  const exists = STYLE_ARTIST_SEEDS[style].some((seed) => isArtistMatch(artist, seed) || isArtistMatch(seed, artist));
  if (exists) return false;
  STYLE_ARTIST_SEEDS[style].push(artist);
  return true;
}

function upsertArtistOverridesFromDataset(style, artistName) {
  const artistKey = normalize(artistName || "");
  if (!style || !artistKey) return;
  if (isCuratorBlockedArtistName(artistName)) return;
  if (!Array.isArray(ARTIST_STYLE_OVERRIDES[artistKey])) ARTIST_STYLE_OVERRIDES[artistKey] = [];
  if (LOCKED_ARTIST_STYLE_OVERRIDES.has(artistKey) && !ARTIST_STYLE_OVERRIDES[artistKey].includes(style)) return;
  if (!ARTIST_STYLE_OVERRIDES[artistKey].includes(style)) ARTIST_STYLE_OVERRIDES[artistKey].push(style);
}

function upsertArtistOriginFromDataset(artistName, country = "", area = "") {
  const artistKey = normalize(artistName || "");
  if (!artistKey) return;
  const safeCountry = String(country || "").trim();
  const safeArea = String(area || "").trim();
  if (!safeCountry && !safeArea) return;

  const current = ARTIST_CANONICAL_ORIGINS[artistKey] || {};
  ARTIST_CANONICAL_ORIGINS[artistKey] = {
    country: current.country || safeCountry || "",
    area: current.area || safeArea || "",
    disambiguation: current.disambiguation || ""
  };
}

function upsertDiscoveryFromDataset(style, artistName, bio = "") {
  const artist = String(artistName || "").trim();
  if (!style || !artist) return false;
  if (isCuratorBlockedArtistName(artist)) return false;

  const artistKey = normalize(artist);
  const existing = discoveryCatalog.find(
    (item) => normalize(item.name) === artistKey && item.style === style
  );
  if (existing) {
    if (bio && String(bio).trim().length > String(existing.bio || "").trim().length) {
      existing.bio = String(bio).trim();
    }
    return false;
  }

  const styleLabel = styleLabelByValue(style);
  discoveryCatalog.push({
    name: artist,
    style,
    bio: String(bio || "").trim() || `${artist} aparece em base externa para ${styleLabel}.`,
    spotifyUrl: `https://open.spotify.com/search/${encodeURIComponent(artist)}`,
    youtubeUrl: `https://www.youtube.com/results?search_query=${encodeURIComponent(`${artist} ${styleLabel}`)}`
  });
  return true;
}

function catalogExtraRowText(row = {}, key = "") {
  return String(row?.[key] ?? "").trim();
}

function catalogExtraRowMetadata(row = {}) {
  const metadata = row?.metadata;
  if (!metadata) return {};
  if (typeof metadata === "object" && !Array.isArray(metadata)) return metadata;
  if (typeof metadata !== "string") return {};
  try {
    const parsed = JSON.parse(metadata);
    return parsed && typeof parsed === "object" && !Array.isArray(parsed) ? parsed : {};
  } catch (_err) {
    return {};
  }
}

function catalogExtraMetadataText(metadata = {}, key = "") {
  const value = metadata?.[key];
  if (Array.isArray(value)) return value.map((item) => String(item || "").trim()).filter(Boolean).join(";");
  if (value && typeof value === "object") return "";
  return String(value ?? "").trim();
}

function catalogExtraMetadataList(metadata = {}, key = "") {
  const value = metadata?.[key];
  if (Array.isArray(value)) return value.map((item) => String(item || "").trim()).filter(Boolean);
  const text = String(value ?? "").trim();
  if (!text) return [];
  return text.split(/[;,]/).map((item) => item.trim()).filter(Boolean);
}

function catalogTrackMetadata(track = {}) {
  const metadata = track?.catalogMetadata || track?.metadata;
  if (!metadata) return {};
  if (typeof metadata === "object" && !Array.isArray(metadata)) return metadata;
  if (typeof metadata !== "string") return {};
  try {
    const parsed = JSON.parse(metadata);
    return parsed && typeof parsed === "object" && !Array.isArray(parsed) ? parsed : {};
  } catch (_err) {
    return {};
  }
}

function catalogTrackMetadataList(track = {}, key = "") {
  const metadata = catalogTrackMetadata(track);
  const direct = track?.[key];
  const value = direct != null && direct !== "" ? direct : metadata?.[key];
  if (Array.isArray(value)) return value.map((item) => String(item || "").trim()).filter(Boolean);
  const text = String(value ?? "").trim();
  if (!text) return [];
  return text.split(/[;,]/).map((item) => item.trim()).filter(Boolean);
}

function catalogTrackMetadataText(track = {}, key = "") {
  const metadata = catalogTrackMetadata(track);
  const direct = track?.[key];
  const value = direct != null && direct !== "" ? direct : metadata?.[key];
  if (Array.isArray(value)) return value.map((item) => String(item || "").trim()).filter(Boolean).join(" ");
  if (value && typeof value === "object") return "";
  return String(value ?? "").trim();
}

function catalogExtraSignalText(track = {}) {
  return [
    catalogTrackMetadataText(track, "catalogRole"),
    catalogTrackMetadataText(track, "catalog_role"),
    catalogTrackMetadataText(track, "energyBand"),
    catalogTrackMetadataText(track, "energy_band"),
    catalogTrackMetadataText(track, "source_type"),
    catalogTrackMetadataText(track, "source_note"),
    ...catalogTrackMetadataList(track, "sourceTags"),
    ...catalogTrackMetadataList(track, "source_tags"),
    ...catalogTrackMetadataList(track, "albumKeywords"),
    ...catalogTrackMetadataList(track, "album_keywords")
  ].filter(Boolean).join(" ");
}

const CATALOG_EXTRA_STYLE_SIGNAL_TERMS = {
  acid_techno: ["acid techno", "acid", "303", "tb 303", "rave", "warehouse"],
  minimal_techno: ["minimal techno", "minimal", "hypnotic", "dub", "microhouse", "loop"],
  melodic_techno: ["melodic techno", "melodic", "afterlife", "cinematic", "progressive", "synth"],
  minimal_deep_tech: ["minimal deep tech", "deep tech", "minimal house", "piv", "fuse", "low slung", "groove"],
  afro_house: ["afro house", "afro tech", "south african", "percussive", "tribal", "afro"],
  organic_house: ["organic house", "downtempo", "desert", "organic", "global", "live"]
};

function catalogExtraClubStyleScore(style = "", role = "", energyBand = "", signalText = "", bpmValue = 0) {
  const styleKey = normalizeDatasetStyle(style || "");
  const terms = CATALOG_EXTRA_STYLE_SIGNAL_TERMS[styleKey];
  if (!terms) return 0;

  const text = normalize([role, energyBand, signalText].filter(Boolean).join(" "));
  const stylePhrase = normalize(styleKey.replace(/_/g, " "));
  const bpm = Number(bpmValue) || 0;
  let score = 0;
  let matches = 0;

  if (stylePhrase && text.includes(stylePhrase)) score += 0.9;
  for (const term of terms) {
    if (text.includes(normalize(term))) matches += 1;
  }
  score += Math.min(1.35, matches * 0.28);

  if (role.includes("anchor")) score += 0.85;
  if (role.includes("bridge")) score += 0.45;
  if (role.includes("depth")) score += 0.42;
  if (role.includes("peak")) score += 0.35;
  if (role.includes("scene")) score += 0.35;

  if (energyBand.includes("peak") || energyBand.includes("warehouse") || energyBand.includes("rave")) score += 0.32;
  if (energyBand.includes("hypnotic") || energyBand.includes("deep") || energyBand.includes("organic")) score += 0.26;
  if (energyBand.includes("groove") || energyBand.includes("percussive")) score += 0.24;

  if (styleKey === "acid_techno" && (text.includes("303") || text.includes("acid"))) score += 0.75;
  if (styleKey === "minimal_deep_tech" && (text.includes("bassline") || text.includes("low slung") || text.includes("groove"))) score += 0.55;
  if (styleKey === "afro_house" && (text.includes("south african") || text.includes("percussive"))) score += 0.55;
  if (styleKey === "organic_house" && (text.includes("organic") || text.includes("desert") || text.includes("global"))) score += 0.5;
  if (styleKey === "melodic_techno" && (text.includes("afterlife") || text.includes("cinematic") || text.includes("synth"))) score += 0.45;

  if (bpm > 0) {
    if (styleKey === "acid_techno" && bpm >= 124 && bpm <= 145) score += 0.45;
    else if (styleKey === "minimal_techno" && bpm >= 123 && bpm <= 130) score += 0.42;
    else if (styleKey === "melodic_techno" && bpm >= 120 && bpm <= 127) score += 0.4;
    else if (styleKey === "minimal_deep_tech" && bpm >= 124 && bpm <= 130) score += 0.42;
    else if (styleKey === "afro_house" && bpm >= 118 && bpm <= 124) score += 0.4;
    else if (styleKey === "organic_house" && bpm >= 110 && bpm <= 122) score += 0.4;
  }

  return Math.min(3.8, score);
}

function catalogExtraEnrichmentScore(track = {}, prefs = {}) {
  if (!isCatalogExtraTrack(track)) return 0;
  prefs = normalizeRecommendationPrefs(prefs || {});
  const style = normalizeDatasetStyle(track.style || prefs.style || "");
  const role = normalize(catalogTrackMetadataText(track, "catalogRole") || catalogTrackMetadataText(track, "catalog_role"));
  const energyBand = normalize(catalogTrackMetadataText(track, "energyBand") || catalogTrackMetadataText(track, "energy_band"));
  const confidence = normalize(catalogTrackMetadataText(track, "catalogConfidence") || catalogTrackMetadataText(track, "confidence"));
  const signalText = normalize(catalogExtraSignalText(track));
  const bpmValue = Number(track.bpmExact) || 0;
  let score = 0;

  if (signalText.includes("psycore")) score += 1.25;
  if (signalText.includes("darkpsy") || signalText.includes("dark psy")) score += style === "psycore" ? 0.7 : 0.35;
  if (signalText.includes("bandcamp")) score += 0.45;
  if (confidence === "high") score += 0.8;
  else if (confidence === "medium_high") score += 0.45;

  if (style !== "psycore") {
    score += catalogExtraClubStyleScore(style, role, energyBand, signalText, bpmValue);
  }

  if (style === "psycore") {
    if (role.includes("solo_artist_bpm_anchor")) score += 2.1;
    if (role.includes("modern_2026_psycore_va")) score += 1.9;
    if (role.includes("modern_2026_darkpsy_psycore_va")) score += 1.55;
    if (role.includes("brazilian_scene_depth")) score += 1.25;
    if (role.includes("hitech_psycore_adjacent")) score += 0.75;

    if (energyBand.includes("ultra_fast")) score += 2;
    else if (energyBand.includes("extreme_psycore")) score += 1.75;
    else if (energyBand.includes("high_velocity")) score += 1.25;
    else if (energyBand.includes("darkpsy_psycore_entry")) score += 0.7;
    else if (energyBand.includes("bpm_unknown")) score -= prefs.bpm ? 2.2 : 0.65;

    if (bpmValue >= 220) score += 1.65;
    else if (bpmValue >= 200) score += 1.25;
    else if (bpmValue >= 180) score += 0.75;
    else if (bpmValue > 0 && bpmValue < 170) score -= 1.2;
  }

  if (track.coverArtUrl) score += 0.18;
  if (Array.isArray(track.labelLinks) && track.labelLinks.length) score += 0.25;
  if (Array.isArray(track.socialDiscoveryLinks) && track.socialDiscoveryLinks.length) score += 0.18;
  return score;
}

function isCatalogExtraTrack(track = {}) {
  const source = normalize(track?.source || "");
  return Boolean(track?.catalogExtra || track?.cloudCatalogExtra || source.includes("supabase catalog extra"));
}

function isTrustedCatalogExtraTrack(track = {}) {
  return isCatalogExtraTrack(track) && track?.existenceVerified !== false;
}

function restoreCatalogExtraTrackHints(track = {}) {
  if (!isCatalogExtraTrack(track)) return;
  const style = normalizeDatasetStyle(track.style || "");
  const artist = String(track.artist || "").trim();
  if (!style || !artist || !STYLE_BPM_RULES[style]) return;

  seedStyleArtistFromDataset(style, artist);
  upsertArtistOverridesFromDataset(style, artist);
  upsertArtistOriginFromDataset(artist, track.artistCountry || track.country || "", track.artistCity || track.city || "");
  upsertDiscoveryFromDataset(style, artist, track.artistBio || track.artistProfileHint || "");
}

function catalogExtraUrlFields(row = {}) {
  const metadata = catalogExtraRowMetadata(row);
  const sourceUrl =
    catalogExtraRowText(row, "source_url") ||
    catalogExtraMetadataText(metadata, "track_url") ||
    catalogExtraMetadataText(metadata, "source_album_url");
  const label = catalogExtraRowText(row, "label");
  const url = sourceUrl || (/^https?:\/\//i.test(label) ? label : "");
  if (!url) return {};

  const lowerUrl = url.toLowerCase();
  if (isDirectYouTubeUrl(url)) return { youtubeTrackUrl: url };
  if (lowerUrl.includes("youtube.com") || lowerUrl.includes("youtu.be")) return { youtubeUrl: url };
  if (isDirectSoundCloudTrackUrl(url)) return { soundcloudTrackUrl: url };
  if (lowerUrl.includes("soundcloud.com")) return { soundcloudUrl: url };
  if (lowerUrl.includes("bandcamp.com")) return { bandcampTrackUrl: url, bandcampUrl: url };
  if (lowerUrl.includes("spotify.com/track")) return { spotifyTrackUrl: url };
  if (lowerUrl.includes("spotify.com")) return { spotifyUrl: url };
  return {};
}

function mergeCatalogExtraPayload(payload = {}, sourceTag = "supabase_catalog_extra") {
  const existingKeys = new Set(catalog.map((track) => normalize(`${track.artist}::${track.song}`)));
  const seededArtistKeys = new Set();
  const importedArtistKeys = new Set();
  let tracksImported = 0;

  const artistRows = Array.isArray(payload?.artists) ? payload.artists : [];
  const trackRows = Array.isArray(payload?.tracks) ? payload.tracks : [];

  const registerArtist = (row = {}) => {
    const style = normalizeDatasetStyle(catalogExtraRowText(row, "style"));
    const artist = catalogExtraRowText(row, "artist");
    if (!style || !STYLE_BPM_RULES[style] || !artist) return false;

    const country = catalogExtraRowText(row, "country");
    const city = catalogExtraRowText(row, "city");
    const bio = catalogExtraRowText(row, "artist_bio");
    if (seedStyleArtistFromDataset(style, artist)) {
      seededArtistKeys.add(`${style}::${normalize(artist)}`);
    }
    upsertArtistOverridesFromDataset(style, artist);
    upsertArtistOriginFromDataset(artist, country, city);
    if (upsertDiscoveryFromDataset(style, artist, bio)) {
      importedArtistKeys.add(normalize(artist));
    }
    return true;
  };

  artistRows.forEach(registerArtist);
  trackRows.forEach(registerArtist);

  trackRows.forEach((row = {}) => {
    const style = normalizeDatasetStyle(catalogExtraRowText(row, "style"));
    const artist = catalogExtraRowText(row, "artist");
    const song = catalogExtraRowText(row, "song");
    if (!style || !STYLE_BPM_RULES[style] || !artist || !song) return;

    const metadata = catalogExtraRowMetadata(row);
    const label = catalogExtraRowText(row, "label") || catalogExtraRowText(row, "source") || "Supabase catalog";
    const bpmExact = Number(row?.bpm_exact) || 0;
    const releaseDate = normalizeDatasetReleaseDate(catalogExtraRowText(row, "release_date") || "Supabase catalog");
    const durationSec = parseDatasetDurationSeconds(catalogExtraRowText(row, "duration_sec"));
    const urlFields = catalogExtraUrlFields(row);
    const added = addDynamicTrackToCatalog(
      {
        style,
        song,
        artist,
        label,
        bpmExact,
        previewUrl: catalogExtraRowText(row, "preview_url"),
        releaseDate,
        durationSec,
        source: sourceTag,
        artistCountry: catalogExtraRowText(row, "country"),
        artistGenre: catalogExtraRowText(row, "artist_genre") || styleLabelByValue(style),
        artistProfileHint:
          catalogExtraRowText(row, "artist_profile_hint") ||
          `Entrada curada no Supabase para ${styleLabelByValue(style)}.`,
        artistBio: catalogExtraRowText(row, "artist_bio"),
        catalogMetadata: metadata,
        sourceTags: catalogExtraMetadataList(metadata, "source_tags"),
        albumKeywords: catalogExtraMetadataList(metadata, "album_keywords"),
        energyBand: catalogExtraMetadataText(metadata, "energy_band"),
        catalogRole: catalogExtraMetadataText(metadata, "catalog_role"),
        coverArtUrl: catalogExtraMetadataText(metadata, "cover_art_url"),
        labelLinks: catalogExtraMetadataList(metadata, "label_links"),
        socialDiscoveryLinks: catalogExtraMetadataList(metadata, "social_discovery_links"),
        sourceNote: catalogExtraMetadataText(metadata, "source_note"),
        catalogConfidence: catalogExtraMetadataText(metadata, "confidence"),
        ...urlFields
      },
      existingKeys
    );
    if (!added) return;

    tracksImported += 1;
    importedArtistKeys.add(normalize(artist));
    const trackKey = normalize(`${artist}::${song}`);
    const importedTrack = catalog.find((track) => recommendationTrackKey(track) === trackKey);
    if (importedTrack) {
      importedTrack.catalogExtra = true;
      importedTrack.cloudCatalogExtra = true;
      importedTrack.existenceVerified = true;
      importedTrack.sourceUrl = catalogExtraRowText(row, "source_url");
      importedTrack.catalogMetadata = metadata;
      importedTrack.sourceTags = catalogExtraMetadataList(metadata, "source_tags");
      importedTrack.albumKeywords = catalogExtraMetadataList(metadata, "album_keywords");
      importedTrack.energyBand = catalogExtraMetadataText(metadata, "energy_band");
      importedTrack.catalogRole = catalogExtraMetadataText(metadata, "catalog_role");
      importedTrack.coverArtUrl = catalogExtraMetadataText(metadata, "cover_art_url");
      importedTrack.labelLinks = catalogExtraMetadataList(metadata, "label_links");
      importedTrack.socialDiscoveryLinks = catalogExtraMetadataList(metadata, "social_discovery_links");
      importedTrack.sourceNote = catalogExtraMetadataText(metadata, "source_note");
      importedTrack.catalogConfidence = catalogExtraMetadataText(metadata, "confidence");
      importedTrack.artistBio = catalogExtraRowText(row, "artist_bio") || importedTrack.artistBio;
      importedTrack.artistGenre = catalogExtraRowText(row, "artist_genre") || importedTrack.artistGenre;
      importedTrack.artistProfileHint = catalogExtraRowText(row, "artist_profile_hint") || importedTrack.artistProfileHint;
    }
    if (releaseDate && releaseDate !== "Catálogo dinâmico" && releaseDate !== "Supabase catalog") {
      registerRecentArtistSignal(style, artist, releaseDate, sourceTag);
    }
  });

  return {
    tracksImported,
    artistsImported: importedArtistKeys.size,
    artistSeedsAdded: seededArtistKeys.size
  };
}

function catalogExtraImportedMessage(tracksImported, artistsImported) {
  if (currentLanguage === "en") {
    return `Cloud catalog connected: ${tracksImported} tracks and ${artistsImported} artists ready.`;
  }
  if (currentLanguage === "es") {
    return `Catalogo en la nube conectado: ${tracksImported} pistas y ${artistsImported} artistas listos.`;
  }
  return `Catalogo na nuvem conectado: ${tracksImported} faixas e ${artistsImported} artistas prontos.`;
}

async function fetchCatalogExtraPage(style = "", offset = 0) {
  const params = new URLSearchParams({
    type: "all",
    limit: String(CATALOG_EXTRA_IMPORT_PAGE_SIZE),
    offset: String(Math.max(0, Number(offset) || 0))
  });
  if (style) params.set("style", style);

  try {
    const response = await fetch(`${CATALOG_EXTRA_ENDPOINT}?${params.toString()}`, { cache: "no-store" });
    if (!response.ok) return null;
    const payload = await response.json();
    if (!payload?.ok || payload.enabled === false || payload.setupNeeded) return null;
    return payload;
  } catch (_err) {
    return null;
  }
}

async function fetchCatalogExtraPayload(style = "") {
  const combined = {
    ok: true,
    enabled: true,
    style,
    count: { artists: 0, tracks: 0 },
    artists: [],
    tracks: []
  };
  const seenArtists = new Set();
  const seenTracks = new Set();
  let loadedAnyPage = false;

  for (let page = 0; page < CATALOG_EXTRA_IMPORT_MAX_PAGES; page += 1) {
    const offset = page * CATALOG_EXTRA_IMPORT_PAGE_SIZE;
    const payload = await fetchCatalogExtraPage(style, offset);
    if (!payload) return loadedAnyPage ? combined : null;

    loadedAnyPage = true;
    const artists = Array.isArray(payload.artists) ? payload.artists : [];
    const tracks = Array.isArray(payload.tracks) ? payload.tracks : [];

    artists.forEach((artist) => {
      const key = String(artist?.id || `${artist?.style || ""}::${artist?.artist || ""}`).trim();
      if (!key || seenArtists.has(key)) return;
      seenArtists.add(key);
      combined.artists.push(artist);
    });

    tracks.forEach((track) => {
      const key = String(track?.id || `${track?.style || ""}::${track?.artist || ""}::${track?.song || ""}`).trim();
      if (!key || seenTracks.has(key)) return;
      seenTracks.add(key);
      combined.tracks.push(track);
    });

    if (artists.length < CATALOG_EXTRA_IMPORT_PAGE_SIZE && tracks.length < CATALOG_EXTRA_IMPORT_PAGE_SIZE) break;
  }

  combined.count = {
    artists: combined.artists.length,
    tracks: combined.tracks.length
  };
  return loadedAnyPage ? combined : null;
}

async function hydrateCatalogExtraFromSupabase(style = "") {
  const cleanStyle = normalizeDatasetStyle(style || "");
  if (catalogExtraImportDoneAll) return { tracksImported: 0, artistsImported: 0, artistSeedsAdded: 0 };
  if (cleanStyle && catalogExtraImportedStyles.has(cleanStyle)) {
    return { tracksImported: 0, artistsImported: 0, artistSeedsAdded: 0 };
  }

  const key = cleanStyle || "__all__";
  if (catalogExtraImportPromises.has(key)) return catalogExtraImportPromises.get(key);

  const promise = (async () => {
    const payload = await fetchCatalogExtraPayload(cleanStyle);
    if (!payload) {
      if (cleanStyle) catalogExtraImportedStyles.add(cleanStyle);
      return { tracksImported: 0, artistsImported: 0, artistSeedsAdded: 0 };
    }

    const merged = mergeCatalogExtraPayload(payload);
    if (cleanStyle) catalogExtraImportedStyles.add(cleanStyle);
    else catalogExtraImportDoneAll = true;

    if (merged.tracksImported > 0 || merged.artistsImported > 0 || merged.artistSeedsAdded > 0) {
      dedupeCatalogByTrackKey();
      syncDiscoveryFromSeeds();
      sanitizeCatalogByStyleRules();
      if (cleanStyle) purgeDynamicMismatches(cleanStyle);
      if (merged.tracksImported > 0) {
        suggestionQueueTracks = [];
        suggestionQueueContextKey = "";
      }
      saveDynamicCatalogCache();

      const appVisible = appContent && !appContent.classList.contains("hidden");
      if (!catalogExtraImportNotified && feedbackMessage && appVisible) {
        catalogExtraImportNotified = true;
        const message = catalogExtraImportedMessage(merged.tracksImported, merged.artistsImported);
        feedbackMessage.textContent = message;
        showToast(message);
      }
    }

    return merged;
  })();

  catalogExtraImportPromises.set(key, promise);
  return promise;
}

function mergeExternalDatasetRows(rows = [], sourceTag = "dataset_external") {
  const existingKeys = new Set(catalog.map((track) => normalize(`${track.artist}::${track.song}`)));
  const seededArtistKeys = new Set();
  const importedArtistKeys = new Set();
  let tracksImported = 0;

  rows.forEach((rawRow) => {
    if (!rawRow || typeof rawRow !== "object") return;
    const fields = datasetFieldMap(rawRow);
    const style = normalizeDatasetStyle(
      pickDatasetValue(fields, ["style", "subgenre", "sub_genre", "genre", "primary_genre", "main_style"])
    );
    if (!style || !STYLE_BPM_RULES[style]) return;

    const artist = pickDatasetValue(fields, ["artist", "artist_name", "name", "project", "dj", "act"]);
    const song = pickDatasetValue(fields, ["song", "track", "track_name", "title", "faixa", "music"]);
    const resolvedSong = song || deriveDatasetSongCandidate(rawRow, fields, artist);
    const label = pickDatasetValue(fields, ["label", "record_label", "release_label", "album", "imprint"]);
    const country = pickDatasetValue(fields, ["country", "origin_country", "artist_country", "pais", "nacionalidade"]);
    const area = pickDatasetValue(fields, ["city", "origin_city", "state", "region", "area", "cidade"]);
    const bio = pickDatasetValue(fields, ["artist_bio", "bio", "description", "about", "resumo"]);

    if (artist) {
      const recentSignalDate = extractRecentReleaseDateFromDatasetRow(rawRow, fields);
      if (seedStyleArtistFromDataset(style, artist)) {
        seededArtistKeys.add(`${style}::${normalize(artist)}`);
      }
      upsertArtistOverridesFromDataset(style, artist);
      upsertArtistOriginFromDataset(artist, country, area);
      if (recentSignalDate) {
        registerRecentArtistSignal(style, artist, recentSignalDate, sourceTag);
      }
      if (upsertDiscoveryFromDataset(style, artist, bio)) {
        importedArtistKeys.add(normalize(artist));
      }
    }

    if (!artist || !resolvedSong) return;

    const bpmExact = parseDatasetBpm(
      pickDatasetValue(fields, ["bpm_exact", "bpm", "tempo", "tempo_bpm", "track_bpm", "tempo_profile", "bpm_guide"])
    );
    const previewUrl = pickDatasetValue(fields, ["preview_url", "preview", "sample_url", "audio_preview"]);
    const spotifyUrl = pickDatasetValue(fields, ["spotify_url", "spotify", "spotify_link", "spotify_track_url"]);
    const spotifyTrackUrl = pickDatasetValue(fields, ["spotify_track_url", "spotify_track", "spotify_track_link"]);
    const youtubeUrl = pickDatasetValue(fields, ["youtube_url", "youtube", "youtube_link", "youtube_track_url", "youtube_watch_url", "youtube_video_url"]);
    const youtubeTrackUrl = pickDatasetValue(fields, ["youtube_track_url", "youtube_watch_url", "youtube_video_url", "youtube_track", "youtube_video"]);
    const soundcloudUrl = pickDatasetValue(fields, ["soundcloud_url", "soundcloud", "soundcloud_link", "soundcloud_track_url"]);
    const soundcloudTrackUrl = pickDatasetValue(fields, ["soundcloud_track_url", "soundcloud_track", "soundcloud_permalink"]);
    const bandcampUrl = pickDatasetValue(fields, ["bandcamp_url", "bandcamp", "bandcamp_link", "bandcamp_album_url"]);
    const bandcampTrackUrl = pickDatasetValue(fields, ["bandcamp_track_url", "bandcamp_track", "bandcamp_track_link"]);
    const bandcampTrackId = pickDatasetValue(fields, ["bandcamp_track_id", "bandcamp_id", "bandcamp_embed_id"]);
    const releaseDate = normalizeDatasetReleaseDate(
      pickDatasetValue(fields, ["release_date", "released", "date", "year", "ano"])
    );
    const durationSec = parseDatasetDurationSeconds(
      pickDatasetValue(fields, ["duration_sec", "duration", "duration_seconds", "track_time", "length", "duracao"])
    );
    const artistGenre = pickDatasetValue(fields, ["artist_genre", "genre_signal", "genre_tags", "tags"]);
    const artistProfileHint = pickDatasetValue(fields, ["artist_profile_hint", "profile_hint", "source_note"]);

    const added = addDynamicTrackToCatalog(
      {
        style,
        song: resolvedSong,
        artist,
        label: label || "Catálogo dinâmico",
        bpmExact,
        previewUrl,
        releaseDate,
        durationSec,
        source: sourceTag.includes("dynamic") ? sourceTag : `dynamic_${sourceTag}`,
        artistCountry: country,
        artistGenre,
        artistProfileHint,
        spotifyUrl,
        spotifyTrackUrl,
        youtubeUrl,
        youtubeTrackUrl,
        soundcloudUrl,
        soundcloudTrackUrl,
        bandcampUrl,
        bandcampTrackUrl,
        bandcampTrackId
      },
      existingKeys
    );
    if (!added) return;

    tracksImported += 1;
    importedArtistKeys.add(normalize(artist));
    if (releaseDate && releaseDate !== "Catálogo dinâmico") {
      registerRecentArtistSignal(style, artist, releaseDate, sourceTag);
    }
    if (bio) {
      const trackKey = normalize(`${artist}::${resolvedSong}`);
      const importedTrack = catalog.find((track) => recommendationTrackKey(track) === trackKey);
      if (importedTrack) importedTrack.artistBio = bio;
    }
  });

  return {
    tracksImported,
    artistsImported: importedArtistKeys.size,
    artistSeedsAdded: seededArtistKeys.size
  };
}

async function readExternalDatasetRowsFromPath(path) {
  try {
    const response = await fetch(`${path}?v=${Date.now()}`, { cache: "no-store" });
    if (!response.ok) return [];
    const lowerPath = String(path || "").toLowerCase();
    if (lowerPath.endsWith(".json")) {
      const payload = await response.json();
      return datasetRowsFromJsonPayload(payload);
    }
    if (lowerPath.endsWith(".csv")) {
      const text = await response.text();
      return parseDatasetCsvRecords(text);
    }
    if (lowerPath.endsWith(".jsonl")) {
      const text = await response.text();
      return parseDatasetJsonlRecords(text);
    }
    return [];
  } catch (_err) {
    return [];
  }
}

function externalDatasetImportedMessage(tracksImported, artistsImported) {
  if (currentLanguage === "en") {
    return "Music base updated in the background.";
  }
  if (currentLanguage === "es") {
    return "Base musical actualizada en segundo plano.";
  }
  return "Base musical atualizada em segundo plano.";
}

function waitForExternalDatasetIdleSlot() {
  return new Promise((resolve) => {
    if (typeof window !== "undefined" && typeof window.requestIdleCallback === "function") {
      window.requestIdleCallback(() => resolve(), { timeout: 90 });
      return;
    }
    window.setTimeout(resolve, 18);
  });
}

async function hydrateExternalDatasetPackInBackground() {
  if (externalDatasetImportPromise) return externalDatasetImportPromise;

  externalDatasetImportPromise = (async () => {
    externalDatasetImportStarted = true;

    let tracksImported = 0;
    let artistsImported = 0;
    let seedsAdded = 0;

    for (let index = 0; index < EXTERNAL_DATASET_FILES.length; index += 1) {
      const path = EXTERNAL_DATASET_FILES[index];
      const rows = await readExternalDatasetRowsFromPath(path);
      if (!rows.length) continue;
      const merged = mergeExternalDatasetRows(rows, `dataset_v14_${path.split("/").pop()}`);
      tracksImported += merged.tracksImported;
      artistsImported += merged.artistsImported;
      seedsAdded += merged.artistSeedsAdded;
      if (index < EXTERNAL_DATASET_FILES.length - 1) {
        await waitForExternalDatasetIdleSlot();
      }
    }

    if (tracksImported > 0 || artistsImported > 0 || seedsAdded > 0) {
      dedupeCatalogByTrackKey();
      syncDiscoveryFromSeeds();
      ensureMinimumArtistSeedsPerStyle(MIN_ARTISTS_PER_STYLE);
      normalizeTrustedSlambientCatalog();
      sanitizeCatalogByStyleRules();
      Object.keys(STYLE_BPM_RULES).forEach((style) => purgeDynamicMismatches(style));
      saveDynamicCatalogCache();
      externalDatasetImportDone = true;

      const message = externalDatasetImportedMessage(tracksImported, artistsImported);
      const appVisible = appContent && !appContent.classList.contains("hidden");
      if (feedbackMessage && appVisible) {
        feedbackMessage.textContent = message;
        showToast(message);
      }
      return;
    }

    externalDatasetImportDone = true;
  })();

  return externalDatasetImportPromise;
}

function trackBpmRangeOverlapsPreference(track, selectedBpm = "") {
  const selectedRange = parseBpmRangeValue(selectedBpm);
  if (!selectedRange || !track) return false;
  if (trackMatchesBpmPreference(track, selectedBpm)) return true;
  const trackRange = parseBpmRangeValue(track.bpm || "") || parseBpmRangeValue(styleBpmRangeCompact(track.style));
  return bpmRangesOverlap(trackRange, selectedRange);
}

function trackMatchesBpmPreference(track, selectedBpm = "") {
  const selectedRange = parseBpmRangeValue(selectedBpm);
  if (!selectedRange) return true;
  if (!track) return false;

  const exact = Number(track.bpmExact);
  if (Number.isFinite(exact) && exact > 0) {
    return exact >= selectedRange.min && exact <= selectedRange.max;
  }
  // Com filtro de BPM ativo, só aceita faixa com BPM exato confirmado.
  return false;
}

function energyFromBpm(bpm) {
  if (!Number.isFinite(bpm) || bpm <= 0) return "mid";
  if (bpm >= 175) return "extreme";
  if (bpm >= 145) return "high";
  if (bpm >= 124) return "mid";
  return "low";
}

function bpmFitsStyle(style, bpm) {
  if (!Number.isFinite(bpm) || bpm <= 0) return true;
  const rule = STYLE_BPM_RULES[style];
  if (!rule) return true;
  return bpm >= rule.min && bpm <= rule.max;
}

function requiresExactBpmForDynamic(style, source = "") {
  // Psycore em APIs abertas quase nunca vem com BPM exato; mantemos filtro por artista seed/estilo e liberamos fallback de BPM.
  if (style === "psycore") return false;
  const sourceKey = normalize(source || "").replace(/[\s_]+/g, "");
  const isExpansionSource =
    sourceKey.includes("verifieddeezerexpansion") ||
    sourceKey.includes("verifiedtrackexpansion") ||
    sourceKey.includes("artistexpansion");
  if (isDynamicSource(source) && sourceKey.includes("dataset")) return false;
  if (isDynamicSource(source) && !isExpansionSource && (sourceKey.includes("artist") || sourceKey.includes("soundcloud"))) return false;
  return STRICT_DYNAMIC_BPM_STYLES.has(style);
}

function targetCatalogSizeForStyle(style) {
  const boostedTargets = {
    tech_house: 280,
    techno: 260,
    house: 240,
    drum_and_bass: 240,
    full_on: 230,
    full_on_night: 210,
    full_on_morning: 210,
    psytrance: 230,
    progressive_psy: 220,
    dark_psy: 210,
    dark_experimental: 190,
    hi_tech: 210,
    psy_comercial: 190,
    forest_psy: 190,
    dark_progressive: 190,
    melodic_techno: 200,
    hard_techno: 200,
    acid_techno: 180,
    deep_house: 180,
    liquid_dnb: 180,
    neurofunk: 180,
    ambient: 170,
    downtempo: 170,
    freeform: 150,
    psycore: 150,
    slambient: 150,
    gabber: 150
  };
  return boostedTargets[style] || 160;
}

function getRecentTrackHistory(style) {
  if (!style) return [];
  if (!recentTrackHistoryByStyle.has(style)) recentTrackHistoryByStyle.set(style, []);
  return recentTrackHistoryByStyle.get(style);
}

function registerRecentTrack(style, trackKey, maxSize) {
  if (!style || !trackKey) return;
  const history = getRecentTrackHistory(style);
  const key = normalize(trackKey);
  if (history.includes(key)) return;
  history.push(key);
  while (history.length > Math.max(1, maxSize - 1)) history.shift();
}

function getServedCycle(style) {
  if (!style) return [];
  if (!servedTrackCycleByStyle.has(style)) servedTrackCycleByStyle.set(style, []);
  return servedTrackCycleByStyle.get(style);
}

function registerServedTrack(style, trackKey, maxSize) {
  if (!style || !trackKey) return;
  const cycle = getServedCycle(style);
  const key = normalize(trackKey);
  if (cycle.includes(key)) return;
  cycle.push(key);
  while (cycle.length > Math.max(2, maxSize)) cycle.shift();
}

function getServedArtistCycle(style) {
  if (!style) return [];
  if (!servedArtistCycleByStyle.has(style)) servedArtistCycleByStyle.set(style, []);
  return servedArtistCycleByStyle.get(style);
}

function registerServedArtist(style, artistName, maxSize) {
  if (!style || !artistName) return;
  const cycle = getServedArtistCycle(style);
  const key = artistMatchKey(artistName);
  if (!key || cycle.includes(key)) return;
  cycle.push(key);
  while (cycle.length > Math.max(2, maxSize)) cycle.shift();
}

function resetServedCycleIfExhausted(style) {
  if (!style) return;
  const pool = catalog
    .filter((track) => track.style === style)
    .map((track) => normalize(`${track.artist}::${track.song}`));
  const uniquePool = new Set(pool);
  const cycle = getServedCycle(style);
  if (!uniquePool.size) return;
  if (cycle.length >= uniquePool.size) servedTrackCycleByStyle.set(style, []);
}

function resetServedArtistCycleIfExhausted(style) {
  if (!style) return;
  const pool = new Set(
    catalog
      .filter((track) => track.style === style && isTrackEligibleForRecommendation(track))
      .map((track) => artistMatchKey(track.artist))
      .filter(Boolean)
  );
  const cycle = getServedArtistCycle(style);
  if (!pool.size) return;
  if (new Set(cycle).size >= pool.size) servedArtistCycleByStyle.set(style, []);
}

function registerGlobalRecommendation(trackKey) {
  const key = normalize(trackKey || "");
  if (!key || recommendationMemory.has(key)) return;
  recommendationMemory.add(key);
  recommendationMemoryQueue.push(key);
  const maxGlobalMemory = 220;
  while (recommendationMemoryQueue.length > maxGlobalMemory) {
    const oldest = recommendationMemoryQueue.shift();
    recommendationMemory.delete(oldest);
  }
}

function clearRecentHistoryIfExhausted(style) {
  if (!style) return;
  const stylePoolKeys = catalog
    .filter((track) => track.style === style)
    .map((track) => normalize(`${track.artist}::${track.song}`));
  const uniquePool = new Set(stylePoolKeys);
  const history = getRecentTrackHistory(style);
  if (!uniquePool.size) return;
  if (history.length >= uniquePool.size) {
    recentTrackHistoryByStyle.set(style, []);
  }
}

function escapeRegex(value) {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function normalizeTitle(value) {
  return normalize(value || "")
    .replace(/\b(feat|ft|featuring)\b.*$/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

const SUSPECT_DYNAMIC_PATTERNS = [
  /\btop\s*\d{2,4}\b/,
  /\bbest\s+of\b/,
  /\bplaylist\b/,
  /\bcompilation\b/,
  /\bmix\b/,
  /\bdj\s*mix\b/,
  /\bmega\s*mix\b/,
  /\bmegamix\b/,
  /\blive\s*set\b/,
  /\bfull\s*set\b/,
  /\bradio\s*show\b/,
  /\bpodcast\b/,
  /\bworkout\b/,
  /\bfitness\b/,
  /\bgym\b/,
  /\bmotivation\b/,
  /\bmotivacion\b/,
  /\bmotivacao\b/,
  /\bmusica\s+para\b/,
  /\bmusic\s+for\b/,
  /\brave\s+party\b/,
  /\brave\s+dj\b/,
  /\bedm\s+club\b/,
  /\belectronic\s+dance\s+music\b/,
  /\belectronik\s+djs?\b/,
  /\belektronik\s+djs?\b/,
  /\bfestival\s+hits\b/,
  /\bparty\s+music\b/,
  /\bchill\s*out\b/,
  /\bchillout\b/,
  /\bnightlife\b/,
  /\bmusic\s+zone\b/,
  /\bgood\s+energy\s+club\b/,
  /\bsleep\s+music\b/,
  /\brelax(?:ing)?\s+music\b/,
  /\bstudy\s+music\b/,
  /\bmeditation\s+music\b/,
  /\bbass\s+boosted\b/,
  /\bslowed\s*\+\s*reverb\b/,
  /\bno\s+copyright\b/,
  /\bpara\s+(treinar|entrenar|estudiar|focar|concentrar|concentracion|dormir|relajar|trabajar|gym)\b/,
  /\bsuperar\s+tus?\s+limites?\b/,
  /\bsin\s+anuncios\b/,
  /\btop\s+hits\b/,
  /\b\d+\s*(hr|hour)\b/
];

function hasSuspiciousDynamicText(value) {
  const normalized = normalize(value || "");
  if (!normalized) return false;
  return SUSPECT_DYNAMIC_PATTERNS.some((pattern) => pattern.test(normalized));
}

function hasGenreKeywordEntity(value) {
  const normalized = normalize(value || "").replace(/\s+/g, " ").trim();
  if (!normalized) return false;
  return /\b(psytrance|psy|trance|techno|tecno|house|electro|eletronica|electronica|electronic|electronik|elektronik|bass|dnb|dubstep|forest|dark|hitech|psycore|gabber|gabba|hardcore|edm|ambient|downtempo|chill\s*out|chillout)\b/.test(normalized);
}

function hasAllowedMixTerm(title) {
  const normalized = normalize(title || "");
  return /\b(original mix|extended mix|club mix|dub mix|radio edit|remix|vip mix|original version)\b/.test(normalized);
}

function isLikelyDjMixOrSetTitle(value) {
  const normalized = normalize(value || "").replace(/\s+/g, " ").trim();
  if (!normalized) return true;
  const compact = normalized.replace(/[\s_-]+/g, " ");
  if (/\b(dj\s*)?(set|mix|session)\s*(ao vivo|live|full|completo|complete|continuous|recorded|recording)\b/.test(compact)) return true;
  if (/\b(full|complete|continuous|seamless|megamix|mixtape)\s+(dj\s*)?(set|mix|session)\b/.test(compact)) return true;
  if (/\b(live|boiler room|essential mix|radio show|podcast|aftermovie|festival set|club set|opening set|closing set)\b/.test(compact)) return true;
  if (/\b\d+\s*(h|hr|hrs|hour|hours|min|minutes)\s+(dj\s*)?(set|mix|session)\b/.test(compact)) return true;
  if (/\b(set|mix|session)\s+#?\d{1,4}\b/.test(compact)) return true;
  if (/\b(best of|top\s*\d+|playlist|compilation|album mix|mixed by|mixado por)\b/.test(compact)) return true;
  return false;
}

function isLikelyGenreDescriptorEntity(value) {
  const normalized = normalize(value || "").replace(/\s+/g, " ").trim();
  if (!normalized) return true;
  const tokens = normalized.split(" ").filter(Boolean);
  if (!tokens.length) return true;

  const genreTokens = new Set([
    "psy",
    "psytrance",
    "trance",
    "techno",
    "house",
    "electro",
    "bass",
    "dnb",
    "dubstep",
    "forest",
    "dark",
    "full",
    "fullon",
    "hitech",
    "psycore",
    "gabber",
    "gabba",
    "hardcore",
    "goa",
    "uplifting",
    "progressive",
    "minimal",
    "melodic",
    "industrial",
    "acid",
    "hard"
  ]);
  const neutralTokens = new Set([
    "and",
    "of",
    "the",
    "de",
    "da",
    "do",
    "del",
    "la",
    "el",
    "music",
    "records",
    "recordings",
    "label",
    "official",
    "collective",
    "project",
    "crew",
    "sounds"
  ]);

  let genreCount = 0;
  let informativeCount = 0;
  tokens.forEach((token) => {
    if (genreTokens.has(token)) {
      genreCount += 1;
      return;
    }
    if (neutralTokens.has(token)) return;
    informativeCount += 1;
  });

  if (genreCount >= 2 && informativeCount === 0) return true;
  if (genreCount >= 3 && informativeCount <= 1) return true;
  return false;
}

function isGenericAutoEntityName(value) {
  const normalized = normalize(value || "").replace(/\s+/g, " ").trim();
  const rawLower = String(value || "").toLowerCase();
  if (!normalized) return true;
  const wordCount = normalized.split(" ").filter(Boolean).length;
  const hasGenreTerm = /(psy|trance|techno|tecno|house|electro|eletronica|electronica|electronic|electronik|elektronik|bass|dnb|dubstep|forest|dark|hitech|psycore|gabber|gabba|hardcore|ambient|downtempo|chill\s*out|chillout)/.test(normalized);
  const hasChannelTerm = /(music|mix|playlist|radio|channel|official|sets?|djs?)/.test(normalized);
  const pureGenreName = /^(psy trance|psytrance|darkpsy|forest psy|dark psy|techno|tecno|house|electro|bass music|gabber|gabba|hardcore techno)$/.test(normalized);
  if (/\[\s*(psy|psytrance|trance|techno|house|electro|bass|dnb|dubstep|hitech|psycore|gabber|gabba|hardcore|edm)\s*\]/.test(rawLower)) return true;
  if (pureGenreName) return true;
  if (/\b(global|world|planet|universal|international)\b/.test(normalized) && /\b(electronic|electronik|elektronik|eletronica|electronica|dance)\b/.test(normalized) && /\bdjs?\b/.test(normalized)) return true;
  if (hasGenreTerm && hasChannelTerm) return true;
  if (wordCount <= 3 && hasGenreTerm && /(music|records|label|official)/.test(normalized)) return true;
  if (wordCount <= 6 && hasGenreTerm && /\b(dj|musica|electronica|eletronica|baile|dance)\b/.test(normalized)) return true;
  if (normalized === "psy trance music") return true;
  return false;
}

function isGenreAliasArtistName(value) {
  const normalized = normalize(value || "").replace(/\s+/g, " ").trim();
  if (!normalized) return true;
  const tokens = normalized.split(" ").filter(Boolean);
  if (!tokens.length) return true;
  const genrePrefixes = new Set([
    "psy",
    "psytrance",
    "trance",
    "techno",
    "house",
    "electro",
    "bass",
    "dnb",
    "dubstep",
    "ambient",
    "forest",
    "dark",
    "fullon",
    "full",
    "minimal",
    "melodic",
    "hardstyle",
    "gabber",
    "gabba",
    "hardcore",
    "drum"
  ]);
  const firstToken = tokens[0];
  if (!genrePrefixes.has(firstToken)) return false;
  if (tokens.length <= 3) return true;
  return false;
}

function isLikelyChannelStyleArtistName(value) {
  const raw = String(value || "").toLowerCase();
  const normalized = normalize(value || "").replace(/\s+/g, " ").trim();
  if (!normalized) return true;
  const words = normalized.split(" ").filter(Boolean);
  const hasGenre = hasGenreKeywordEntity(normalized);
  const hasChannelTone = /\b(rave|party|club|music|musica|beats|vibes|mix|playlist|radio|channel|official|zone|nightlife|chill|relax|sleep|meditation|dj|djs|electronica|eletronica|electronic|electronik|elektronik|baile|dance)\b/.test(normalized);
  const hasCommaList = /[,;|]/.test(raw);
  const hasYear = /\b(19|20)\d{2}\b/.test(raw);
  if (/\b(global|world|planet|universal|international)\b/.test(normalized) && hasChannelTone) return true;
  if (hasCommaList && hasChannelTone) return true;
  if (hasYear && hasChannelTone && words.length >= 4) return true;
  if (hasGenre && hasChannelTone) return true;
  if (words.length >= 4 && hasGenre) return true;
  if (words.length >= 6 && hasChannelTone && !hasGenre) return true;
  return false;
}

function isLikelyGeneratedTrackTitle(value) {
  const normalized = normalize(value || "").replace(/\s+/g, " ").trim();
  const rawLower = String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .trim();
  const raw = String(value || "")
    .toLowerCase()
    .normalize("NFD")
    .replace(/[^\w\s()]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  if (!normalized) return true;
  const tokenCount = normalized.split(" ").filter(Boolean).length;
  const genreTermCount = genreKeywordCount(normalized);
  const promoTermCount = [
    "festival",
    "hits",
    "radio",
    "version",
    "rave",
    "dj",
    "electronic dance music",
    "party",
    "music",
    "chill out",
    "chillout",
    "nightlife",
    "zone",
    "relax",
    "sleep",
    "meditation"
  ].reduce((count, term) => (normalized.includes(term) ? count + 1 : count), 0);
  const tokens = normalized.split(" ").filter(Boolean);
  if (tokens.length >= 2) {
    const genreRepeatRoots = new Set(["techno", "tecno", "trance", "house", "electro", "psy", "goa", "hitech"]);
    const root = tokens[0];
    if (genreRepeatRoots.has(root) && tokens.every((token) => token === root)) return true;
  }

  if (/^(psy|psytrance|psy trance|trance|techno|house|electro|electronic|edm|dnb|drum and bass|dubstep|forest psy|dark psy|hitech|hi tech|psycore|goa trance|progressive psy)$/.test(normalized)) return true;
  if (/^(ambient|ambient electronic|electronic ambient|chill out|chillout|ambient chill|ambient relax|sleep ambient|meditation ambient)$/.test(normalized)) return true;
  if (/^(psy|psytrance|psy trance|trance|techno|house|electro|electronic|edm|dnb|dubstep|hitech|hi tech|psycore)\s+(single|ep|album)$/.test(normalized)) return true;
  if (/\[\s*(psy|psytrance|trance|techno|house|electro|bass|dnb|dubstep|hitech|psycore|edm)\s*\]/.test(rawLower)) return true;
  if (/\((psy|psytrance|trance|techno|house|edm|fullon|full on|rave|club).*\)/.test(raw)) return true;
  if (/\(([^)]*(festival|hits|radio|rave dj|electronic dance music)[^)]*)\)/.test(raw)) return true;
  if (isLikelyDjMixOrSetTitle(raw)) return true;
  if (/^de\s+[a-z0-9 ]{2,32}\s+a\s+[a-z0-9 ]{2,32}$/.test(normalized)) return true;
  if (/^from\s+[a-z0-9 ]{2,32}\s+to\s+[a-z0-9 ]{2,32}$/.test(normalized)) return true;
  if (/\b(psy|techno|house)\s*(music|mix)\b/.test(normalized)) return true;
  if (/\b(chill\s*out|chillout|nightlife|music zone|good energy club)\b/.test(normalized) && tokenCount >= 3) return true;
  if (tokenCount >= 10 && promoTermCount >= 3 && genreTermCount >= 1) return true;
  if (tokenCount >= 12 && promoTermCount >= 2) return true;
  if (normalized.length >= 86 && promoTermCount >= 2) return true;
  if (normalized.includes("radio version") && (promoTermCount >= 2 || genreTermCount >= 1)) return true;
  if (/\b(para|for)\b/.test(normalized) && hasSuspiciousDynamicText(normalized)) return true;
  if (/^(techno|tecno|house|trance|electro|eletronica|electronica)\s*\(([^)]*(musica|music|electronic|electronica|eletronica|baile|dance)[^)]*)\)$/.test(normalized)) return true;
  if (/^(techno|tecno|house|trance|electro|eletronica|electronica)\b/.test(normalized) && /\b(musica|music|electronic|electronica|eletronica|baile|dance)\b/.test(normalized) && tokenCount >= 3) return true;
  return false;
}

function genreKeywordCount(text) {
  const normalized = normalize(text || "");
  const terms = [
    "psy",
    "darkpsy",
    "forest",
    "techno",
    "house",
    "electro",
    "bass",
    "trance",
    "dubstep",
    "drum and bass",
    "dnb"
  ];
  return terms.reduce((count, term) => (normalized.includes(term) ? count + 1 : count), 0);
}

function parseDurationTextToSeconds(value) {
  if (!value) return 0;
  const match = String(value).trim().match(/^(\d{1,3}):([0-5]\d)$/);
  if (!match) return 0;
  const minutes = Number(match[1]) || 0;
  const seconds = Number(match[2]) || 0;
  return (minutes * 60) + seconds;
}

function previewUrlExpiryEpoch(value = "") {
  const raw = String(value || "").trim();
  if (!raw) return 0;
  try {
    const parsed = new URL(raw);
    const signedToken = [
      parsed.searchParams.get("hdnea"),
      parsed.searchParams.get("hdnts"),
      parsed.searchParams.get("token"),
      raw
    ]
      .filter(Boolean)
      .join("~");
    const match = signedToken.match(/(?:^|[~&?])exp=(\d{9,12})(?:$|[~&])/i);
    return match ? Number(match[1]) || 0 : 0;
  } catch (_err) {
    const match = raw.match(/(?:^|[~&?])exp=(\d{9,12})(?:$|[~&])/i);
    return match ? Number(match[1]) || 0 : 0;
  }
}

function previewUrlIsExpired(value = "", graceSeconds = 30) {
  const expiresAt = previewUrlExpiryEpoch(value);
  if (!expiresAt) return false;
  return expiresAt <= Math.floor(Date.now() / 1000) + Math.max(0, Number(graceSeconds) || 0);
}

function normalizePreviewUrl(value = "") {
  const raw = String(value || "").trim();
  if (!raw) return "";
  if (!/^https?:\/\//i.test(raw)) return "";
  try {
    const parsed = new URL(raw);
    if (parsed.protocol === "http:") parsed.protocol = "https:";
    const normalized = parsed.toString();
    return previewUrlIsExpired(normalized) ? "" : normalized;
  } catch (_err) {
    return "";
  }
}

function registerPreviewCandidate(track, previewUrl = "") {
  if (!track) return;
  const normalized = normalizePreviewUrl(previewUrl);
  if (!normalized) return;
  if (!Array.isArray(track.previewCandidates)) track.previewCandidates = [];
  const exists = track.previewCandidates.some((url) => normalizePreviewUrl(url) === normalized);
  if (!exists) track.previewCandidates.push(normalized);
  if (!normalizePreviewUrl(track.previewUrl)) track.previewUrl = normalized;
}

function promotePreviewCandidate(track, previewUrl = "") {
  if (!track) return;
  const normalized = normalizePreviewUrl(previewUrl);
  if (!normalized) return;
  if (!Array.isArray(track.previewCandidates)) track.previewCandidates = [];
  track.previewCandidates = [
    normalized,
    ...track.previewCandidates.filter((url) => normalizePreviewUrl(url) !== normalized)
  ];
  track.previewUrl = normalized;
}

function previewCandidatesForTrack(track) {
  if (!track) return [];
  const ordered = [];
  const seen = new Set();
  const add = (value = "") => {
    const url = normalizePreviewUrl(value);
    if (!url || seen.has(url)) return;
    seen.add(url);
    ordered.push(url);
  };
  add(track.previewUrl);
  if (Array.isArray(track.previewCandidates)) {
    track.previewCandidates.forEach((url) => add(url));
  }
  return ordered;
}

const ARTIST_PREVIEW_FALLBACK_LIMIT = 6;
const ARTIST_PREVIEW_FALLBACK_LOOKUP_TARGET = 3;

function artistPreviewOptionKey(option = {}) {
  return [
    artistMatchKey(option.artist || ""),
    normalizeTitle(option.song || ""),
    normalizePreviewUrl(option.previewUrl || "")
  ].join("::");
}

function scoreArtistPreviewOption(option = {}, baseTrack = {}) {
  let score = 0;
  const sameTitle = normalizeTitle(option.song || "") === normalizeTitle(baseTrack.song || "");
  if (!sameTitle) score += 3;
  if (option.source === "catalog") score += 1.6;
  if (option.source === "itunes") score += 1.4;
  if (option.source === "deezer") score += 1.2;
  if (option.source === "soundcloud") score += 1.1;
  if (option.style && option.style === baseTrack.style) score += 0.7;
  if (option.previewUrl) score += 0.8;
  if (Number(option.rank) > 0) score += Math.min(1.8, Math.log10(Number(option.rank) + 1) / 3);
  if (sameTitle) score -= 1.6;
  return score;
}

function isAwkwardArtistPreviewTitle(value = "") {
  const normalized = normalize(value || "");
  return Boolean(
    normalized.includes("includes hidden track") ||
    normalized.includes("continuous mix") ||
    normalized.includes("full album") ||
    normalized.includes("entire album")
  );
}

function addArtistPreviewOption(options, seen, baseTrack, option = {}) {
  if (!baseTrack || !option) return;
  const previewUrl = normalizePreviewUrl(option.previewUrl || "");
  const artist = String(option.artist || baseTrack.artist || "").trim();
  const song = String(option.song || option.title || "").trim();
  if (!previewUrl || !artist || !song) return;
  if (isAwkwardArtistPreviewTitle(song)) return;
  if (Array.isArray(baseTrack.artistPreviewFailedUrls) && baseTrack.artistPreviewFailedUrls.includes(previewUrl)) return;
  if (!isArtistMatch(artist, baseTrack.artist || "") && !isArtistMatch(baseTrack.artist || "", artist)) return;
  if (hasUnrequestedAlternateVersion(baseTrack.song || "", song) && normalizeTitle(baseTrack.song || "") === normalizeTitle(song)) return;

  const normalized = {
    artist,
    song,
    previewUrl,
    source: String(option.source || "artist").trim() || "artist",
    style: option.style || baseTrack.style || "",
    rank: Number(option.rank) || 0,
    score: 0
  };
  normalized.score = scoreArtistPreviewOption(normalized, baseTrack);
  const key = artistPreviewOptionKey(normalized);
  if (!key || seen.has(key)) return;
  seen.add(key);
  options.push(normalized);
}

function removeArtistPreviewOption(track, previewUrl = "") {
  if (!track) return;
  const normalized = normalizePreviewUrl(previewUrl);
  if (!normalized) return;
  if (!Array.isArray(track.artistPreviewFailedUrls)) track.artistPreviewFailedUrls = [];
  if (!track.artistPreviewFailedUrls.includes(normalized)) track.artistPreviewFailedUrls.push(normalized);
  if (Array.isArray(track.artistPreviewOptions)) {
    track.artistPreviewOptions = track.artistPreviewOptions.filter((option) => normalizePreviewUrl(option?.previewUrl) !== normalized);
  }
  if (normalizePreviewUrl(track.artistPreviewFallback?.previewUrl) === normalized) {
    track.artistPreviewFallback = null;
  }
}

async function fetchDeezerPreviewOptionsByArtist(artist, style = "") {
  const artistName = sanitizeArtistLookupName(artist);
  if (!artistName) return [];
  const queries = [
    `artist:"${artistName}"`,
    artistName
  ];
  const collected = new Map();

  for (const queryValue of queries) {
    try {
      const data = await deezerJsonp(`https://api.deezer.com/search?q=${encodeURIComponent(queryValue)}&limit=50`);
      const rows = Array.isArray(data?.data) ? data.data : [];
      rows
        .filter((row) => row?.title && row?.artist?.name)
        .filter((row) => isArtistMatch(row.artist.name, artistName))
        .filter((row) => normalizePreviewUrl(row.preview || ""))
        .filter((row) => !isLikelyDjMixOrSetTitle(row.title || ""))
        .filter((row) => !hasUnrequestedAlternateVersion("", row.title || ""))
        .forEach((row) => {
          const key = String(row.id || `${row.artist.name}::${row.title}`);
          if (!collected.has(key)) collected.set(key, row);
        });
    } catch (_err) {
      // tenta a proxima query
    }
  }

  return Array.from(collected.values())
    .filter((row) => !style || !hasTrackStyleSignalConflict(style, {
      artist: row.artist?.name || artistName,
      song: row.title || "",
      label: row.album?.title || "",
      artistGenre: [STYLE_SEARCH_TERMS[style], styleLabelByValue(style)].filter(Boolean).join(" "),
      artistProfileHint: row.album?.title || "",
      source: "deezer_artist_preview"
    }))
    .slice(0, 30);
}

async function collectArtistPreviewOptions(track, { forceLookup = false } = {}) {
  if (!track?.artist) return [];
  if (!forceLookup && Array.isArray(track.artistPreviewOptions) && track.artistPreviewOptions.length) {
    return track.artistPreviewOptions;
  }
  if (!forceLookup && track.artistPreviewLookupAttempted) return track.artistPreviewOptions || [];

  const options = [];
  const seen = new Set();
  const addOption = (option) => addArtistPreviewOption(options, seen, track, option);

  catalog
    .filter((candidate) => candidate && candidate !== track && candidate.artist && candidate.song)
    .filter((candidate) => isArtistMatch(candidate.artist, track.artist) || isArtistMatch(track.artist, candidate.artist))
    .sort((a, b) => {
      const aScore =
        (a.style === track.style ? 2 : 0) +
        (trackHasReliableAudioPreview(a) ? 2 : 0) -
        (normalizeTitle(a.song) === normalizeTitle(track.song) ? 1 : 0);
      const bScore =
        (b.style === track.style ? 2 : 0) +
        (trackHasReliableAudioPreview(b) ? 2 : 0) -
        (normalizeTitle(b.song) === normalizeTitle(track.song) ? 1 : 0);
      return bScore - aScore;
    })
    .slice(0, 12)
    .forEach((candidate) => {
      previewCandidatesForTrack(candidate).forEach((previewUrl) => {
        addOption({
          artist: candidate.artist,
          song: candidate.song,
          previewUrl,
          source: "catalog",
          style: candidate.style
        });
      });
    });

  if (forceLookup || options.length < ARTIST_PREVIEW_FALLBACK_LOOKUP_TARGET) {
    try {
      const rows = await fetchDeezerPreviewOptionsByArtist(track.artist, track.style);
      rows
        .slice(0, 16)
        .forEach((row) => {
          addOption({
            artist: row?.artist?.name || track.artist,
            song: row?.title || "",
            previewUrl: row?.preview || "",
            source: "deezer",
            style: track.style,
            rank: row?.rank
          });
        });
    } catch (_err) {
      // segue para top tracks
    }
  }

  if (forceLookup || options.length < ARTIST_PREVIEW_FALLBACK_LOOKUP_TARGET) {
    try {
      const rows = await fetchDeezerArtistTopTracks(track.artist, track.style);
      rows
        .filter((row) => normalizePreviewUrl(row?.preview || ""))
        .slice(0, 12)
        .forEach((row) => {
          addOption({
            artist: row?.artist?.name || track.artist,
            song: row?.title || "",
            previewUrl: row?.preview || "",
            source: "deezer",
            style: track.style,
            rank: row?.rank
          });
        });
    } catch (_err) {
      // segue para iTunes/SoundCloud
    }
  }

  if (forceLookup || options.length < ARTIST_PREVIEW_FALLBACK_LOOKUP_TARGET) {
    try {
      const rows = await fetchItunesTracksByArtist(track.artist, track.style);
      rows
        .filter((row) => normalizePreviewUrl(row?.previewUrl || ""))
        .slice(0, 16)
        .forEach((row) => {
          addOption({
            artist: row?.artistName || track.artist,
            song: row?.trackName || "",
            previewUrl: row?.previewUrl || "",
            source: "itunes",
            style: track.style
          });
        });
    } catch (_err) {
      // segue para SoundCloud
    }
  }

  if (forceLookup || options.length < ARTIST_PREVIEW_FALLBACK_LOOKUP_TARGET) {
    try {
      const rows = await fetchSoundCloudTracksByStyle(track.style, track.artist, { track, force: forceLookup });
      rows
        .map((row) => ({
          row,
          previewUrl: soundCloudPreviewUrlFromRow(row)
        }))
        .filter((entry) => normalizePreviewUrl(entry.previewUrl))
        .slice(0, 12)
        .forEach(({ row, previewUrl }) => {
          addOption({
            artist: row?.artist || track.artist,
            song: row?.song || row?.title || "",
            previewUrl,
            source: "soundcloud",
            style: track.style
          });
        });
    } catch (_err) {
      // sem alternativas extras
    }
  }

  const sorted = options
    .sort((a, b) => b.score - a.score)
    .slice(0, ARTIST_PREVIEW_FALLBACK_LIMIT);
  track.artistPreviewOptions = sorted;
  track.artistPreviewLookupAttempted = true;
  return sorted;
}

async function pickPlayableArtistPreviewFallback(audioEl, track, { forceLookup = false } = {}) {
  if (!audioEl || !track) return null;
  const options = await collectArtistPreviewOptions(track, { forceLookup });
  for (const option of options) {
    const previewUrl = normalizePreviewUrl(option.previewUrl || "");
    if (!previewUrl) continue;
    const probe = await probeAudioSource(audioEl, previewUrl);
    if (probe.ok) {
      track.artistPreviewFallback = option;
      track.previewChecked = true;
      track.previewMissing = false;
      return option;
    }
    removeArtistPreviewOption(track, previewUrl);
  }
  resetTrackPreviewElement(audioEl);
  return null;
}

function resetTrackPreviewElement(audioEl) {
  if (!audioEl) return;
  try {
    audioEl.pause();
    audioEl.removeAttribute("src");
    audioEl.load();
  } catch (_err) {
    // ignore preview reset failures
  }
}

function probeAudioSource(audioEl, previewUrl, timeoutMs = 6500) {
  return new Promise((resolve) => {
    let settled = false;
    let timeoutId = 0;
    const hasPlayableBuffer = () => {
      const duration = Number(audioEl.duration);
      const readyState = Number(audioEl.readyState) || 0;
      return Number.isFinite(duration) && duration > 0 && readyState >= 2 && !audioEl.error;
    };

    const finish = (ok, reason = "") => {
      if (settled) return;
      settled = true;
      cleanup();
      resolve({ ok, reason });
    };

    const onCanPlay = () => finish(true, "canplay");
    const onCanPlayThrough = () => finish(true, "canplaythrough");
    const onLoadedMeta = () => {
      if (hasPlayableBuffer()) finish(true, "metadata");
    };
    const onLoadedData = () => {
      if (hasPlayableBuffer()) finish(true, "loadeddata");
    };
    const onError = () => finish(false, "error");
    const onStalled = () => finish(false, "stalled");
    const onAbort = () => finish(false, "abort");

    const cleanup = () => {
      if (timeoutId) window.clearTimeout(timeoutId);
      delete audioEl.dataset.previewProbing;
      audioEl.removeEventListener("canplay", onCanPlay);
      audioEl.removeEventListener("canplaythrough", onCanPlayThrough);
      audioEl.removeEventListener("loadedmetadata", onLoadedMeta);
      audioEl.removeEventListener("loadeddata", onLoadedData);
      audioEl.removeEventListener("error", onError);
      audioEl.removeEventListener("stalled", onStalled);
      audioEl.removeEventListener("abort", onAbort);
    };

    audioEl.addEventListener("canplay", onCanPlay);
    audioEl.addEventListener("canplaythrough", onCanPlayThrough);
    audioEl.addEventListener("loadedmetadata", onLoadedMeta);
    audioEl.addEventListener("loadeddata", onLoadedData);
    audioEl.addEventListener("error", onError);
    audioEl.addEventListener("stalled", onStalled);
    audioEl.addEventListener("abort", onAbort);

    timeoutId = window.setTimeout(() => finish(false, "timeout"), timeoutMs);

    try {
      resetTrackPreviewElement(audioEl);
      audioEl.dataset.previewProbing = "true";
      audioEl.src = previewUrl;
      audioEl.load();
    } catch (_err) {
      finish(false, "exception");
    }
  });
}

async function pickPlayablePreviewSource(audioEl, candidates = []) {
  if (!audioEl) return "";
  const uniqueCandidates = [];
  const seen = new Set();
  (Array.isArray(candidates) ? candidates : []).forEach((value) => {
    const normalized = normalizePreviewUrl(value);
    if (!normalized || seen.has(normalized)) return;
    seen.add(normalized);
    uniqueCandidates.push(normalized);
  });

  for (const candidate of uniqueCandidates) {
    const probe = await probeAudioSource(audioEl, candidate);
    if (probe.ok) return candidate;
  }
  resetTrackPreviewElement(audioEl);
  return "";
}

function isLikelyCompilationEntry({ song = "", artist = "", label = "", durationSec = 0 } = {}) {
  const songRaw = String(song || "").trim();
  const artistRaw = String(artist || "").trim();
  const labelRaw = String(label || "").trim();
  if (!songRaw || !artistRaw) return true;
  if (songRaw.length > 92 || artistRaw.length > 72) return true;
  if (isGenericAutoEntityName(artistRaw)) return true;
  if (isLikelyGenreDescriptorEntity(artistRaw)) return true;
  if (isGenreAliasArtistName(artistRaw)) return true;
  if (isLikelyChannelStyleArtistName(artistRaw)) return true;
  if (isLikelyGeneratedTrackTitle(songRaw)) return true;
  if (isLikelyDjMixOrSetTitle(songRaw)) return true;
  if (isLikelyDjMixOrSetTitle(artistRaw)) return true;
  if (labelRaw && isGenericAutoEntityName(labelRaw)) return true;
  if (labelRaw && isLikelyGenreDescriptorEntity(labelRaw)) return true;

  if (Number(durationSec) >= 720) return true;

  const songSuspicious = hasSuspiciousDynamicText(songRaw);
  if (songSuspicious && !hasAllowedMixTerm(songRaw)) return true;
  if (/\bmix\b/.test(normalize(songRaw)) && !hasAllowedMixTerm(songRaw) && genreKeywordCount(songRaw) >= 2) return true;
  if (hasSuspiciousDynamicText(artistRaw)) return true;
  if (hasSuspiciousDynamicText(labelRaw)) return true;
  if (genreKeywordCount(songRaw) >= 3) return true;

  return false;
}

function directArtistGenreHint(artistName = "") {
  const key = artistMatchKey(artistName || "");
  const direct = key ? ARTIST_GENRE_HINT_OVERRIDES[key] : null;
  if (direct && typeof direct === "object") {
    return String(direct[currentLanguage] || direct.pt || direct.en || direct.es || "").trim();
  }
  if (typeof direct === "string") return String(direct).trim();
  return "";
}

function curatedReleaseLabelForArtist(rawLabel = "", artistName = "") {
  const releaseKey = normalize(rawLabel || "");
  if (!releaseKey) return "";
  const artistKey = artistMatchKey(artistName || "");
  const directMap = artistKey ? ARTIST_RELEASE_LABEL_OVERRIDES[artistKey] : null;
  if (directMap?.[releaseKey]) return directMap[releaseKey];
  const aliasKey = Object.keys(ARTIST_RELEASE_LABEL_OVERRIDES).find((key) => isArtistMatch(artistName, key));
  return aliasKey ? ARTIST_RELEASE_LABEL_OVERRIDES[aliasKey]?.[releaseKey] || "" : "";
}

function isCuratedArtistReleaseTitle(rawValue = "", artistName = "") {
  return Boolean(curatedReleaseLabelForArtist(rawValue, artistName));
}

function isGenericArtistGenreSignal(rawValue = "") {
  const value = normalize(rawValue || "");
  if (!value) return true;
  return [
    "electronic",
    "electronica",
    "dance",
    "trance",
    "psy",
    "psytrance",
    "psy trance",
    "psychedelic trance"
  ].includes(value);
}

function applyCuratedTrackMetadata(track) {
  if (!track) return track;
  const curatedGenre = directArtistGenreHint(track.artist);
  if (curatedGenre) {
    const rawGenre = String(track.artistGenre || "").trim();
    if (
      !rawGenre ||
      isGenericArtistGenreSignal(rawGenre) ||
      isCuratedArtistReleaseTitle(rawGenre, track.artist) ||
      artistMatchKey(track.artist) === "astrix"
    ) {
      track.artistGenre = curatedGenre;
    }
  }

  if (isCuratedArtistReleaseTitle(track.artistProfileHint, track.artist)) {
    track.artistProfileHint = "";
  }

  const curatedLabel = curatedReleaseLabelForArtist(track.label, track.artist);
  if (curatedLabel) track.label = curatedLabel;
  return track;
}

function sanitizeLabel(label, artistName, songName) {
  const raw = String(label || "").trim();
  if (!raw) return "Catálogo dinâmico";
  const curatedLabel = curatedReleaseLabelForArtist(raw, artistName);
  if (curatedLabel) return curatedLabel;
  const clean = normalize(raw);
  if (!clean) return "Catálogo dinâmico";
  if (/^(psy|psytrance|psy trance|trance|techno|house|electro|electronic|edm|dnb|dubstep|hitech|hi tech|psycore)\s+(single|ep|album)$/.test(clean)) return "Catálogo dinâmico";
  if (clean === normalize(songName) || clean === normalize(artistName)) return "Catálogo dinâmico";
  if (isGenericAutoEntityName(raw)) return "Catálogo dinâmico";
  if (isLikelyGenreDescriptorEntity(raw)) return "Catálogo dinâmico";
  if (raw.length > 84) return "Catálogo dinâmico";
  if (hasSuspiciousDynamicText(raw)) return "Catálogo dinâmico";
  return raw;
}

function labelAllowedForStyle(style, labelName) {
  const requiredTerms = STYLE_REQUIRED_LABEL_TERMS[style] || [];
  if (!requiredTerms.length) return true;
  const normalizedLabel = normalize(labelName || "");
  if (!normalizedLabel) return false;
  return requiredTerms.some((term) => normalizedLabel.includes(normalize(term)));
}

function textHasForbiddenSignalsForStyle(style, rawText = "") {
  const forbiddenTerms = STYLE_FORBIDDEN_SIGNAL_TERMS[style] || [];
  if (!forbiddenTerms.length) return false;
  const text = normalize(rawText || "");
  if (!text) return false;
  return forbiddenTerms.some((term) => text.includes(normalize(term)));
}

function normalizedTextHasIdentitySignal(rawText = "", rawSignal = "") {
  const text = normalize(rawText || "");
  const signal = normalize(rawSignal || "");
  if (!text || !signal) return false;
  if (!signal.includes(" ")) {
    return new RegExp(`(^|\\s)${escapeRegex(signal)}($|\\s)`).test(text);
  }
  return text.includes(signal);
}

function textHasAnyIdentitySignal(rawText = "", signals = []) {
  if (!Array.isArray(signals) || !signals.length) return false;
  return signals.some((signal) => normalizedTextHasIdentitySignal(rawText, signal));
}

function hasArtistIdentityCollision(style, trackLike = {}) {
  if (!style || !trackLike) return false;
  const artistName = String(trackLike.artist || "").trim();
  if (!artistName) return false;

  const rule = ARTIST_IDENTITY_COLLISION_RULES.find((entry) => {
    const styles = Array.isArray(entry.styles) ? entry.styles : [];
    const styleMatches = !styles.length || styles.includes(style);
    return styleMatches && isArtistMatch(artistName, entry.artist);
  });
  if (!rule) return false;

  const identityText = [
    trackLike.song,
    trackLike.label,
    trackLike.artistGenre,
    trackLike.artistProfileHint,
    trackLike.vibe,
    trackLike.artistBio,
    trackLike.labelBio,
    trackLike.source
  ]
    .filter(Boolean)
    .join(" ");
  if (!identityText) return false;

  const hasHardWrongSignal = textHasAnyIdentitySignal(identityText, rule.hardWrongSignals);
  if (hasHardWrongSignal) return true;

  const hasSoftWrongSignal = textHasAnyIdentitySignal(identityText, rule.softWrongSignals);
  if (!hasSoftWrongSignal) return false;

  const hasAllowedSignal = textHasAnyIdentitySignal(identityText, rule.allowedSignals);
  return !hasAllowedSignal;
}

function textHasTechnoRequiredSignalsForStyle(style, rawText = "") {
  if (!style || familyOf(style) !== "techno") return false;
  const terms = TECHNO_REQUIRED_SIGNAL_TERMS[style] || TECHNO_REQUIRED_SIGNAL_TERMS.techno;
  if (!terms.length) return false;
  const text = normalize(rawText || "");
  if (!text) return false;
  return terms.some((term) => text.includes(normalize(term)));
}

function textHasBassRequiredSignalsForStyle(style, rawText = "") {
  if (!style || familyOf(style) !== "bass_music" && familyOf(style) !== "dnb") return false;
  const terms = BASS_REQUIRED_SIGNAL_TERMS[style] || [];
  if (!terms.length) return false;
  const text = normalize(rawText || "");
  if (!text) return false;
  return terms.some((term) => text.includes(normalize(term)));
}

function textHasLowTempoRequiredSignalsForStyle(style, rawText = "") {
  const terms = LOW_TEMPO_SIGNAL_TERMS[style] || [];
  if (!terms.length) return false;
  const text = normalize(rawText || "");
  if (!text) return false;
  return terms.some((term) => text.includes(normalize(term)));
}

function textHasPsytranceRequiredSignal(rawText = "") {
  const text = normalize(rawText || "");
  if (!text) return false;
  return PSYTRANCE_REQUIRED_SIGNAL_TERMS.some((term) => text.includes(normalize(term)));
}

function hasTechnoFamilyIntegrityConflict(style, trackLike = {}) {
  if (!style || !trackLike) return false;
  if (familyOf(style) !== "techno") return false;

  const sourceRaw = String(trackLike.source || "").trim();
  const sourceNormalized = normalize(sourceRaw);
  const sourceCompact = sourceNormalized.replace(/[\s_]+/g, "");
  if (!isDynamicSource(sourceRaw)) return false;

  // Dataset import ja vem com rotulagem curada e não deve ser bloqueado por falta de sinal textual.
  if (sourceCompact.includes("dataset")) return false;

  const artistName = String(trackLike.artist || "").trim();
  if (artistSeedAnchoredForStyle(style, artistName)) return false;

  const genreHasSignal = textHasTechnoRequiredSignalsForStyle(style, trackLike.artistGenre || "");
  if (genreHasSignal) return false;

  const labelHasSignal = textHasTechnoRequiredSignalsForStyle(style, trackLike.label || "");
  if (labelHasSignal) return false;

  // Não aceitar apenas "sinal no título" para techno; isso gera falso positivo
  // como "Techno Techno" em faixas fora do gênero.
  return true;
}

function hasBassFamilyIntegrityConflict(style, trackLike = {}) {
  if (!style || !trackLike) return false;
  const family = familyOf(style);
  if (family !== "bass_music" && family !== "dnb") return false;

  const sourceRaw = String(trackLike.source || "").trim();
  const sourceNormalized = normalize(sourceRaw);
  const sourceCompact = sourceNormalized.replace(/[\s_]+/g, "");
  if (!isDynamicSource(sourceRaw)) return false;

  // Dataset import já vem curado e não deve ser bloqueado por ausência de sinal textual.
  if (sourceCompact.includes("dataset")) return false;

  const artistName = String(trackLike.artist || "").trim();
  if (artistSeedAnchoredForStyle(style, artistName)) return false;

  const genreHasSignal = textHasBassRequiredSignalsForStyle(style, trackLike.artistGenre || "");
  if (genreHasSignal) return false;

  const labelHasSignal = textHasBassRequiredSignalsForStyle(style, trackLike.label || "");
  if (labelHasSignal) return false;

  const songHasSignal = textHasBassRequiredSignalsForStyle(style, trackLike.song || "");
  if (songHasSignal) return false;

  return true;
}

function hasLowTempoIntegrityConflict(style, trackLike = {}) {
  if (!LOW_TEMPO_SIGNAL_TERMS[style] || !trackLike) return false;

  const sourceRaw = String(trackLike.source || "").trim();
  const sourceCompact = normalize(sourceRaw).replace(/[\s_]+/g, "");
  if (!isDynamicSource(sourceRaw)) return false;

  // Seeds/datasets locais sao curados; a regra abaixo mira falsos positivos de APIs gerais.
  if (sourceCompact.includes("dataset")) return false;

  const signalText = [
    trackLike.artistGenre,
    trackLike.label,
    trackLike.song,
    trackLike.artistProfileHint,
    trackLike.vibe
  ]
    .filter(Boolean)
    .join(" ");

  return !textHasLowTempoRequiredSignalsForStyle(style, signalText);
}

function hasPsytranceIntegrityConflict(style, trackLike = {}) {
  if (style !== "psytrance" || !trackLike) return false;

  const sourceRaw = String(trackLike.source || "").trim();
  const sourceCompact = normalize(sourceRaw).replace(/[\s_]+/g, "");
  if (!isDynamicSource(sourceRaw)) return false;
  if (sourceCompact.includes("dataset")) return false;

  const bpmValue = Number(trackLike.bpmExact || 0);
  if (Number.isFinite(bpmValue) && bpmValue > 0 && bpmFitsStyle(style, bpmValue)) return false;

  const signalText = [
    trackLike.artistGenre,
    trackLike.label,
    trackLike.song,
    trackLike.artistProfileHint,
    trackLike.vibe
  ]
    .filter(Boolean)
    .join(" ");
  if (textHasPsytranceRequiredSignal(signalText)) return false;

  const artistName = String(trackLike.artist || "").trim();
  const styleOverride = allowedStylesForArtist(artistName);
  if (styleOverride.includes("psytrance")) return false;

  return true;
}

function textHasPsytranceSceneLabelSignal(rawText = "") {
  const text = normalize(rawText || "");
  if (!text) return false;
  return PSYTRANCE_SCENE_LABEL_TERMS.some((term) => text.includes(normalize(term)));
}

function isGenericDynamicPsyLabel(label = "", artistName = "", songName = "") {
  const raw = String(label || "").trim();
  if (!raw) return true;
  const key = normalize(raw);
  if (!key) return true;
  if (key === normalize("Catálogo dinâmico") || key === normalize("Dynamic catalog")) return true;
  if (songName && key === normalize(songName)) return true;
  if (artistName && key === normalize(artistName)) return true;
  return isLikelyGenreDescriptorEntity(raw);
}

function hasAmbiguousDynamicPsyHomonymConflict(style, trackLike = {}) {
  const cleanStyle = normalizeDatasetStyle(style || trackLike?.style || "");
  if (!cleanStyle || familyOf(cleanStyle) !== "psytrance" || !trackLike) return false;

  const sourceRaw = String(trackLike.source || "").trim();
  const sourceCompact = normalize(sourceRaw).replace(/[\s_]+/g, "");
  if (!isDynamicSource(sourceRaw)) return false;
  if (!sourceCompact.includes("deezer") && !sourceCompact.includes("itunes") && !sourceCompact.includes("artistexpansion")) return false;

  const artistKey = artistMatchKey(trackLike.artist || "");
  if (!DYNAMIC_PSY_HOMONYM_RISK_ARTIST_KEYS.has(artistKey)) return false;

  const bpmValue = Number(trackLike.bpmExact || 0);
  const reliableBpm = Number.isFinite(bpmValue) && bpmValue > 0 && bpmFitsStyle(cleanStyle, bpmValue);
  const sceneEvidence = textHasPsytranceSceneLabelSignal([
    trackLike.label,
    trackLike.artistGenre,
    trackLike.artistProfileHint,
    trackLike.labelBio,
    trackLike.vibe
  ].filter(Boolean).join(" "));
  const genericLabel = isGenericDynamicPsyLabel(trackLike.label, trackLike.artist, trackLike.song);

  if (sceneEvidence && reliableBpm) return false;
  if (sceneEvidence && !genericLabel && !sourceCompact.includes("deezer")) return false;
  return true;
}

function hasTrackStyleSignalConflict(style, trackLike = {}) {
  if (!style || !trackLike) return false;
  const merged = [
    trackLike.artist,
    trackLike.song,
    trackLike.label,
    trackLike.artistGenre,
    trackLike.vibe
  ]
    .filter(Boolean)
    .join(" ");
  if (textHasForbiddenSignalsForStyle(style, merged)) return true;
  if (hasArtistIdentityCollision(style, trackLike)) return true;
  if (hasTechnoFamilyIntegrityConflict(style, trackLike)) return true;
  if (hasBassFamilyIntegrityConflict(style, trackLike)) return true;
  if (hasLowTempoIntegrityConflict(style, trackLike)) return true;
  if (hasPsytranceIntegrityConflict(style, trackLike)) return true;
  if (hasAmbiguousDynamicPsyHomonymConflict(style, trackLike)) return true;
  return false;
}

function titleConfidence(baseTitle, candidateTitle) {
  const a = normalizeTitle(baseTitle);
  const b = normalizeTitle(candidateTitle);
  if (!a || !b) return 0;
  if (a === b) return 1;
  if (a.startsWith(b) || b.startsWith(a)) return 0.9;

  const aTokens = new Set(a.split(" ").filter(Boolean));
  const bTokens = new Set(b.split(" ").filter(Boolean));
  let overlap = 0;
  aTokens.forEach((token) => {
    if (bTokens.has(token)) overlap += 1;
  });
  const denom = Math.max(aTokens.size, bTokens.size, 1);
  return overlap / denom;
}

function strictTitleMatch(baseTitle, candidateTitle) {
  const a = normalizeTitle(baseTitle);
  const b = normalizeTitle(candidateTitle);
  if (!a || !b) return false;
  if (a === b) return true;
  const shortest = Math.min(a.length, b.length);
  const longest = Math.max(a.length, b.length);
  if (longest === 0) return false;
  const ratio = shortest / longest;
  if (ratio < 0.78) return false;
  return a.startsWith(b) || b.startsWith(a);
}

function hasUnrequestedAlternateVersion(baseTitle, candidateTitle) {
  const base = normalizeTitle(baseTitle);
  const candidate = normalizeTitle(candidateTitle);
  if (!base || !candidate) return false;
  const baseAllowsAlternate = /\b(remix|bootleg|rework|edit|vip|dub|flip|version|refix)\b/.test(base);
  if (baseAllowsAlternate) return false;
  return /\b(remix|bootleg|rework|cover|mashup|flip|edit|vip|refix|live|set|session|podcast)\b/.test(candidate);
}

function canonicalArtistIdentity(nameLike = "") {
  const raw = String(nameLike || "");
  const noParentheses = raw.replace(/\([^)]*\)/g, " ");
  const noAliasTail = noParentheses.replace(/\baka\b.*$/i, " ");
  return normalize(noAliasTail).replace(/\s+/g, " ").trim();
}

function artistMatchKey(nameLike = "") {
  const canonical = canonicalArtistIdentity(nameLike || "");
  const compact = canonical
    .replace(/\b(feat|ft|featuring|x|vs|and|with)\b/g, " ")
    .replace(/\s+/g, " ")
    .trim();
  if (compact) return compact;
  return normalize(nameLike || "").replace(/\s+/g, " ").trim();
}

function artistMatchingKeys(nameLike = "") {
  const keys = new Set();
  const normalized = normalize(nameLike || "").replace(/\s+/g, " ").trim();
  const canonical = canonicalArtistIdentity(nameLike || "");
  const compact = artistMatchKey(nameLike || "");
  if (normalized) keys.add(normalized);
  if (canonical) keys.add(canonical);
  if (compact) keys.add(compact);
  return keys;
}

function addArtistKeysToSet(setRef, nameLike = "") {
  if (!setRef) return;
  artistMatchingKeys(nameLike).forEach((key) => setRef.add(key));
}

function addArtistIdentityToSet(setRef, nameLike = "") {
  if (!setRef) return;
  const key = artistMatchKey(nameLike || "");
  if (key) setRef.add(key);
}

function removeArtistIdentityFromSet(setRef, nameLike = "") {
  if (!setRef?.size) return;
  artistMatchingKeys(nameLike).forEach((key) => {
    if (setRef.has(key)) setRef.delete(key);
  });
}

function artistSetHasMatch(setRef, nameLike = "") {
  if (!setRef?.size) return false;
  for (const key of artistMatchingKeys(nameLike)) {
    if (setRef.has(key)) return true;
  }
  return false;
}

function isAmbiguousArtistImageName(nameLike = "") {
  const key = artistMatchKey(nameLike || "");
  if (!key) return false;
  return AMBIGUOUS_ARTIST_IMAGE_KEYS.has(key);
}

function isCuratorBlockedArtistName(nameLike = "") {
  const key = artistMatchKey(nameLike || "");
  if (!key) return false;
  return CURATOR_BLOCKED_ARTIST_KEYS.has(key);
}

function artistImageSourceIsVerified(source = "") {
  const value = normalize(source || "");
  if (!value) return false;
  return (
    value.includes("manual") ||
    value.includes("verified") ||
    value.includes("verificado") ||
    value.includes("artist photo")
  );
}

function shouldSuppressUnverifiedArtistImage(track, source = "") {
  const artist = String(track?.artist || "").trim();
  if (!artist || !isAmbiguousArtistImageName(artist)) return false;
  if (track?.artistImageVerified === true || track?.verifiedArtistImage === true) return false;
  return !artistImageSourceIsVerified(source || track?.artistImageSource || "");
}

function compactArtistIdentitySet(setRef) {
  if (!setRef?.size) return;
  const compacted = new Set();
  Array.from(setRef.values()).forEach((value) => addArtistIdentityToSet(compacted, value));
  setRef.clear();
  compacted.forEach((value) => setRef.add(value));
}

function isArtistMatch(candidateName, seedName) {
  const candidate = normalize(candidateName || "");
  const seed = normalize(seedName || "");
  const candidateCanonical = canonicalArtistIdentity(candidateName || "");
  const seedCanonical = canonicalArtistIdentity(seedName || "");
  if (!candidate || !seed) return false;
  if (candidate === seed || candidateCanonical === seedCanonical) return true;

  const seedEscaped = escapeRegex(seed);
  const seedCanonicalEscaped = seedCanonical ? escapeRegex(seedCanonical) : "";
  // Regra rígida: seed deve ser o artista principal (inicio do nome), opcionalmente com collab/feat.
  const collabSeparator = "&|and|e|feat|ft|x|vs";
  const mainArtistPattern = new RegExp(`^${seedEscaped}(?:\\s*(?:${collabSeparator})\\s+.+)?$`);
  if (!seedCanonicalEscaped) return mainArtistPattern.test(candidate);
  const mainArtistCanonicalPattern = new RegExp(`^${seedCanonicalEscaped}(?:\\s*(?:${collabSeparator})\\s+.+)?$`);
  return mainArtistPattern.test(candidate) || mainArtistCanonicalPattern.test(candidateCanonical);
}

function allowedStylesForArtist(artistName) {
  const normalizedArtist = normalize(artistName || "");
  if (!normalizedArtist) return [];
  const exact = ARTIST_STYLE_OVERRIDES[normalizedArtist];
  if (exact?.length) return exact;
  const canonicalArtist = canonicalArtistIdentity(artistName || "");
  const canonicalExact = canonicalArtist ? ARTIST_STYLE_OVERRIDES[canonicalArtist] : null;
  if (canonicalExact?.length) return canonicalExact;
  const aliasKey = Object.keys(ARTIST_STYLE_OVERRIDES).find((key) => isArtistMatch(normalizedArtist, key));
  return aliasKey ? ARTIST_STYLE_OVERRIDES[aliasKey] : [];
}

function resolveProfileArtistCandidateStyle(artistName = "", rawStyle = "", targetStyles = [], sourceLabel = "") {
  const style = normalizeDatasetStyle(rawStyle || "") || normalize(rawStyle || "");
  if (!artistName || !style) return { style: "", sourceStyle: "", styleCorrected: false };
  if (artistAllowedForStyle(style, artistName)) {
    return { style, sourceStyle: style, styleCorrected: false };
  }

  const allowedStyles = allowedStylesForArtist(artistName)
    .map((entry) => normalizeDatasetStyle(entry || "") || normalize(entry || ""))
    .filter((entry, index, list) => entry && STYLE_BPM_RULES[entry] && list.indexOf(entry) === index)
    .filter((entry) => artistAllowedForStyle(entry, artistName));
  if (!allowedStyles.length) return { style: "", sourceStyle: style, styleCorrected: false };

  const exactTargetStyle = allowedStyles.find((entry) => targetStyles.some((target) => target.style === entry));
  const sourceKey = normalize(sourceLabel || "");
  if (sourceKey === "styleseed" || sourceKey === "style seed" || sourceKey === "style-seed") {
    if (!exactTargetStyle) return { style: "", sourceStyle: style, styleCorrected: false };
    return { style: exactTargetStyle, sourceStyle: style, styleCorrected: exactTargetStyle !== style };
  }

  const familyTargetStyle = allowedStyles.find((entry) => profileStyleAffinity(entry, targetStyles) > 0);
  const resolvedStyle = exactTargetStyle || familyTargetStyle || "";
  return {
    style: resolvedStyle,
    sourceStyle: style,
    styleCorrected: Boolean(resolvedStyle && resolvedStyle !== style)
  };
}

function hasStrictWhitelist(style) {
  return Array.isArray(STYLE_STRICT_WHITELISTS[style]) && STYLE_STRICT_WHITELISTS[style].length > 0;
}

function artistAllowedForStyle(style, artistName) {
  if (isCuratorBlockedArtistName(artistName)) return false;
  const strictWhitelist = STYLE_STRICT_WHITELISTS[style] || [];
  if (strictWhitelist.length && !strictWhitelist.some((seed) => isArtistMatch(artistName, seed))) {
    return false;
  }
  if (textHasForbiddenSignalsForStyle(style, artistName)) return false;

  const styleOverride = allowedStylesForArtist(artistName);
  if (styleOverride.length && !styleOverride.includes(style)) return false;

  const seeds = STYLE_ARTIST_SEEDS[style] || [];
  const blocked = (STYLE_ARTIST_BLOCKLIST[style] || []).some((name) => isArtistMatch(artistName, name));
  if (blocked) return false;
  if (!seeds.length) return true;
  if (!STRICT_ARTIST_MATCH_STYLES.has(style)) return true;
  return seeds.some((seed) => isArtistMatch(artistName, seed));
}

function trackBlockedForStyle(style, trackLike = {}) {
  const cleanStyle = normalizeDatasetStyle(style || trackLike?.style || "");
  if (!cleanStyle || !trackLike) return false;
  const trackArtist = String(trackLike.artist || "").trim();
  const trackSong = String(trackLike.song || trackLike.title || "").trim();
  if (trackArtist && isCuratorBlockedArtistName(trackArtist)) return true;
  if (!trackArtist || !trackSong) return false;
  const styleFamily = familyOf(cleanStyle);
  return TRACK_STYLE_BLOCKLIST.some((entry) => {
    const entryStyle = normalizeDatasetStyle(entry.style || "");
    const entryFamily = normalize(entry.family || "");
    const styleMatches =
      (entryStyle && entryStyle === cleanStyle) ||
      (entryFamily && entryFamily === styleFamily);
    if (!styleMatches) return false;
    const artistMatches = entry.artist ? isArtistMatch(trackArtist, entry.artist) : true;
    return artistMatches && strictTitleMatch(trackSong, entry.song || "");
  });
}

function dynamicFineStyleNeedsVerifiedTrack(style, source = "") {
  const cleanStyle = normalizeDatasetStyle(style || "");
  if (!cleanStyle || !isDynamicSource(source)) return false;
  if (isTrustedSourceForFineStyle(source)) return false;
  return familyOf(cleanStyle) === "psytrance" || FINE_SUBGENRE_EVIDENCE_STYLES.has(cleanStyle);
}

function isTrustedSourceForFineStyle(source = "") {
  const sourceKey = normalize(source || "").replace(/[\s_]+/g, "");
  return (
    sourceKey.includes("datasetlocal") ||
    sourceKey.includes("localseed") ||
    sourceKey.includes("verifiedtrackexpansion") ||
    sourceKey.includes("verifieddeezerexpansion")
  );
}

function requiresSeedAnchorForDynamicStyle(style) {
  return style === "forest_psy" || style === "psy_comercial" || DARK_UNDERGROUND_DISCOVERY_STYLES.has(style);
}

function artistSeedAnchoredForStyle(style, artistName) {
  if (!style) return false;
  const strictWhitelist = STYLE_STRICT_WHITELISTS[style] || [];
  if (strictWhitelist.length) return strictWhitelist.some((seed) => isArtistMatch(artistName, seed));
  const styleOverride = allowedStylesForArtist(artistName);
  if (styleOverride.length) return styleOverride.includes(style);
  const seeds = STYLE_ARTIST_SEEDS[style] || [];
  if (!seeds.length) return false;
  return seeds.some((seed) => isArtistMatch(artistName, seed));
}

function hasCuratedFineStyleProofWithoutBpm(style, track = null) {
  const cleanStyle = normalizeDatasetStyle(style || track?.style || "");
  if (!cleanStyle || !track) return false;
  const artistKey = artistMatchKey(track.artist || "");
  const allowed = CURATED_FINE_STYLE_NO_BPM_ARTIST_PROOF[artistKey] || [];
  if (!allowed.includes(cleanStyle)) return false;
  const sourceKey = normalize(track.source || "").replace(/[\s_]+/g, "");
  if (!sourceKey.includes("verifieddeezerexpansion") && !sourceKey.includes("verifiedtrackexpansion") && !sourceKey.includes("datasetlocal")) return false;
  if (!trackHasPlayablePreviewExperience(track) && track.existenceVerified !== true) return false;
  const signalText = [
    track.artistGenre,
    track.label,
    track.artistProfileHint,
    track.vibe,
    track.source,
    catalogExtraSignalText(track)
  ].filter(Boolean).join(" ");
  return textHasSpecificStyleSignal(cleanStyle, signalText);
}

function isDynamicSource(source) {
  const normalizedSource = normalize(source || "");
  const compactSource = normalizedSource.replace(/[\s_]+/g, "");
  return (
    normalizedSource.includes("dynamic") ||
    compactSource.includes("itunesstyle") ||
    compactSource.includes("itunesartist") ||
    compactSource.includes("deezerstyle") ||
    compactSource.includes("deezerartist") ||
    compactSource.includes("verifieddeezerexpansion") ||
    compactSource.includes("verifiedtrackexpansion") ||
    compactSource.includes("artistexpansion") ||
    compactSource.includes("dataset") ||
    compactSource.includes("soundcloudapi") ||
    compactSource.includes("soundclouddynamic")
  );
}

function isTrustedSlambientCatalogTrack(track) {
  if (!track || track.style !== "slambient") return false;
  if (isDynamicSource(track.source)) return false;
  if (!artistAllowedForStyle("slambient", track.artist)) return false;
  if (!labelAllowedForStyle("slambient", track.label)) return false;
  return true;
}

function isTrustedCuratedCatalogTrack(track) {
  if (!track) return false;
  if (isTrustedSlambientCatalogTrack(track)) return true;
  const source = normalize(track.source || "");
  const curatedLocalSeed = source.includes("datasetlocal") || source.includes("dataset local") || source.includes("dataset_local_seed_boost");
  if (!curatedLocalSeed) return false;
  if (!artistAllowedForStyle(track.style, track.artist)) return false;
  return ["freeform", "ambient", "downtempo", "chillout", "brazilian_funk", "psycore"].includes(track.style);
}

function curatedCatalogPriorityScore(track) {
  if (!track || !CURATED_PRIORITY_STYLES.has(track.style)) return 0;
  if (isTrustedCuratedCatalogTrack(track)) return 6.2;
  if (!isDynamicSource(track.source)) return 4.6;
  return 0;
}

function normalizeTrustedSlambientCatalog() {
  catalog.forEach((track) => {
    if (!isTrustedSlambientCatalogTrack(track)) return;

    // Mantém o catálogo curado da Endless Knot elegível mesmo sem preview oficial.
    track.existenceVerified = true;
    track.previewChecked = Boolean(track.previewUrl);
    track.previewMissing = !track.previewUrl;
    if (track.spotifyVerified === undefined) track.spotifyVerified = false;
    track.youtubeVerified = true;
    track.bandcampVerified = Boolean(track.bandcampTrackUrl || track.bandcampUrl);
    if (track.soundcloudVerified === undefined) track.soundcloudVerified = trackHasDirectSoundCloudTrack(track);
    if (!track.spotifyTrackUrl) track.spotifyTrackUrl = buildSpotifyTrackLink(track);
    if (!track.youtubeTrackUrl) track.youtubeTrackUrl = buildYouTubeTrackLink(track);
    if (!track.soundcloudTrackUrl && !track.soundcloudUrl) {
      track.soundcloudUrl = buildSoundCloudTrackLink(track);
    }
  });
}

function purgeDynamicMismatches(style) {
  for (let i = catalog.length - 1; i >= 0; i -= 1) {
    const track = catalog[i];
    const styleToCheck = style || track.style;
    if (style && track.style !== style) continue;
    if (styleToCheck && track.style === styleToCheck && hasStrictWhitelist(styleToCheck) && !artistAllowedForStyle(styleToCheck, track.artist)) {
      catalog.splice(i, 1);
      delete TRACK_METADATA[`${track.song}|${track.artist}`];
      continue;
    }
    if (!isDynamicSource(track.source)) continue;
    const dynamicMeta = TRACK_METADATA[`${track.song}|${track.artist}`] || {};
    const dynamicDurationSec = parseDurationTextToSeconds(dynamicMeta.duration);
    const isInvalidDynamic = isLikelyCompilationEntry({
      song: track.song,
      artist: track.artist,
      label: track.label,
      durationSec: dynamicDurationSec
    });
    const artistOk = artistAllowedForStyle(styleToCheck, track.artist);
    const anchoredArtistOk =
      !requiresSeedAnchorForDynamicStyle(styleToCheck) ||
      artistSeedAnchoredForStyle(styleToCheck, track.artist);
    const bpmValue = Number(track.bpmExact);
    const bpmPresent = Number.isFinite(bpmValue) && bpmValue > 0;
    const bpmOk =
      (!requiresExactBpmForDynamic(styleToCheck, track.source) || bpmPresent) &&
      (!dynamicFineStyleNeedsVerifiedTrack(styleToCheck, track.source) || bpmPresent) &&
      (!bpmPresent || bpmFitsStyle(styleToCheck, bpmValue));
    const labelOk = labelAllowedForStyle(styleToCheck, track.label);
    const styleSignalConflict = hasTrackStyleSignalConflict(styleToCheck, track);
    const blockedTrack = trackBlockedForStyle(styleToCheck, track);
    const generatedArtist = isLikelyChannelStyleArtistName(track.artist);
    const generatedTitle = isLikelyGeneratedTrackTitle(track.song);
    if (!artistOk || !anchoredArtistOk || !bpmOk || !labelOk || isInvalidDynamic || styleSignalConflict || blockedTrack || generatedArtist || generatedTitle) {
      catalog.splice(i, 1);
      delete TRACK_METADATA[`${track.song}|${track.artist}`];
    }
  }
}

function sanitizeCatalogByStyleRules() {
  for (let i = catalog.length - 1; i >= 0; i -= 1) {
    const track = catalog[i];
    const meta = TRACK_METADATA[`${track.song}|${track.artist}`] || {};
    const durationSec = parseDurationTextToSeconds(meta.duration);
    const invalidDynamic = isDynamicSource(track.source) && isLikelyCompilationEntry({
      song: track.song,
      artist: track.artist,
      label: track.label,
      durationSec
    });
    const generatedDynamic =
      isDynamicSource(track.source) &&
      (isLikelyGeneratedTrackTitle(track.song) || isLikelyChannelStyleArtistName(track.artist));
    const bpmValue = Number(track.bpmExact);
    const bpmPresent = Number.isFinite(bpmValue) && bpmValue > 0;
    const unverifiableFineDynamic =
      isDynamicSource(track.source) &&
      dynamicFineStyleNeedsVerifiedTrack(track.style, track.source) &&
      !bpmPresent;
    const styleSignalConflict = hasTrackStyleSignalConflict(track.style, track);
    const blockedTrack = trackBlockedForStyle(track.style, track);
    if (!artistAllowedForStyle(track.style, track.artist) || !labelAllowedForStyle(track.style, track.label) || styleSignalConflict || blockedTrack) {
      catalog.splice(i, 1);
      delete TRACK_METADATA[`${track.song}|${track.artist}`];
      continue;
    }
    if (invalidDynamic || generatedDynamic || unverifiableFineDynamic) {
      catalog.splice(i, 1);
      delete TRACK_METADATA[`${track.song}|${track.artist}`];
    }
  }
}

function dedupeCatalogByTrackKey() {
  const scoreTrack = (track) => {
    let score = 0;
    if (trackHasReliableAudioPreview(track)) score += 4;
    if (track?.existenceVerified === true) score += 3;
    if (track?.spotifyVerified === true) score += 2;
    if (track?.youtubeVerified === true) score += 1.5;
    if (hasReliableBpmForTrack(track)) score += 3.2;
    else if (isDynamicSource(track?.source)) score -= 3.5;
    if (String(track?.source || "").includes("dataset")) score += 0.5;
    return score;
  };

  const mergeTrackPlayableCandidates = (target, source) => {
    if (!target || !source || target === source) return;
    previewCandidatesForTrack(source).forEach((url) => registerPreviewCandidate(target, url));
    const mergedYoutube = youtubeVideoCandidatesForTrack(target);
    youtubeVideoCandidatesForTrack(source).forEach((candidate) => {
      const exists = mergedYoutube.some((item) => item.videoId === candidate.videoId);
      if (!exists) mergedYoutube.push(candidate);
    });
    if (mergedYoutube.length) setYouTubeVideoCandidates(target, mergedYoutube);
    if (!target.soundcloudTrackUrl && source.soundcloudTrackUrl) target.soundcloudTrackUrl = source.soundcloudTrackUrl;
    if (!target.soundcloudUrl && source.soundcloudUrl) target.soundcloudUrl = source.soundcloudUrl;
    if (!target.bandcampTrackUrl && source.bandcampTrackUrl) target.bandcampTrackUrl = source.bandcampTrackUrl;
    if (!target.bandcampTrackId && source.bandcampTrackId) target.bandcampTrackId = source.bandcampTrackId;
  };

  const bestByKey = new Map();
  const tracksByKey = new Map();
  catalog.forEach((track) => {
    const key = recommendationTrackKey(track);
    if (!key) return;
    const grouped = tracksByKey.get(key) || [];
    grouped.push(track);
    tracksByKey.set(key, grouped);
    const currentBest = bestByKey.get(key);
    if (!currentBest || scoreTrack(track) > scoreTrack(currentBest)) {
      bestByKey.set(key, track);
    }
  });
  if (bestByKey.size >= catalog.length) return;

  const deduped = [];
  const seen = new Set();
  catalog.forEach((track) => {
    const key = recommendationTrackKey(track);
    if (!key) {
      deduped.push(track);
      return;
    }
    if (seen.has(key)) return;
    seen.add(key);
    const best = bestByKey.get(key) || track;
    (tracksByKey.get(key) || [])
      .filter((item) => item !== best)
      .forEach((item) => mergeTrackPlayableCandidates(best, item));
    deduped.push(best);
  });

  catalog.length = 0;
  deduped.forEach((track) => catalog.push(track));
}

function boost(mapRef, key, amount = 1) {
  const cleanKey = normalize(key || "");
  if (!cleanKey) return;
  mapRef.set(cleanKey, (mapRef.get(cleanKey) || 0) + amount);
}

function swipeTrainingSignalCount() {
  const stored = Math.max(0, Number(userStats.swipeTrainingSignals) || 0);
  if (stored > 0) return stored;
  return (
    Math.max(0, Number(userStats.likedSongs) || 0) +
    Math.max(0, Number(userStats.likedArtists) || 0) +
    Math.max(0, Number(userStats.likedDiscoveries) || 0) +
    Math.max(0, Number(userStats.alreadyKnew) || 0) +
    Math.max(0, Number(userStats.skipped) || 0) +
    Math.max(0, Number(userStats.ratingCount) || 0)
  );
}

function adaptiveLearningMultiplier() {
  const signals = swipeTrainingSignalCount();
  if (signals >= 30) return 1.9;
  if (signals >= 20) return 1.62;
  if (signals >= 10) return 1.34;
  if (signals >= 5) return 1.14;
  return 1;
}

function swipeLearningLevelKey() {
  const signals = swipeTrainingSignalCount();
  if (signals >= 30) return "swipeLearningLevelStrong";
  if (signals >= 20) return "swipeLearningLevelGood";
  if (signals >= 10) return "swipeLearningLevelWarming";
  if (signals > 0) return "swipeLearningLevelEarly";
  return "swipeLearningLevelEmpty";
}

function recordSwipeTrainingSignal(options = {}) {
  const source = String(options?.source || "").toLowerCase();
  if (!source || source === "system") return;
  userStats.swipeTrainingSignals = Math.max(0, Number(userStats.swipeTrainingSignals) || 0) + 1;

  const reached = SWIPE_LEARNING_MILESTONES
    .filter((milestone) => userStats.swipeTrainingSignals >= milestone)
    .pop() || 0;
  const previous = Math.max(0, Number(userStats.lastSwipeLearningMilestone) || 0);
  if (reached > previous) {
    userStats.lastSwipeLearningMilestone = reached;
    pendingSwipeLearningMessage = t(`swipeLearningMilestone${reached}`, {
      count: userStats.swipeTrainingSignals
    });
  }
}

function takeSwipeLearningMessage() {
  const message = pendingSwipeLearningMessage;
  pendingSwipeLearningMessage = "";
  return message;
}

function appendSwipeLearningMessage(message = "") {
  const learningMessage = takeSwipeLearningMessage();
  return [message, learningMessage].filter(Boolean).join(" ");
}

function getAdaptiveScore(track) {
  const styleKey = normalize(track.style);
  const artistKeys = artistMatchingKeys(track.artist);
  const energyKey = normalize(track.energy);
  const artistLike = Math.max(
    0,
    ...Array.from(artistKeys).map((key) => Number(adaptiveModel.likedArtists.get(key) || 0))
  );
  const artistDislike = Math.max(
    0,
    ...Array.from(artistKeys).map((key) => Number(adaptiveModel.dislikedArtists.get(key) || 0))
  );
  const like =
    (adaptiveModel.likedStyles.get(styleKey) || 0) * 1.2 +
    artistLike * 1.6 +
    (adaptiveModel.likedEnergies.get(energyKey) || 0) * 0.8;
  const dislike =
    (adaptiveModel.dislikedStyles.get(styleKey) || 0) * 1.4 +
    artistDislike * 2 +
    (adaptiveModel.dislikedEnergies.get(energyKey) || 0) * 0.9;

  return (like - dislike) * adaptiveLearningMultiplier();
}

function registerTrackPreferenceSignal(track, delta = 0) {
  if (!track || !Number.isFinite(delta) || delta === 0) return;
  const key = recommendationTrackKey(track);
  if (!key) return;
  const next = (trackPreferenceSignals.get(key) || 0) + delta;
  if (Math.abs(next) < 0.04) {
    trackPreferenceSignals.delete(key);
    return;
  }
  const clamped = Math.max(-8, Math.min(8, next));
  trackPreferenceSignals.set(key, clamped);
}

function adjustPreviewReliabilitySignal(style = "", delta = 0) {
  const styleKey = normalize(style || "");
  if (!styleKey || !Number.isFinite(delta) || delta === 0) return;
  const next = (previewReliabilityByStyle.get(styleKey) || 0) + delta;
  if (Math.abs(next) < 0.04) {
    previewReliabilityByStyle.delete(styleKey);
    return;
  }
  previewReliabilityByStyle.set(styleKey, Math.max(-8, Math.min(8, next)));
}

function adjustTrackPreviewIssueSignal(track, delta = 0) {
  if (!track || !Number.isFinite(delta) || delta === 0) return;
  const trackKey = recommendationTrackKey(track);
  if (!trackKey) return;
  const next = (trackPreviewIssueSignals.get(trackKey) || 0) + delta;
  if (next <= 0.04) {
    trackPreviewIssueSignals.delete(trackKey);
    return;
  }
  trackPreviewIssueSignals.set(trackKey, Math.max(0.05, Math.min(8, next)));
}

const RECOMMENDATION_ISSUE_REASONS = new Set(["style_issue", "bpm_issue", "image_issue"]);

function adjustTrackRecommendationIssueSignal(track, delta = 0) {
  if (!track || !Number.isFinite(delta) || delta === 0) return;
  const trackKey = recommendationTrackKey(track);
  if (!trackKey) return;
  const next = (trackRecommendationIssueSignals.get(trackKey) || 0) + delta;
  if (next <= 0.04) {
    trackRecommendationIssueSignals.delete(trackKey);
    return;
  }
  trackRecommendationIssueSignals.set(trackKey, Math.max(0.05, Math.min(8, next)));
}

function recommendationIssuePenaltyForTrack(track) {
  if (!track) return 0;
  const trackKey = recommendationTrackKey(track);
  const issueSignal = Number(trackRecommendationIssueSignals.get(trackKey) || 0);
  return issueSignal > 0 ? Math.min(5.4, issueSignal * 1.35) : 0;
}

function trackHasReliableAudioPreview(track) {
  if (!track) return false;
  if (normalizePreviewUrl(track.previewUrl)) return true;
  if (normalizePreviewUrl(track.artistPreviewFallback?.previewUrl || "")) return true;
  return previewCandidatesForTrack(track).some((candidate) => Boolean(normalizePreviewUrl(candidate)));
}

function trackHasConfirmedAudioPreview(track) {
  if (!track || !normalizePreviewUrl(track.previewUrl)) return false;
  if (track.previewChecked && track.previewMissing) return false;
  return true;
}

function trackHasExternalPlayableFallback(track) {
  return Boolean(
    trackHasDirectYouTubeVideo(track) ||
    trackHasDirectSoundCloudTrack(track) ||
    trackHasEmbeddableBandcampTrack(track)
  );
}

function trackHasPlayablePreviewExperience(track) {
  return (
    trackHasReliableAudioPreview(track) ||
    trackHasExternalPlayableFallback(track)
  );
}

function inferNegativeFeedbackReason(track, { source = "skip" } = {}) {
  if (!track) return "taste_mismatch";
  const noReliableAudio =
    !trackHasPlayablePreviewExperience(track) ||
    Boolean(
      track.previewChecked &&
      track.previewMissing &&
      !trackHasDirectSoundCloudTrack(track) &&
      !trackHasDirectYouTubeVideo(track) &&
      !trackHasEmbeddableBandcampTrack(track) &&
      !trackHasDirectBandcampTrack(track)
    );
  const embeddedFallbackVisible =
    Boolean(trackPreview?.classList.contains("hidden")) &&
    (
      Boolean(youtubePreviewWrap && !youtubePreviewWrap.classList.contains("hidden")) ||
      Boolean(soundcloudPreviewWrap && !soundcloudPreviewWrap.classList.contains("hidden")) ||
      Boolean(bandcampPreviewWrap && !bandcampPreviewWrap.classList.contains("hidden"))
    );

  if (source === "preview_dislike" && (noReliableAudio || embeddedFallbackVisible)) {
    return "preview_issue";
  }
  if ((source === "novelty_not_yet" || source === "skip") && noReliableAudio && embeddedFallbackVisible) {
    return "preview_issue";
  }
  return "taste_mismatch";
}

function previewPenaltyForTrack(track) {
  if (!track) return 0;
  let penalty = 0;
  const trackKey = recommendationTrackKey(track);
  const issueSignal = Number(trackPreviewIssueSignals.get(trackKey) || 0);
  if (issueSignal > 0) {
    penalty += Math.min(3.1, issueSignal * 0.72);
  }

  const styleSignal = Number(previewReliabilityByStyle.get(normalize(track.style || "")) || 0);
  if (!trackHasPlayablePreviewExperience(track) && styleSignal < 0) {
    penalty += Math.min(1.7, Math.abs(styleSignal) * 0.34);
  }
  return penalty;
}

function registerTrackFeedback(track, liked, options = {}) {
  if (!track) return;
  recordSwipeTrainingSignal(options);
  const delta = liked ? 1 : 1.2;
  if (liked) {
    boost(adaptiveModel.likedStyles, track.style, delta);
    boost(adaptiveModel.likedArtists, track.artist, delta);
    boost(adaptiveModel.likedEnergies, track.energy, 0.6);
    registerTrackPreferenceSignal(track, 1.15);
    removeArtistIdentityFromSet(rejectedArtists, track.artist);
    adjustTrackPreviewIssueSignal(track, options?.rewardPreview ? -0.95 : -0.45);
    adjustPreviewReliabilitySignal(track.style, options?.rewardPreview ? 0.16 : 0.07);
    rememberLikedTrack(track, options?.source || "liked");
    recordDailyMusicAction(track, "like");
    saveProgress();
    return "liked";
  }
  const reason = options?.reason || inferNegativeFeedbackReason(track, { source: options?.source || "skip" });
  rememberDislikedTrack(track, options?.source || reason || "disliked");
  if (reason === "preview_issue") {
    // Quando falha no preview, aprendemos a priorizar faixas com player melhor sem punir forte o gosto musical.
    boost(adaptiveModel.dislikedStyles, track.style, 0.18);
    boost(adaptiveModel.dislikedArtists, track.artist, 0.38);
    boost(adaptiveModel.dislikedEnergies, track.energy, 0.12);
    registerTrackPreferenceSignal(track, -0.38);
    if (options?.avoidRepeatArtist !== false) {
      addArtistIdentityToSet(rejectedArtists, track.artist);
    }
    adjustTrackPreviewIssueSignal(track, 1);
    adjustPreviewReliabilitySignal(track.style, -0.65);
    saveProgress();
    return reason;
  }

  if (RECOMMENDATION_ISSUE_REASONS.has(reason)) {
    // Erro de classificacao/tempo/imagem reduz confianca sem confundir com gosto musical do usuario.
    const issueWeight = reason === "style_issue" ? 1.6 : reason === "bpm_issue" ? 1.35 : 1.1;
    if (reason === "style_issue") boost(adaptiveModel.dislikedStyles, track.style, 0.22);
    if (reason === "image_issue") boost(adaptiveModel.dislikedArtists, track.artist, 0.12);
    registerTrackPreferenceSignal(track, -0.56 * issueWeight);
    adjustTrackRecommendationIssueSignal(track, issueWeight);
    adjustPreviewReliabilitySignal(track.style, reason === "image_issue" ? -0.08 : -0.18);
    saveProgress();
    return reason;
  }

  boost(adaptiveModel.dislikedStyles, track.style, 1.35);
  boost(adaptiveModel.dislikedArtists, track.artist, 1.72);
  boost(adaptiveModel.dislikedEnergies, track.energy, 0.86);
  registerTrackPreferenceSignal(track, -1.02);
  if (options?.avoidRepeatArtist !== false) {
    addArtistIdentityToSet(rejectedArtists, track.artist);
  }
  adjustTrackPreviewIssueSignal(track, -0.65);
  adjustPreviewReliabilitySignal(track.style, 0.08);
  saveProgress();
  return reason;
}

function collectSuppressedArtistsFromAdaptiveModel() {
  const suppressed = new Set();
  const MIN_DISLIKE_SCORE = 1.6; // bloqueia mais cedo artistas rejeitados repetidamente e reduz repetição na sessão.
  const LIKE_RECOVERY_MARGIN = 0.35;

  adaptiveModel.dislikedArtists.forEach((dislikeValue, artistKey) => {
    const dislikeScore = Number(dislikeValue) || 0;
    if (dislikeScore < MIN_DISLIKE_SCORE) return;
    const likedScore = Number(adaptiveModel.likedArtists.get(artistKey) || 0);
    if (likedScore + LIKE_RECOVERY_MARGIN >= dislikeScore) return;
    addArtistIdentityToSet(suppressed, artistKey);
  });

  return suppressed;
}

function recommendationTrackKey(track) {
  if (!track) return "";
  return normalize(`${track.artist}::${track.song}`);
}

function starAriaLabel(stars) {
  const count = Math.max(1, Number(stars) || 1);
  if (currentLanguage === "en") return `${count} ${count === 1 ? "star" : "stars"}`;
  if (currentLanguage === "es") return `${count} ${count === 1 ? "estrella" : "estrellas"}`;
  return `${count} ${count === 1 ? "estrela" : "estrelas"}`;
}

function ratingMoodLabel(stars) {
  const value = Math.max(0, Math.min(5, Math.round(Number(stars) || 0)));
  const labels = {
    pt: ["", "Não bateu", "Fraco", "Ok", "Curti", "Favorita"],
    en: ["", "Missed", "Weak fit", "OK", "Liked", "Favorite"],
    es: ["", "No conectó", "Floja", "Ok", "Me gustó", "Favorita"]
  };
  const list = labels[currentLanguage] || labels.pt;
  return list[value] || "";
}

function ratingSignalFromStars(stars) {
  const value = Math.max(1, Math.min(5, Math.round(Number(stars) || 0)));
  if (value <= 1) return -1.6;
  if (value === 2) return -0.8;
  if (value === 3) return 0;
  if (value === 4) return 0.8;
  return 1.6;
}

function applyRatingSignal(track, signalDelta = 0) {
  if (!track || !Number.isFinite(signalDelta) || signalDelta === 0) return;
  const amount = Math.abs(signalDelta);
  registerTrackPreferenceSignal(track, signalDelta * 0.72);
  if (signalDelta > 0) {
    boost(adaptiveModel.likedStyles, track.style, amount * 1.05);
    boost(adaptiveModel.likedArtists, track.artist, amount * 1.2);
    boost(adaptiveModel.likedEnergies, track.energy, amount * 0.7);
    registerSpiritSignal(track.style, amount * 0.85);
    return;
  }

  boost(adaptiveModel.dislikedStyles, track.style, amount * 1.05);
  boost(adaptiveModel.dislikedArtists, track.artist, amount * 1.2);
  boost(adaptiveModel.dislikedEnergies, track.energy, amount * 0.75);
  registerSpiritSignal(track.style, -amount * 0.65);
}

function recalculateRatingStats() {
  let count = 0;
  let sum = 0;
  const invalidKeys = [];
  trackRatings.forEach((value, key) => {
    const stars = Math.round(Number(value) || 0);
    if (stars < 1 || stars > 5) {
      invalidKeys.push(key);
      return;
    }
    if (Number(value) !== stars) {
      trackRatings.set(key, stars);
    }
    count += 1;
    sum += stars;
  });
  invalidKeys.forEach((key) => trackRatings.delete(key));
  userStats.ratingCount = count;
  userStats.ratingSum = sum;
}

function ratingAverageText() {
  if (!userStats.ratingCount) return "0.0";
  return (userStats.ratingSum / userStats.ratingCount).toFixed(1);
}

function ratingValueForCurrentTrack() {
  const key = recommendationTrackKey(currentRecommendation);
  if (!key) return 0;
  return Math.max(0, Math.min(5, Math.round(Number(trackRatings.get(key)) || 0)));
}

function starButtonForValue(stars) {
  const value = Math.max(1, Math.min(5, Math.round(Number(stars) || 1)));
  return starButtons.find((button) => Number(button.dataset.stars || 0) === value) || starButtons[value - 1] || null;
}

function setRatingStars(stars, { preview = false } = {}) {
  const selected = Math.max(0, Math.min(5, Math.round(Number(stars) || 0)));
  if (starRating) {
    starRating.classList.toggle("is-previewing", Boolean(preview && selected));
    if (preview) starRating.dataset.previewStars = String(selected);
    else {
      starRating.dataset.stars = String(selected);
      delete starRating.dataset.previewStars;
    }
  }
  starButtons.forEach((button, index) => {
    const value = index + 1;
    const active = value <= selected;
    const isSelected = selected > 0 && value === selected;
    button.classList.toggle("active", active);
    button.classList.toggle("filled", active);
    button.classList.toggle("selected", isSelected);
    button.classList.toggle("preview", Boolean(preview && active));
    if (!preview) {
      button.setAttribute("aria-checked", isSelected ? "true" : "false");
      button.tabIndex = selected ? (isSelected ? 0 : -1) : (value === 1 ? 0 : -1);
    }
  });
}

function previewRatingStars(stars) {
  if (!currentRecommendation) return;
  const value = Math.max(1, Math.min(5, Math.round(Number(stars) || 0)));
  setRatingStars(value, { preview: true });
  if (ratingHint) {
    ratingHint.textContent = t("ratingPreviewHint", {
      label: ratingMoodLabel(value),
      stars: value
    });
  }
  if (ratingCelebration) {
    ratingCelebration.textContent = ratingMoodLabel(value);
    ratingCelebration.classList.toggle("is-positive", value >= 4);
  }
}

function clearRatingPreview() {
  renderTrackRating(currentRecommendation);
}

function renderTrackRating(track = currentRecommendation) {
  const key = recommendationTrackKey(track);
  const hasTrack = Boolean(track && key);
  starButtons.forEach((button, index) => {
    button.disabled = !hasTrack;
    button.setAttribute("aria-label", starAriaLabel(index + 1));
  });

  if (starRating) starRating.setAttribute("aria-label", t("ratingAriaGroup"));
  if (!hasTrack) {
    setRatingStars(0);
    if (ratingHint) ratingHint.textContent = t("ratingHint");
    if (ratingCelebration) {
      ratingCelebration.textContent = t("ratingAwaiting");
      ratingCelebration.classList.remove("is-positive");
    }
    return;
  }

  const selected = Math.max(0, Math.min(5, Number(trackRatings.get(key)) || 0));
  setRatingStars(selected);
  if (ratingHint) {
    ratingHint.textContent = selected
      ? t("ratingSavedHint", { label: ratingMoodLabel(selected), stars: selected })
      : t("ratingHint");
  }
  if (ratingCelebration) {
    ratingCelebration.textContent = selected ? ratingMoodLabel(selected) : t("ratingAwaiting");
    ratingCelebration.classList.toggle("is-positive", selected >= 4);
  }
}

async function rateCurrentRecommendation(stars, triggerEl = null) {
  if (!currentRecommendation) return;
  const value = Math.max(1, Math.min(5, Math.round(Number(stars) || 0)));
  const key = recommendationTrackKey(currentRecommendation);
  if (!key) return;

  const previousSignal = Number(trackRatingSignals.get(key)) || 0;
  const nextSignal = ratingSignalFromStars(value);
  const signalDelta = nextSignal - previousSignal;
  if (signalDelta !== 0) applyRatingSignal(currentRecommendation, signalDelta);
  recordSwipeTrainingSignal({ source: "rating" });

  trackRatings.set(key, value);
  if (nextSignal === 0) trackRatingSignals.delete(key);
  else trackRatingSignals.set(key, nextSignal);
  if (value >= 4) {
    rememberLikedTrack(currentRecommendation, `rating_${value}`);
  } else if (value <= 2) {
    rememberDislikedTrack(currentRecommendation, `rating_${value}`);
  }

  recalculateRatingStats();
  renderTrackRating(currentRecommendation);
  updateStats();

  if (feedbackMessage) {
    feedbackMessage.textContent = appendSwipeLearningMessage(t("ratingSavedFeedback", {
      label: ratingMoodLabel(value),
      stars: value,
      song: currentRecommendation.song
    }));
  }

  if (value >= 4) {
    burstConfetti(triggerEl || starRating, ["#ffd77d", "#ffb48b", "#f8b5ff", "#7de0ff"]);
  }
  showToast(t("ratingSavedToast", { label: ratingMoodLabel(value), stars: value }));

  await runPositiveFeedbackFollowups(triggerEl || starRating || spiritBadge, {
    celebrate: false,
    forceAnimation: value >= 4,
    animateBio: false,
    loadEvents: false
  });
}

function deezerJsonp(url) {
  return new Promise((resolve, reject) => {
    const callbackName = `dzcb_${Date.now()}_${Math.floor(Math.random() * 100000)}`;
    const script = document.createElement("script");
    let settled = false;
    const timeout = setTimeout(() => {
      if (settled) return;
      settled = true;
      cleanup();
      reject(new Error("Timeout na consulta Deezer"));
    }, 4500);

    function cleanup() {
      clearTimeout(timeout);
      window[callbackName] = () => {};
      setTimeout(() => {
        if (window[callbackName]) delete window[callbackName];
      }, 10000);
      if (script.parentNode) script.parentNode.removeChild(script);
    }

    window[callbackName] = (data) => {
      if (settled) return;
      settled = true;
      cleanup();
      resolve(data);
    };

    script.onerror = () => {
      if (settled) return;
      settled = true;
      cleanup();
      reject(new Error("Falha ao carregar Deezer JSONP"));
    };

    const separator = url.includes("?") ? "&" : "?";
    script.src = `${url}${separator}output=jsonp&callback=${callbackName}`;
    document.body.appendChild(script);
  });
}

function itunesJsonp(url) {
  return new Promise((resolve, reject) => {
    const callbackName = `itcb_${Date.now()}_${Math.floor(Math.random() * 100000)}`;
    const script = document.createElement("script");
    let settled = false;
    const timeout = setTimeout(() => {
      if (settled) return;
      settled = true;
      cleanup();
      reject(new Error("Timeout na consulta iTunes"));
    }, 4500);

    function cleanup() {
      clearTimeout(timeout);
      window[callbackName] = () => {};
      setTimeout(() => {
        if (window[callbackName]) delete window[callbackName];
      }, 10000);
      if (script.parentNode) script.parentNode.removeChild(script);
    }

    window[callbackName] = (data) => {
      if (settled) return;
      settled = true;
      cleanup();
      resolve(data);
    };

    script.onerror = () => {
      if (settled) return;
      settled = true;
      cleanup();
      reject(new Error("Falha ao carregar iTunes JSONP"));
    };

    const separator = url.includes("?") ? "&" : "?";
    script.src = `${url}${separator}callback=${callbackName}`;
    document.body.appendChild(script);
  });
}

function collectStyleKnowledgeArtists(style) {
  if (!style) return [];
  const ordered = [];
  const seen = new Set();
  const addArtist = (artistLike = "") => {
    const artist = String(artistLike || "").trim();
    if (!artist) return;
    if (!artistAllowedForStyle(style, artist)) return;
    const key = artistMatchKey(artist);
    if (!key || seen.has(key)) return;
    seen.add(key);
    ordered.push(artist);
  };

  Array.from(recentArtistSignals.values())
    .filter((entry) => entry?.style === style)
    .sort((a, b) => {
      const dateA = parseReleaseDateSafe(a?.releaseDate)?.getTime() || 0;
      const dateB = parseReleaseDateSafe(b?.releaseDate)?.getTime() || 0;
      return dateB - dateA;
    })
    .forEach((entry) => addArtist(entry.artist));

  discoveryCatalog
    .filter((entry) => entry?.style === style)
    .forEach((entry) => addArtist(entry.name));

  (STYLE_ARTIST_SEEDS[style] || []).forEach((artist) => addArtist(artist));
  catalog
    .filter((track) => track?.style === style)
    .forEach((track) => addArtist(track.artist));

  return ordered;
}

function styleLocalArtistKnowledgeCount(style) {
  if (!style) return 0;
  const artists = new Set();
  const addArtist = (artistLike = "") => {
    const artist = String(artistLike || "").trim();
    if (!artist || !artistAllowedForStyle(style, artist)) return;
    const key = artistMatchKey(artist);
    if (!key) return;
    artists.add(key);
  };
  (STYLE_ARTIST_SEEDS[style] || []).forEach((artist) => addArtist(artist));
  discoveryCatalog.forEach((entry) => {
    if (entry?.style === style) addArtist(entry.name);
  });
  recentArtistSignals.forEach((entry) => {
    if (entry?.style === style) addArtist(entry.artist);
  });
  catalog.forEach((track) => {
    if (track?.style === style) addArtist(track.artist);
  });
  return artists.size;
}

function selectHydrationArtists(style, artists = [], cap = 24) {
  const normalizedPool = [];
  const seen = new Set();
  (artists || []).forEach((artistLike) => {
    const artist = String(artistLike || "").trim();
    const key = artistMatchKey(artist);
    if (!artist || !key || seen.has(key)) return;
    seen.add(key);
    normalizedPool.push(artist);
  });
  if (!normalizedPool.length) return [];
  if (normalizedPool.length <= cap) return normalizedPool;

  const guaranteedCount = Math.min(12, cap);
  const guaranteed = normalizedPool.slice(0, guaranteedCount);
  const remainder = normalizedPool.slice(guaranteedCount);
  if (!remainder.length) return guaranteed;

  const styleEntropy = String(style || "")
    .split("")
    .reduce((acc, char) => acc + char.charCodeAt(0), 0);
  const cursorSeed = styleEntropy + catalog.length + (Number(dynamicCatalogByStyle.get(style)) || 0);
  const offset = Math.abs(cursorSeed) % remainder.length;
  const rotated = remainder.slice(offset).concat(remainder.slice(0, offset));
  return [...guaranteed, ...rotated.slice(0, Math.max(0, cap - guaranteed.length))];
}

function stylePoolStats(style) {
  const tracks = catalog.filter((track) => track.style === style);
  return {
    trackCount: tracks.length,
    artistCount: new Set(tracks.map((track) => artistMatchKey(track.artist)).filter(Boolean)).size
  };
}

function styleCoverageTarget(style) {
  const base = {
    tracks: MIN_TRACKS_PER_STYLE,
    artists: MIN_ARTISTS_PER_STYLE,
    labels: MIN_LABELS_PER_STYLE
  };
  const override = STYLE_COVERAGE_OVERRIDES[style] || {};
  const artistTarget = Number(override.artists) || base.artists;
  return {
    tracks: Number(override.tracks) || base.tracks,
    artists: Math.max(base.artists, artistTarget),
    labels: Number(override.labels) || base.labels
  };
}

function styleCoverageStats(style) {
  const styleTracks = catalog.filter((track) => track.style === style);
  const validatedTracks = styleTracks.filter((track) => {
    if (!isTrackEligibleForRecommendation(track)) return false;
    return track.style === style;
  });
  const artistsByIdentity = new Set(validatedTracks.map((track) => artistMatchKey(track.artist)).filter(Boolean));
  const labels = new Set(
    validatedTracks
      .map((track) => sanitizeLabel(track.label, track.artist, track.song))
      .map((label) => normalize(label))
      .filter((label) => label && label !== normalize("Catálogo dinâmico"))
  );

  return {
    tracks: validatedTracks.length,
    artists: artistsByIdentity.size,
    labels: labels.size,
    localArtists: styleLocalArtistKnowledgeCount(style)
  };
}

function styleCoverageArtistSignal(stats = {}) {
  return Math.max(Number(stats.artists) || 0, Number(stats.localArtists) || 0);
}

function isStyleCoverageHealthy(style, stats = styleCoverageStats(style), target = styleCoverageTarget(style)) {
  return stats.tracks >= target.tracks && styleCoverageArtistSignal(stats) >= target.artists && stats.labels >= target.labels;
}

function externalCatalogHydrationAllowed() {
  if (typeof window !== "undefined" && window.SONIC_LOCAL_CATALOG_ONLY === true) return false;
  if (typeof navigator !== "undefined" && navigator.onLine === false) return false;
  return true;
}

function coveragePassLimit(style, maxPasses = COVERAGE_MAX_PASSES) {
  if (!style) return maxPasses;
  if (style === "psycore") return Math.max(4, Math.min(maxPasses, 6));
  if (STRICT_DYNAMIC_BPM_STYLES.has(style)) return Math.min(maxPasses, FAST_COVERAGE_MAX_PASSES);
  return maxPasses;
}

function coverageTimeoutForStyle(style) {
  if (style === "psycore") return Math.max(DEFAULT_COVERAGE_TIMEOUT_MS, 42000);
  return STRICT_DYNAMIC_BPM_STYLES.has(style) ? FAST_COVERAGE_TIMEOUT_MS : DEFAULT_COVERAGE_TIMEOUT_MS;
}

async function ensureStyleCoverageWithTimeout(style, maxPasses = COVERAGE_MAX_PASSES) {
  if (!style) return { ok: true, stats: null, target: null };
  const effectivePasses = coveragePassLimit(style, maxPasses);
  const timeoutMs = coverageTimeoutForStyle(style);

  let timeoutId = 0;
  const timeoutPromise = new Promise((resolve) => {
    timeoutId = window.setTimeout(() => {
      resolve({
        ok: false,
        timedOut: true,
        stats: styleCoverageStats(style),
        target: styleCoverageTarget(style)
      });
    }, timeoutMs);
  });

  const coveragePromise = ensureStyleCoverage(style, effectivePasses);
  const result = await Promise.race([coveragePromise, timeoutPromise]);
  window.clearTimeout(timeoutId);
  return result;
}

function buildCoverageReport() {
  return Object.keys(STYLE_BPM_RULES)
    .map((style) => {
      const target = styleCoverageTarget(style);
      const stats = styleCoverageStats(style);
      const artistSignal = styleCoverageArtistSignal(stats);
      return {
        style,
        tracks: stats.tracks,
        artists: stats.artists,
        labels: stats.labels,
        localArtists: stats.localArtists,
        artistSignal,
        targetTracks: target.tracks,
        targetArtists: target.artists,
        targetLabels: target.labels,
        healthy: isStyleCoverageHealthy(style, stats, target)
      };
    })
    .sort((a, b) => a.style.localeCompare(b.style));
}

function buildCatalogGenreAudit({ sampleLimit = 80 } = {}) {
  const issues = [];
  const issueTypeCounts = new Map();
  const styleIssueCounts = new Map();
  const problematicTrackKeys = new Set();

  const registerIssue = (track, issue, detail = "") => {
    const safeTrack = track || {};
    const style = String(safeTrack.style || "");
    const trackKey = recommendationTrackKey(safeTrack) || normalize(`${safeTrack.artist || ""}::${safeTrack.song || ""}`);
    if (trackKey) problematicTrackKeys.add(trackKey);
    issueTypeCounts.set(issue, (issueTypeCounts.get(issue) || 0) + 1);
    if (style) styleIssueCounts.set(style, (styleIssueCounts.get(style) || 0) + 1);
    issues.push({
      issue,
      detail,
      style,
      artist: String(safeTrack.artist || "").trim(),
      song: String(safeTrack.song || "").trim(),
      source: String(safeTrack.source || "").trim()
    });
  };

  catalog.forEach((track) => {
    if (!track || typeof track !== "object") return;
    const style = String(track.style || "").trim();
    if (!style || !STYLE_BPM_RULES[style]) {
      registerIssue(track, "invalid_style", "Style not found in STYLE_BPM_RULES.");
      return;
    }

    if (!artistAllowedForStyle(style, track.artist)) {
      registerIssue(track, "artist_not_allowed_for_style", "Artist/override/whitelist rule rejected this style.");
    }
    if (!labelAllowedForStyle(style, track.label)) {
      registerIssue(track, "label_not_allowed_for_style", "Label rule rejected this style.");
    }

    const bpmValue = Number(track.bpmExact);
    if (Number.isFinite(bpmValue) && bpmValue > 0 && !bpmFitsStyle(style, bpmValue)) {
      registerIssue(track, "bpm_out_of_style_range", `BPM ${Math.round(bpmValue)} outside ${style}.`);
    }

    if (hasTrackStyleSignalConflict(style, track)) {
      registerIssue(track, "style_signal_conflict", "Artist/label/genre text signals conflict with selected style.");
    }

    const hasAudioPreview = Boolean(normalizePreviewUrl(track.previewUrl));
    const hasYoutubePath = Boolean(buildYouTubeEmbedUrl(track, { autoplay: false }));
    const hasExternalPath = Boolean(buildSpotifyTrackLink(track) || buildYouTubeTrackLink(track) || buildSoundCloudTrackLink(track) || buildBandcampTrackLink(track));
    if (!hasAudioPreview && !hasYoutubePath && !hasExternalPath) {
      registerIssue(track, "no_preview_or_external_path", "No audio preview, no YouTube embed, and no external fallback link.");
    }
  });

  const styleCoverageGaps = buildCoverageReport().filter((row) => !row.healthy);
  const byType = Object.fromEntries(
    Array.from(issueTypeCounts.entries()).sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]))
  );
  const byStyle = Object.fromEntries(
    Array.from(styleIssueCounts.entries()).sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]))
  );

  return {
    totalCatalogTracks: catalog.length,
    issueCount: issues.length,
    problematicTracks: problematicTrackKeys.size,
    stylesWithCoverageGap: styleCoverageGaps.length,
    byType,
    byStyle,
    sample: Number(sampleLimit) > 0 ? issues.slice(0, sampleLimit) : [],
    coverageGaps: styleCoverageGaps
  };
}

async function ensureStyleCoverage(style, maxPasses = COVERAGE_MAX_PASSES) {
  if (!style) return { ok: true, stats: null, target: null };

  const target = styleCoverageTarget(style);
  for (let pass = 0; pass < maxPasses; pass += 1) {
    sanitizeCatalogByStyleRules();
    purgeDynamicMismatches(style);
    const statsBefore = styleCoverageStats(style);
    if (isStyleCoverageHealthy(style, statsBefore, target)) {
      return { ok: true, stats: statsBefore, target };
    }

    await hydrateCatalogForStyle(style);
    sanitizeCatalogByStyleRules();
    purgeDynamicMismatches(style);

    const statsAfter = styleCoverageStats(style);
    if (isStyleCoverageHealthy(style, statsAfter, target)) {
      return { ok: true, stats: statsAfter, target };
    }

    const noProgress =
      statsAfter.tracks <= statsBefore.tracks &&
      statsAfter.artists <= statsBefore.artists &&
      statsAfter.labels <= statsBefore.labels;
    const localArtists = Number(statsAfter.localArtists) || styleLocalArtistKnowledgeCount(style);
    if (noProgress && pass >= 1 && localArtists <= 0) break;
  }

  const finalStats = styleCoverageStats(style);
  return { ok: isStyleCoverageHealthy(style, finalStats, target), stats: finalStats, target };
}

function canFallbackToPartialCoverage(coverage) {
  const tracks = Number(coverage?.stats?.tracks) || 0;
  const artists = Number(coverage?.stats?.artists) || 0;
  const localArtists = Number(coverage?.stats?.localArtists) || 0;
  return (tracks > 0 && artists > 0) || localArtists >= 4;
}

function resolveTrackDurationSeconds(track) {
  if (!track) return 0;
  const meta = TRACK_METADATA[`${track.song}|${track.artist}`] || {};
  return parseDurationTextToSeconds(meta.duration);
}

function isTrackEligibleForRecommendation(track) {
  if (!track) return false;
  applyCuratedTrackMetadata(track);
  if (!track.style || !track.artist || !track.song) return false;
  if (isLikelyChannelStyleArtistName(track.artist)) return false;
  if (isLikelyGeneratedTrackTitle(track.song)) return false;
  const trustedCurated = isTrustedCuratedCatalogTrack(track);
  if (track.existenceVerified === false && !trustedCurated) return false;
  if (!artistAllowedForStyle(track.style, track.artist)) return false;
  if (!labelAllowedForStyle(track.style, track.label)) return false;
  if (trackBlockedForStyle(track.style, track)) return false;
  if (hasTrackStyleSignalConflict(track.style, track)) return false;
  if (!trackFineSubgenreHasRecommendationProof(track)) return false;
  if (!dynamicPsyHomonymHasStrongIdentityProof(track)) return false;
  const bpmValue = Number(track.bpmExact);
  if (Number.isFinite(bpmValue) && bpmValue > 0 && !bpmFitsStyle(track.style, bpmValue)) return false;
  if (isDynamicSource(track.source)) {
    if (requiresExactBpmForDynamic(track.style, track.source) && !hasReliableBpmForTrack(track)) {
      return false;
    }
    if (requiresSeedAnchorForDynamicStyle(track.style) && !artistSeedAnchoredForStyle(track.style, track.artist)) {
      return false;
    }
    if (dynamicFineStyleNeedsVerifiedTrack(track.style, track.source) && !hasReliableBpmForTrack(track)) {
      return false;
    }
    const invalidDynamic = isLikelyCompilationEntry({
      song: track.song,
      artist: track.artist,
      label: track.label,
      durationSec: resolveTrackDurationSeconds(track)
    });
    if (invalidDynamic) return false;
  }
  return true;
}

async function fetchDeezerTrackDetails(trackId) {
  if (!trackId) return null;
  try {
    const details = await deezerJsonp(`https://api.deezer.com/track/${trackId}`);
    return details && !details.error ? details : null;
  } catch (_err) {
    return null;
  }
}

function styleSearchParts(style) {
  const styleTerm = STYLE_SEARCH_TERMS[style] || styleLabelByValue(style);
  const styleTokens = String(styleTerm || "")
    .split(/\s+/)
    .map((token) => String(token || "").trim())
    .filter(Boolean);
  const family = familyOf(style);
  const familyTerm = family === "dnb"
    ? "drum and bass"
    : family === "psytrance"
      ? "psytrance"
      : family === "techno"
        ? "techno"
        : family === "house"
          ? "house"
          : family === "bass_music"
            ? "bass music"
            : family === "trance"
              ? "trance"
              : "electronic";

  return {
    styleTerm,
    styleTokens,
    compactStyleTerm: styleTokens.slice(0, 2).join(" ") || styleLabelByValue(style),
    compactThreeTerm: styleTokens.slice(0, 3).join(" ") || styleLabelByValue(style),
    broadStyleToken: styleTokens[0] || styleLabelByValue(style),
    family,
    familyTerm
  };
}

function advancedStyleSearchTerms(style, limit = 6) {
  const parts = styleSearchParts(style);
  const terms = [
    ...(STYLE_ADVANCED_SEARCH_TERMS[style] || []),
    parts.styleTerm,
    parts.compactThreeTerm,
    parts.compactStyleTerm,
    `${parts.broadStyleToken} ${parts.familyTerm}`,
    styleLabelByValue(style),
    parts.familyTerm
  ];

  const seen = new Set();
  return terms
    .map((term) => String(term || "").replace(/\s+/g, " ").trim())
    .filter(Boolean)
    .filter((term) => {
      const key = normalize(term);
      if (!key || seen.has(key)) return false;
      seen.add(key);
      return true;
    })
    .slice(0, limit);
}

function hydrationSeedCapForStyle(style) {
  if (style === "psycore") return 72;
  if (style === "slambient" || DARK_UNDERGROUND_DISCOVERY_STYLES.has(style)) return 42;
  return STRICT_DYNAMIC_BPM_STYLES.has(style) ? 24 : 48;
}

function deezerArtistTopSeedCapForStyle(style) {
  if (style === "psycore") return 36;
  if (style === "slambient" || DARK_UNDERGROUND_DISCOVERY_STYLES.has(style)) return 22;
  return STRICT_DYNAMIC_BPM_STYLES.has(style) ? 14 : 28;
}

function soundCloudArtistSeedCapForStyle(style) {
  if (style === "psycore") return 18;
  if (style === "slambient" || DARK_UNDERGROUND_DISCOVERY_STYLES.has(style)) return 14;
  return STRICT_DYNAMIC_BPM_STYLES.has(style) ? 10 : 12;
}

async function fetchTracksByArtistAndStyle(artist, style) {
  const fastMode = STRICT_DYNAMIC_BPM_STYLES.has(style) && style !== "psycore";
  const parts = styleSearchParts(style);
  const searchTerms = advancedStyleSearchTerms(style, fastMode ? 3 : 5);
  const queries = Array.from(
    new Set(
      [
        ...searchTerms.map((term) => `artist:"${artist}" ${term}`),
        `artist:"${artist}"`,
        ...(fastMode ? [] : searchTerms.slice(0, 3).map((term) => `${artist} ${term} ${parts.familyTerm}`))
      ]
        .map((query) => query.replace(/\s+/g, " ").trim())
        .filter(Boolean)
    )
  );
  const collected = new Map();

  for (const rawQuery of queries) {
    for (const index of (fastMode ? [0, 25] : [0, 25, 50])) {
      try {
        const query = encodeURIComponent(rawQuery);
        const data = await deezerJsonp(`https://api.deezer.com/search?q=${query}&limit=25&index=${index}`);
        if (!data || !Array.isArray(data.data)) continue;
        data.data
          .filter((row) => row?.id && row?.title && row?.artist?.name)
          .filter((row) => isArtistMatch(row.artist.name, artist))
          .forEach((row) => collected.set(String(row.id), row));
      } catch (_err) {
        // ignora e tenta proxima consulta
      }
    }
  }

  return Array.from(collected.values()).slice(0, 28);
}

async function fetchDeezerTracksByStyle(style) {
  const fastMode = STRICT_DYNAMIC_BPM_STYLES.has(style) && style !== "psycore";
  const parts = styleSearchParts(style);
  const searchTerms = advancedStyleSearchTerms(style, fastMode ? 4 : 7);
  const queries = Array.from(
    new Set(
      [
        ...searchTerms.map((term) => `${term} ${parts.familyTerm}`),
        ...searchTerms.slice(0, fastMode ? 2 : 4).map((term) => `${term} electronic`),
        ...(parts.family === "psytrance" ? searchTerms.slice(0, 3).map((term) => `${term} psytrance`) : []),
        ...(parts.family === "techno" ? searchTerms.slice(0, 3).map((term) => `${term} techno`) : []),
        ...(parts.family === "house" ? searchTerms.slice(0, 3).map((term) => `${term} house`) : []),
        ...(parts.family === "dnb" ? searchTerms.slice(0, 3).map((term) => `${term} drum and bass`) : []),
        ...(fastMode ? [] : searchTerms.slice(0, 2).map((term) => `${term} official`))
      ]
        .map((query) => query.replace(/\s+/g, " ").trim())
        .filter(Boolean)
    )
  );
  const collected = new Map();

  for (const rawQuery of queries) {
    for (const index of (fastMode ? [0, 25] : [0, 25, 50])) {
      try {
        const query = encodeURIComponent(rawQuery);
        const data = await deezerJsonp(`https://api.deezer.com/search?q=${query}&limit=25&index=${index}`);
        if (!data || !Array.isArray(data.data)) continue;
        data.data
          .filter((row) => row?.id && row?.title && row?.artist?.name)
          .forEach((row) => collected.set(String(row.id), row));
      } catch (_err) {
        // ignora erro de lote e continua com outros
      }
    }
  }

  return Array.from(collected.values()).slice(0, 120);
}

async function fetchDeezerArtistTopTracks(artist, style) {
  const artistName = sanitizeArtistLookupName(artist);
  const cacheKey = `${style || "any"}::${normalize(artistName)}`;
  if (!artistName || !style) return [];
  if (deezerArtistTopTrackCache.has(cacheKey)) return deezerArtistTopTrackCache.get(cacheKey);

  try {
    const artistData = await deezerJsonp(`https://api.deezer.com/search/artist?q=${encodeURIComponent(artistName)}&limit=8`);
    const artistRows = Array.isArray(artistData?.data) ? artistData.data : [];
    const best = artistRows.find((row) => isArtistMatch(row?.name || "", artistName));
    const topUrl = String(best?.tracklist || (best?.id ? `https://api.deezer.com/artist/${best.id}/top?limit=50` : "")).trim();
    if (!topUrl) {
      deezerArtistTopTrackCache.set(cacheKey, []);
      return [];
    }

    let lookupUrl = topUrl.replace(/limit=\d+/i, "limit=50");
    if (!/limit=/i.test(lookupUrl)) lookupUrl += `${lookupUrl.includes("?") ? "&" : "?"}limit=50`;
    const topData = await deezerJsonp(lookupUrl);
    const rows = Array.isArray(topData?.data) ? topData.data : [];
    const collected = new Map();

    rows
      .filter((row) => row?.id && row?.title && row?.artist?.name)
      .filter((row) => isArtistMatch(row.artist.name, artistName))
      .filter(
        (row) =>
          !hasTrackStyleSignalConflict(style, {
            artist: row.artist.name,
            song: row.title,
            label: row.album?.title || "",
            artistGenre: [STYLE_SEARCH_TERMS[style], styleLabelByValue(style)].filter(Boolean).join(" "),
            artistProfileHint: row.album?.title || "",
            source: "deezer_artist_top"
          })
      )
      .forEach((row) => collected.set(String(row.id), row));

    const result = Array.from(collected.values()).slice(0, 40);
    deezerArtistTopTrackCache.set(cacheKey, result);
    return result;
  } catch (_err) {
    deezerArtistTopTrackCache.set(cacheKey, []);
    return [];
  }
}

function catalogTrackEntriesForArtist(artist, style = "", { eligibleOnly = false } = {}) {
  const artistName = String(artist || "").trim();
  if (!artistName) return [];
  return catalog.filter((track) => {
    if (!track?.artist || !track?.song) return false;
    if (style && track.style !== style) return false;
    if (!isArtistMatch(track.artist, artistName) && !isArtistMatch(artistName, track.artist)) return false;
    if (eligibleOnly && !isTrackEligibleForRecommendation(track)) return false;
    return true;
  });
}

function catalogTrackDepthForArtist(artist, style = "", options = {}) {
  const uniqueTitles = new Set();
  catalogTrackEntriesForArtist(artist, style, options).forEach((track) => {
    const title = normalizeTitle(track.song || "");
    if (title) uniqueTitles.add(title);
  });
  return uniqueTitles.size;
}

function catalogPlayableTrackDepthForArtist(artist, style = "", options = {}) {
  const uniqueTitles = new Set();
  catalogTrackEntriesForArtist(artist, style, options).forEach((track) => {
    if (!trackHasPlayablePreviewExperience(track)) return;
    const title = normalizeTitle(track.song || "");
    if (title) uniqueTitles.add(title);
  });
  return uniqueTitles.size;
}

function catalogPrimaryStyleForArtist(artist, preferredStyle = "") {
  if (preferredStyle && STYLE_BPM_RULES[preferredStyle]) return preferredStyle;
  const counts = new Map();
  catalogTrackEntriesForArtist(artist).forEach((track) => {
    const style = String(track.style || "").trim();
    if (!style || !STYLE_BPM_RULES[style]) return;
    counts.set(style, (counts.get(style) || 0) + 1);
  });
  return Array.from(counts.entries()).sort((a, b) => b[1] - a[1])[0]?.[0] || "";
}

function artistDepthCacheKey(artist, style = "") {
  return `${style || "any"}::${artistMatchKey(artist || "")}`;
}

function buildCatalogArtistDepthAudit({ style = "", minimum = MIN_TRACKS_PER_ARTIST } = {}) {
  const byArtist = new Map();
  catalog.forEach((track) => {
    if (!track?.artist || !track?.song) return;
    if (style && track.style !== style) return;
    if (!isTrackEligibleForRecommendation(track)) return;
    const key = artistMatchKey(track.artist);
    if (!key) return;
    const entry = byArtist.get(key) || {
      artist: track.artist,
      styles: new Set(),
      songs: new Set()
    };
    entry.styles.add(track.style);
    entry.songs.add(normalizeTitle(track.song));
    byArtist.set(key, entry);
  });

  const rows = Array.from(byArtist.values())
    .map((entry) => ({
      artist: entry.artist,
      count: entry.songs.size,
      playableCount: catalogPlayableTrackDepthForArtist(entry.artist, style, { eligibleOnly: false }),
      styles: Array.from(entry.styles)
    }))
    .sort((a, b) => a.count - b.count || a.playableCount - b.playableCount || a.artist.localeCompare(b.artist));

  return {
    artists: rows.length,
    belowMinimum: rows.filter((row) => row.count < minimum || row.playableCount < minimum).length,
    minimum,
    sample: rows.filter((row) => row.count < minimum || row.playableCount < minimum).slice(0, 40),
    rows
  };
}

function artistsNeedingCatalogDepth(style = "", { limit = ARTIST_CATALOG_DEPTH_STYLE_LIMIT, target = ARTIST_CATALOG_DEPTH_TARGET } = {}) {
  const byArtist = new Map();
  catalog.forEach((track) => {
    if (!track?.artist || !track?.song) return;
    if (style && track.style !== style) return;
    const artistKey = artistMatchKey(track.artist);
    if (!artistKey) return;
    const entry = byArtist.get(artistKey) || {
      artist: track.artist,
      style: track.style,
      songs: new Set(),
      previewTracks: 0,
      eligibleTracks: 0
    };
    entry.songs.add(normalizeTitle(track.song));
    if (trackHasPlayablePreviewExperience(track)) entry.previewTracks += 1;
    if (isTrackEligibleForRecommendation(track)) entry.eligibleTracks += 1;
    byArtist.set(artistKey, entry);
  });

  return Array.from(byArtist.values())
    .filter(
      (entry) =>
        entry.artist &&
        entry.style &&
        entry.songs.size > 0 &&
        (entry.songs.size < target || entry.previewTracks < MIN_TRACKS_PER_ARTIST)
    )
    .sort((a, b) => {
      const aNeed = target - a.songs.size;
      const bNeed = target - b.songs.size;
      return bNeed - aNeed || a.previewTracks - b.previewTracks || b.eligibleTracks - a.eligibleTracks;
    })
    .slice(0, Math.max(0, Number(limit) || 0));
}

async function addDeezerArtistDepthTrack(row, style, fallbackArtist, existingKeys) {
  if (!row || !style || !existingKeys) return false;
  const artist = String(row?.artist?.name || fallbackArtist || "").trim();
  const song = String(row?.title || row?.title_short || "").trim();
  const previewUrl = normalizePreviewUrl(row?.preview || "");
  if (!artist || !song || !previewUrl) return false;
  if (!isArtistMatch(artist, fallbackArtist) && !isArtistMatch(fallbackArtist, artist)) return false;
  if (isAwkwardArtistPreviewTitle(song) || isLikelyDjMixOrSetTitle(song)) return false;
  if (hasUnrequestedAlternateVersion("", song)) return false;

  const key = normalize(`${artist}::${song}`);
  const existingTrack = catalog.find((track) => recommendationTrackKey(track) === key);
  if (existingTrack) {
    promotePreviewCandidate(existingTrack, previewUrl);
    existingTrack.previewChecked = true;
    existingTrack.previewMissing = false;
    existingTrack.previewLookupAttempted = true;
    existingTrack.previewSource = existingTrack.previewSource || "deezer_artist_depth";
    existingTrack.existenceVerified = true;
    return true;
  }

  const details = row.id ? await fetchDeezerTrackDetails(row.id) : null;
  const inserted = addDynamicTrackToCatalog(
    {
      style,
      song,
      artist,
      label: details?.label || row?.album?.title || "Deezer",
      bpmExact: Number(details?.bpm) || 0,
      previewUrl: details?.preview || previewUrl,
      releaseDate: details?.release_date || "Deezer",
      durationSec: Number(details?.duration) || Number(row?.duration) || 0,
      artistGenre: [STYLE_SEARCH_TERMS[style], styleLabelByValue(style)].filter(Boolean).join(" • "),
      artistProfileHint: row?.album?.title || "Expansão automática de repertório do artista com preview tocável.",
      source: "verified_deezer_expansion_artist_depth"
    },
    existingKeys
  );

  if (!inserted) return false;
  const insertedTrack = catalog.find((track) => recommendationTrackKey(track) === normalize(`${artist}::${song}`));
  if (insertedTrack) {
    insertedTrack.deezerTrackId = row.id || details?.id || "";
    if (row?.artist?.picture_xl || row?.artist?.picture_big || row?.artist?.picture_medium) {
      insertedTrack.artistImageUrl = row.artist.picture_xl || row.artist.picture_big || row.artist.picture_medium;
      insertedTrack.artistImageSource = "Deezer";
    }
  }
  return true;
}

async function expandCatalogForArtistDepth(artist, style = "", options = {}) {
  const artistName = sanitizeArtistLookupName(artist);
  const resolvedStyle = catalogPrimaryStyleForArtist(artistName, style);
  if (!artistName || !resolvedStyle) return { added: 0, depth: 0, skipped: true };

  const target = Math.max(MIN_TRACKS_PER_ARTIST, Number(options.target) || ARTIST_CATALOG_DEPTH_TARGET);
  const force = Boolean(options.force);
  const cacheKey = artistDepthCacheKey(artistName, resolvedStyle);
  const currentDepth = catalogTrackDepthForArtist(artistName, resolvedStyle, { eligibleOnly: false });
  const currentPlayableDepth = catalogPlayableTrackDepthForArtist(artistName, resolvedStyle, { eligibleOnly: false });
  if (!force && currentDepth >= target && currentPlayableDepth >= MIN_TRACKS_PER_ARTIST) {
    return { added: 0, depth: currentDepth, playableDepth: currentPlayableDepth, ok: true };
  }
  if (!externalCatalogHydrationAllowed()) return { added: 0, depth: currentDepth, skipped: true };

  const cached = artistCatalogDepthCache.get(cacheKey);
  if (!force && cached && Date.now() - cached.at < 20 * 60 * 1000 && currentDepth >= MIN_TRACKS_PER_ARTIST && currentPlayableDepth >= MIN_TRACKS_PER_ARTIST) {
    return { added: 0, depth: currentDepth, playableDepth: currentPlayableDepth, ok: true, cached: true };
  }
  if (artistCatalogDepthInFlight.has(cacheKey)) return artistCatalogDepthInFlight.get(cacheKey);

  const task = (async () => {
    const existingKeys = new Set(catalog.map((track) => recommendationTrackKey(track)).filter(Boolean));
    const rowMap = new Map();
    const addRow = (row) => {
      if (!row?.title || !row?.artist?.name) return;
      const key = String(row.id || `${row.artist.name}::${row.title}`);
      if (!key || rowMap.has(key)) return;
      rowMap.set(key, row);
    };

    try {
      const previewRows = await fetchDeezerPreviewOptionsByArtist(artistName, resolvedStyle);
      previewRows.forEach(addRow);
    } catch (_err) {
      // segue para top tracks
    }

    if (rowMap.size < target) {
      try {
        const topRows = await fetchDeezerArtistTopTracks(artistName, resolvedStyle);
        topRows.filter((row) => normalizePreviewUrl(row?.preview || "")).forEach(addRow);
      } catch (_err) {
        // SoundCloud abaixo cobre artistas que nao vierem do Deezer
      }
    }

    let added = 0;
    for (const row of Array.from(rowMap.values()).slice(0, ARTIST_CATALOG_DEPTH_BATCH_LIMIT)) {
      const depthNow = catalogTrackDepthForArtist(artistName, resolvedStyle, { eligibleOnly: false });
      const playableDepthNow = catalogPlayableTrackDepthForArtist(artistName, resolvedStyle, { eligibleOnly: false });
      if (depthNow >= target && playableDepthNow >= MIN_TRACKS_PER_ARTIST) break;
      if (await addDeezerArtistDepthTrack(row, resolvedStyle, artistName, existingKeys)) {
        added += 1;
      }
    }

    let depth = catalogTrackDepthForArtist(artistName, resolvedStyle, { eligibleOnly: false });
    let playableDepth = catalogPlayableTrackDepthForArtist(artistName, resolvedStyle, { eligibleOnly: false });
    if (depth < MIN_TRACKS_PER_ARTIST || playableDepth < MIN_TRACKS_PER_ARTIST) {
      try {
        const rows = await fetchSoundCloudTracksByStyle(resolvedStyle, artistName);
        for (const row of rows.slice(0, ARTIST_CATALOG_DEPTH_BATCH_LIMIT)) {
          if (depth >= target && playableDepth >= MIN_TRACKS_PER_ARTIST) break;
          if (addSoundCloudApiTrackToCatalog(row, resolvedStyle, existingKeys)) {
            added += 1;
            depth = catalogTrackDepthForArtist(artistName, resolvedStyle, { eligibleOnly: false });
            playableDepth = catalogPlayableTrackDepthForArtist(artistName, resolvedStyle, { eligibleOnly: false });
          }
        }
      } catch (_err) {
        // fonte complementar opcional
      }
    }

    depth = catalogTrackDepthForArtist(artistName, resolvedStyle, { eligibleOnly: false });
    playableDepth = catalogPlayableTrackDepthForArtist(artistName, resolvedStyle, { eligibleOnly: false });
    artistCatalogDepthCache.set(cacheKey, {
      at: Date.now(),
      added,
      depth,
      playableDepth
    });
    if (added > 0) {
      dedupeCatalogByTrackKey();
      saveDynamicCatalogCache();
    }
    return { added, depth, playableDepth, ok: depth >= MIN_TRACKS_PER_ARTIST && playableDepth >= MIN_TRACKS_PER_ARTIST };
  })();

  artistCatalogDepthInFlight.set(cacheKey, task);
  try {
    return await task;
  } finally {
    artistCatalogDepthInFlight.delete(cacheKey);
  }
}

async function ensureCatalogArtistDepthForStyle(style, options = {}) {
  const styleKey = String(style || "").trim();
  if (!styleKey) return { added: 0, checked: 0 };
  const limit = Math.max(1, Number(options.limit) || ARTIST_CATALOG_DEPTH_STYLE_LIMIT);
  const target = Math.max(MIN_TRACKS_PER_ARTIST, Number(options.target) || ARTIST_CATALOG_DEPTH_TARGET);
  const artists = artistsNeedingCatalogDepth(styleKey, { limit, target });
  let added = 0;
  let checked = 0;
  for (const entry of artists) {
    checked += 1;
    const result = await expandCatalogForArtistDepth(entry.artist, styleKey, { target });
    added += Number(result?.added) || 0;
  }
  return { added, checked };
}

async function fetchItunesTracksByStyle(style, artist = "") {
  const parts = styleSearchParts(style);
  const searchTerms = advancedStyleSearchTerms(style, artist ? 3 : 5);
  const rawTerms = Array.from(
    new Set(
      (artist
        ? searchTerms.map((term) => `${artist} ${term}`)
        : searchTerms.map((term) => `${term} ${parts.familyTerm}`))
        .map((term) => term.replace(/\s+/g, " ").trim())
        .filter(Boolean)
    )
  );
  const collected = new Map();
  const fastMode = STRICT_DYNAMIC_BPM_STYLES.has(style) && style !== "psycore";
  const offsets = artist
    ? (fastMode ? [0, 60] : [0, 60, 120])
    : (fastMode ? [0, 60] : [0, 60, 120]);

  for (const rawTerm of rawTerms) {
    const term = encodeURIComponent(rawTerm);
    for (const offset of offsets) {
      try {
        const data = await itunesJsonp(`https://itunes.apple.com/search?term=${term}&entity=song&limit=60&offset=${offset}`);
        const rows = data?.results || [];
        rows
          .filter((row) => row?.trackName && row?.artistName)
          .filter((row) => !artist || isArtistMatch(row.artistName, artist))
          .filter(
            (row) =>
              !hasTrackStyleSignalConflict(style, {
                artist: row.artistName,
                song: row.trackName,
                label: row.collectionName || "",
                artistGenre: row.primaryGenreName || "",
                source: artist ? "itunes_artist_style" : "itunes_style"
              })
          )
          .forEach((row) => collected.set(String(row.trackId || `${row.artistName}::${row.trackName}`), row));
      } catch (_err) {
        // segue fluxo com outros lotes/fontes
      }
    }
  }

  return Array.from(collected.values()).slice(0, 100);
}

async function fetchItunesTracksByArtist(artist, style = "") {
  const artistName = String(artist || "").trim();
  if (!artistName) return [];
  const term = encodeURIComponent(artistName);
  const fastMode = STRICT_DYNAMIC_BPM_STYLES.has(style) && style !== "psycore";
  const offsets = fastMode ? [0, 60] : [0, 60, 120];
  const collected = new Map();

  for (const offset of offsets) {
    try {
      const data = await itunesJsonp(`https://itunes.apple.com/search?term=${term}&entity=song&limit=60&offset=${offset}`);
      const rows = data?.results || [];
      rows
        .filter((row) => row?.trackName && row?.artistName)
        .filter((row) => isArtistMatch(row.artistName, artistName))
        .filter(
          (row) =>
            !style ||
            !hasTrackStyleSignalConflict(style, {
              artist: row.artistName,
              song: row.trackName,
              label: row.collectionName || "",
              artistGenre: row.primaryGenreName || "",
              source: "itunes_artist"
            })
        )
        .forEach((row) => collected.set(String(row.trackId || `${row.artistName}::${row.trackName}`), row));
    } catch (_err) {
      // ignora lote com falha e continua
    }
  }

  return Array.from(collected.values()).slice(0, 80);
}

function resolveMusicApiEndpoint(globalName, fallbackPath) {
  const configured = String(window?.[globalName] || "").trim();
  if (configured) return configured;
  return canUseRelativeApiEndpoint() ? fallbackPath : "";
}

function soundCloudApiQueryTerms(style, artist = "", track = null) {
  const parts = styleSearchParts(style);
  const searchTerms = advancedStyleSearchTerms(style, artist ? 4 : 6);
  const artistName = String(artist || "").trim();
  const songName = String(track?.song || track?.title || "").trim();
  const labelName = sanitizeLabel(String(track?.label || "").trim(), artistName, songName);
  const styleTerm = String(STYLE_SEARCH_TERMS[style] || styleLabelByValue(style) || "").trim();

  if (artistName && songName) {
    const exactQueries = [
      `"${artistName}" "${songName}"`,
      `${artistName} ${songName}`,
      `"${songName}" "${artistName}"`,
      [artistName, songName, labelName && !/catalog|catálogo|curated|dinâmico|dinamico/i.test(labelName) ? labelName : ""].filter(Boolean).join(" "),
      [artistName, songName, styleTerm].filter(Boolean).join(" "),
      [songName, artistName, parts.familyTerm].filter(Boolean).join(" ")
    ];
    return Array.from(
      new Set(
        exactQueries
          .map((query) => query.replace(/\s+/g, " ").trim())
          .filter(Boolean)
      )
    ).slice(0, 6);
  }

  const queries = artistName
    ? searchTerms.map((term) => `${artistName} ${term}`)
    : [
        ...searchTerms,
        ...searchTerms.slice(0, 3).map((term) => `${term} ${parts.familyTerm}`)
      ];

  return Array.from(
    new Set(
      queries
        .map((query) => query.replace(/\s+/g, " ").trim())
        .filter(Boolean)
    )
  ).slice(0, artistName ? 3 : 5);
}

function soundCloudRowHasTrackArtistSignal(row, artist = "", song = "") {
  const safeArtist = String(artist || "").trim();
  if (!safeArtist) return true;
  if (isArtistMatch(row?.artist || "", safeArtist)) return true;

  const searchable = [
    row?.song,
    row?.title,
    row?.description,
    row?.tags,
    row?.genre
  ].filter(Boolean).join(" ");
  const normalizedArtist = normalize(safeArtist);
  const normalizedSearchable = normalize(searchable);
  if (normalizedArtist && normalizedSearchable.includes(normalizedArtist)) return true;
  const compactArtist = normalizedArtist.replace(/\s+/g, "");
  const compactSearchable = normalizedSearchable.replace(/\s+/g, "");
  if (compactArtist && compactSearchable.includes(compactArtist)) return true;

  const songTitle = String(song || "").trim();
  if (!songTitle) return false;
  return strictTitleMatch(songTitle, row?.song || row?.title || "") && titleConfidence(songTitle, row?.song || row?.title || "") >= 0.92;
}

async function fetchSoundCloudTracksByStyle(style, artist = "", options = {}) {
  const endpoint = resolveMusicApiEndpoint("SONIC_SOUNDCLOUD_SEARCH_API_URL", "/api/soundcloud-search");
  if (!endpoint || !style) return [];

  const track = options?.track || null;
  const trackKey = track?.song ? normalize(`${track.artist || artist}::${track.song}`) : "";
  const cacheKey = `${style}::${normalize(artist || "generic")}::${trackKey || "style"}`;
  if (!options?.force && soundCloudApiCache.has(cacheKey)) return soundCloudApiCache.get(cacheKey);

  const collected = new Map();
  const queries = soundCloudApiQueryTerms(style, artist, track);
  for (const query of queries) {
    try {
      const response = await fetch(endpoint, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Accept: "application/json"
        },
        body: JSON.stringify({
          style,
          query,
          limit: track ? 20 : artist ? 16 : 32,
          resolvePreview: true,
          previewResolveLimit: track ? 20 : artist ? 16 : 12
        })
      });
      if (!response.ok) break;
      const payload = await response.json();
      const rows = Array.isArray(payload?.tracks) ? payload.tracks : [];
      rows
        .filter((row) => row?.song && row?.artist && row?.soundcloudTrackUrl)
        .filter((row) => !artist || (track ? soundCloudRowHasTrackArtistSignal(row, artist, track.song) : isArtistMatch(row.artist, artist)))
        .filter(
          (row) =>
            !hasTrackStyleSignalConflict(style, {
              artist: track?.artist || row.artist,
              song: row.song,
              label: row.label || "SoundCloud",
              artistGenre: [row.genre, row.tags, STYLE_SEARCH_TERMS[style], styleLabelByValue(style)]
                .filter(Boolean)
                .join(" "),
              artistProfileHint: row.description || "",
              source: "soundcloud_api"
            })
        )
        .forEach((row) => collected.set(String(row.soundcloudTrackUrl), row));
    } catch (_err) {
      // SoundCloud e uma fonte complementar; se falhar, o app segue com catalogo local/Deezer/iTunes.
      break;
    }
  }

  const tracks = Array.from(collected.values()).slice(0, track ? 24 : artist ? 16 : 60);
  soundCloudApiCache.set(cacheKey, tracks);
  return tracks;
}

function addDynamicTrackToCatalog({
  style,
  song,
  artist,
  label = "Catálogo dinâmico",
  bpmExact = 0,
  previewUrl = "",
  releaseDate = "Catálogo dinâmico",
  durationSec = 0,
  source = "dynamic",
  artistCountry = "",
  artistGenre = "",
  artistProfileHint = "",
  artistBio = "",
  labelBio = "",
  bandcampUrl = "",
  bandcampTrackUrl = "",
  bandcampTrackId = "",
  soundcloudUrl = "",
  soundcloudTrackUrl = "",
  spotifyUrl = "",
  spotifyTrackUrl = "",
  youtubeUrl = "",
  youtubeTrackUrl = "",
  catalogMetadata = null,
  sourceTags = [],
  albumKeywords = [],
  energyBand = "",
  catalogRole = "",
  coverArtUrl = "",
  labelLinks = [],
  socialDiscoveryLinks = [],
  sourceNote = "",
  catalogConfidence = ""
}, existingKeys) {
  const artistName = (artist || "").trim();
  const songName = (song || "").trim();
  if (!artistName || !songName) return false;
  const curatedInput = applyCuratedTrackMetadata({
    artist: artistName,
    song: songName,
    label,
    artistGenre,
    artistProfileHint
  });
  label = curatedInput.label || label;
  artistGenre = curatedInput.artistGenre || artistGenre;
  artistProfileHint = curatedInput.artistProfileHint || artistProfileHint;
  if (trackBlockedForStyle(style, { artist: artistName, song: songName })) return false;
  if (hasTrackStyleSignalConflict(style, {
    artist: artistName,
    song: songName,
    label,
    artistGenre: artistGenre || "",
    artistProfileHint,
    vibe: [artistBio, labelBio].filter(Boolean).join(" "),
    source
  })) return false;
  if (isLikelyChannelStyleArtistName(artistName)) return false;
  if (isLikelyGeneratedTrackTitle(songName)) return false;
  if (!artistAllowedForStyle(style, artistName)) return false;
  if (isDynamicSource(source) && requiresSeedAnchorForDynamicStyle(style) && !artistSeedAnchoredForStyle(style, artistName)) return false;

  const rawLabel = String(label || "").trim();
  const labelLooksGenreDescriptor = isLikelyGenreDescriptorEntity(rawLabel);
  if (isDynamicSource(source) && familyOf(style) === "psytrance" && labelLooksGenreDescriptor) return false;

  const cleanLabel = sanitizeLabel(rawLabel, artistName, songName);
  if (!labelAllowedForStyle(style, cleanLabel)) return false;

  const key = normalize(`${artistName}::${songName}`);
  if (existingKeys.has(key)) return false;

  const bpmNumber = Number(bpmExact) || 0;
  if (requiresExactBpmForDynamic(style, source) && !bpmNumber) return false;
  if (bpmNumber && !bpmFitsStyle(style, bpmNumber)) return false;
  const fineStyleNeedsVerifiedTrack = dynamicFineStyleNeedsVerifiedTrack(style, source);
  if (fineStyleNeedsVerifiedTrack && !bpmNumber) return false;

  const fallbackBpm = Math.round((STYLE_BPM_RULES[style]?.min + STYLE_BPM_RULES[style]?.max || 130) / 2);
  const duration = Number(durationSec) || 0;
  const normalizedPreview = normalizePreviewUrl(previewUrl);
  const safeSpotifyUrl = String(spotifyUrl || "").trim();
  const safeSpotifyTrackUrl = String(spotifyTrackUrl || "").trim();
  const safeYoutubeUrl = String(youtubeUrl || "").trim();
  const safeYoutubeTrackUrl = String(youtubeTrackUrl || "").trim();
  const safeSoundcloudUrl = String(soundcloudUrl || "").trim();
  const safeSoundcloudTrackUrl = String(soundcloudTrackUrl || "").trim();
  const safeBandcampUrl = String(bandcampUrl || "").trim();
  const safeBandcampTrackUrl = String(bandcampTrackUrl || "").trim();
  const safeBandcampTrackId = String(bandcampTrackId || "").trim();
  const safeCatalogMetadata = catalogMetadata && typeof catalogMetadata === "object" && !Array.isArray(catalogMetadata)
    ? catalogMetadata
    : {};
  const hasDirectYoutube = isDirectYouTubeUrl(safeYoutubeTrackUrl) || isDirectYouTubeUrl(safeYoutubeUrl);
  const hasDirectSoundcloud = isDirectSoundCloudTrackUrl(safeSoundcloudTrackUrl) || isDirectSoundCloudTrackUrl(safeSoundcloudUrl);
  const hasBandcampPreview = Boolean(safeBandcampTrackId || safeBandcampTrackUrl || safeBandcampUrl);
  const hasPlayableFallback = Boolean(hasDirectYoutube || hasDirectSoundcloud || hasBandcampPreview);
  if (isLikelyCompilationEntry({ song: songName, artist: artistName, label: cleanLabel, durationSec: duration })) return false;
  const durationText = duration > 0
    ? `${String(Math.floor(duration / 60)).padStart(2, "0")}:${String(duration % 60).padStart(2, "0")}`
    : "06:00";

  const hydratedTrack = {
    style,
    song: songName,
    artist: artistName,
    label: cleanLabel,
    bpm: mapBpmToRange(bpmNumber || fallbackBpm),
    bpmExact: bpmNumber || undefined,
    energy: energyFromBpm(bpmNumber || fallbackBpm),
    vocals: "instrumental",
    context: ["peak", "treino", "estrada", "after", "foco", "trabalho", "warmup"],
    vibe: `Garimpei esta faixa porque ela conversa bem com ${styleLabelByValue(style)} e pode abrir um caminho novo no seu gosto.`,
    spotifyUrl: safeSpotifyUrl || `https://open.spotify.com/search/${encodeURIComponent(`track:"${songName}" artist:"${artistName}"`)}`,
    spotifyTrackUrl: safeSpotifyTrackUrl,
    youtubeUrl: safeYoutubeUrl || `https://www.youtube.com/results?search_query=${encodeURIComponent(`${artistName} ${songName}`)}`,
    soundcloudUrl: safeSoundcloudUrl,
    soundcloudTrackUrl: safeSoundcloudTrackUrl || (safeSoundcloudUrl ? "" : `https://soundcloud.com/search?q=${encodeURIComponent(`"${artistName}" "${songName}"`)}`),
    bandcampUrl: safeBandcampUrl,
    bandcampTrackUrl: safeBandcampTrackUrl,
    bandcampTrackId: safeBandcampTrackId,
    beatportUrl: `https://www.beatport.com/search?q=${encodeURIComponent(`${artistName} ${songName}`)}`,
    youtubeTrackUrl: safeYoutubeTrackUrl || `https://www.youtube.com/results?search_query=${encodeURIComponent(`"${songName}" "${artistName}"`)}`,
    previewUrl: normalizedPreview,
    previewCandidates: normalizedPreview ? [normalizedPreview] : [],
    spotifyVerified: Boolean(safeSpotifyTrackUrl),
    youtubeVerified: hasDirectYoutube,
    soundcloudVerified: hasDirectSoundcloud,
    bandcampVerified: hasBandcampPreview,
    existenceVerified: (normalizedPreview || hasPlayableFallback) ? true : undefined,
    previewChecked: Boolean(normalizedPreview),
    previewMissing: !normalizedPreview && !hasPlayableFallback,
    artistCountry: String(artistCountry || "").trim(),
    artistGenre: String(artistGenre || "").trim(),
    artistProfileHint: String(artistProfileHint || "").trim(),
    artistBio: String(artistBio || "").trim() || `${artistName} entrou no radar como uma pista nova dentro de ${styleLabelByValue(style)}. Use esta faixa como porta de entrada e, se bater, vale ouvir mais do projeto.`,
    labelBio: String(labelBio || "").trim() || buildDynamicLabelSummary(style, cleanLabel),
    catalogMetadata: safeCatalogMetadata,
    sourceTags: Array.isArray(sourceTags) ? sourceTags.map((item) => String(item || "").trim()).filter(Boolean) : [],
    albumKeywords: Array.isArray(albumKeywords) ? albumKeywords.map((item) => String(item || "").trim()).filter(Boolean) : [],
    energyBand: String(energyBand || safeCatalogMetadata.energy_band || "").trim(),
    catalogRole: String(catalogRole || safeCatalogMetadata.catalog_role || "").trim(),
    coverArtUrl: String(coverArtUrl || safeCatalogMetadata.cover_art_url || "").trim(),
    labelLinks: Array.isArray(labelLinks) ? labelLinks.map((item) => String(item || "").trim()).filter(Boolean) : [],
    socialDiscoveryLinks: Array.isArray(socialDiscoveryLinks) ? socialDiscoveryLinks.map((item) => String(item || "").trim()).filter(Boolean) : [],
    sourceNote: String(sourceNote || safeCatalogMetadata.source_note || "").trim(),
    catalogConfidence: String(catalogConfidence || safeCatalogMetadata.confidence || "").trim(),
    source
  };

  catalog.push(hydratedTrack);
  existingKeys.add(key);
  TRACK_METADATA[`${songName}|${artistName}`] = {
    releaseDate,
    duration: durationText,
    musicalKey: "N/A",
    catalogRef: `${source.toUpperCase().slice(0, 4)}-${style.toUpperCase().slice(0, 5)}`
  };

  return true;
}

function injectLocalTrackSeedBoost() {
  const existingKeys = new Set(catalog.map((track) => recommendationTrackKey(track)));
  let added = 0;
  LOCAL_TRACK_SEED_BOOST.forEach((seed) => {
    const releaseDate = normalizeDatasetReleaseDate(seed.releaseDate || "Catálogo local");
    const inserted = addDynamicTrackToCatalog(
      {
        style: seed.style,
        song: seed.song,
        artist: seed.artist,
        label: seed.label || "Catálogo curado",
        bpmExact: Number(seed.bpmExact) || 0,
        previewUrl: "",
        releaseDate,
        durationSec: Number(seed.durationSec) || 0,
        source: "dataset_local_seed_boost",
        artistCountry: String(seed.artistCountry || "").trim(),
        artistGenre: String(seed.artistGenre || "").trim(),
        artistProfileHint: String(seed.artistProfileHint || "").trim() || "Seed local curado para ampliar cobertura e rotação de artistas.",
        artistBio: String(seed.artistBio || "").trim(),
        labelBio: String(seed.labelBio || "").trim(),
        bandcampUrl: String(seed.bandcampUrl || "").trim(),
        bandcampTrackUrl: String(seed.bandcampTrackUrl || "").trim(),
        bandcampTrackId: String(seed.bandcampTrackId || "").trim(),
        soundcloudTrackUrl: String(seed.soundcloudTrackUrl || "").trim()
      },
      existingKeys
    );
    if (inserted) {
      added += 1;
      const insertedTrack = catalog.find((track) => recommendationTrackKey(track) === normalize(`${seed.artist}::${seed.song}`));
      if (insertedTrack && seed.spotifyUrl) insertedTrack.spotifyUrl = String(seed.spotifyUrl).trim();
      if (insertedTrack && seed.bandcampUrl) insertedTrack.bandcampUrl = String(seed.bandcampUrl).trim();
      if (insertedTrack && seed.bandcampTrackUrl) insertedTrack.bandcampTrackUrl = String(seed.bandcampTrackUrl).trim();
      if (insertedTrack && seed.bandcampTrackId) insertedTrack.bandcampTrackId = String(seed.bandcampTrackId).trim();
      if (insertedTrack && seed.soundcloudTrackUrl) insertedTrack.soundcloudTrackUrl = String(seed.soundcloudTrackUrl).trim();
      if (releaseDate && releaseDate !== "Catálogo dinâmico" && releaseDate !== "Catálogo local") {
        registerRecentArtistSignal(seed.style, seed.artist, releaseDate, "local_seed_boost");
      }
    }
  });
  return added;
}

function injectSoundCloudSupplementalSeeds() {
  const existingKeys = new Set(catalog.map((track) => recommendationTrackKey(track)));
  let added = 0;
  SOUNDCLOUD_SUPPLEMENTAL_DJ_SEEDS.forEach((seed) => {
    const inserted = addDynamicTrackToCatalog(
      {
        style: seed.style,
        song: seed.song,
        artist: seed.artist,
        label: seed.label || "SoundCloud supplement",
        bpmExact: Number(seed.bpmExact) || 0,
        previewUrl: "",
        releaseDate: seed.releaseDate || "SoundCloud supplement",
        durationSec: Number(seed.durationSec) || 0,
        source: "soundcloud_label_supplement",
        artistCountry: String(seed.artistCountry || "").trim(),
        artistGenre: String(seed.artistGenre || "").trim(),
        artistProfileHint: String(seed.artistProfileHint || seed.artistBio || "").trim(),
        artistBio: String(seed.artistBio || "").trim(),
        labelBio: String(seed.labelBio || "").trim(),
        soundcloudTrackUrl: String(seed.soundcloudTrackUrl || "").trim(),
        bandcampUrl: String(seed.bandcampUrl || "").trim(),
        bandcampTrackUrl: String(seed.bandcampTrackUrl || "").trim()
      },
      existingKeys
    );
    if (!inserted) return;
    added += 1;
    if (seed.releaseDate) registerRecentArtistSignal(seed.style, seed.artist, seed.releaseDate, "soundcloud_label_supplement");
  });
  return added;
}

function addSoundCloudApiTrackToCatalog(row, style, existingKeys) {
  if (!row || !style) return false;
  return addDynamicTrackToCatalog({
    style,
    song: row.song,
    artist: row.artist,
    label: row.label || row.genre || "SoundCloud",
    bpmExact: Number(row.bpmExact) || 0,
    previewUrl: row.previewUrl || row.preview || "",
    releaseDate: row.releaseDate || "SoundCloud",
    durationSec: Number(row.durationSec) || 0,
    artistCountry: "",
    artistGenre: [row.genre, row.tags, STYLE_SEARCH_TERMS[style], styleLabelByValue(style)]
      .filter(Boolean)
      .join(" • "),
    artistProfileHint: row.description || row.tags || row.genre || "Faixa localizada via SoundCloud API.",
    artistBio: row.description || "",
    labelBio: row.label ? `${row.label} apareceu como sinal de origem nesta busca do SoundCloud.` : "",
    soundcloudTrackUrl: row.soundcloudTrackUrl,
    source: "soundcloud_api"
  }, existingKeys);
}

async function hydrateCatalogForStyle(style) {
  if (!style) return;
  purgeDynamicMismatches(style);
  const knowledgeArtists = collectStyleKnowledgeArtists(style);
  const seeds = knowledgeArtists.length ? knowledgeArtists : (STYLE_ARTIST_SEEDS[style] || []);
  if (!seeds.length) return;

  const targetSize = targetCatalogSizeForStyle(style);
  const coverageTarget = styleCoverageTarget(style);
  const currentStats = styleCoverageStats(style);
  if (
    currentStats.tracks >= Math.max(targetSize, coverageTarget.tracks) &&
    styleCoverageArtistSignal(currentStats) >= coverageTarget.artists &&
    currentStats.labels >= coverageTarget.labels
  ) return;
  if (!externalCatalogHydrationAllowed()) {
    dynamicCatalogByStyle.set(style, Date.now());
    saveDynamicCatalogCache();
    return;
  }

  const existingKeys = new Set(catalog.map((t) => normalize(`${t.artist}::${t.song}`)));
  const seedCap = hydrationSeedCapForStyle(style);
  const skipBroadStyleHydration = NO_BROAD_STYLE_HYDRATION_STYLES.has(style);
  const allowArtistItunesHydration = !requiresExactBpmForDynamic(style, "itunes_artist_style");
  const allowBroadItunesHydration = !requiresExactBpmForDynamic(style, "itunes_style");
  const selectedSeeds = selectHydrationArtists(style, seeds, Math.min(seedCap, seeds.length));

  for (const artist of selectedSeeds) {
    const results = await fetchTracksByArtistAndStyle(artist, style);
    for (const row of results) {
      const details = await fetchDeezerTrackDetails(row.id);
      addDynamicTrackToCatalog({
        style,
        song: row.title,
        artist: row.artist.name,
        label: details?.label || row.album?.title || "Catálogo dinâmico",
        bpmExact: Number(details?.bpm) || 0,
        previewUrl: row.preview || details?.preview || "",
        releaseDate: details?.release_date || "Catálogo dinâmico",
        durationSec: Number(details?.duration) || Number(row.duration) || 0,
        artistProfileHint: row.album?.title || "",
        source: "deezer_artist_style"
      }, existingKeys);

      const stats = stylePoolStats(style);
      if (stats.trackCount >= targetSize) break;
    }

    const stats = stylePoolStats(style);
    if (stats.trackCount >= targetSize) break;
  }

  let stats = stylePoolStats(style);
  const hasLocalArtistDepth = () => styleLocalArtistKnowledgeCount(style) >= coverageTarget.artists;

  // Deezer por perfil de artista: busca o repertorio do seed direto, sem depender do termo de genero.
  if (
    stats.trackCount < targetSize ||
    (!hasLocalArtistDepth() && stats.artistCount < coverageTarget.artists) ||
    stats.labels < coverageTarget.labels
  ) {
    for (const artist of selectedSeeds.slice(0, deezerArtistTopSeedCapForStyle(style))) {
      const rows = await fetchDeezerArtistTopTracks(artist, style);
      for (const row of rows) {
        const details = await fetchDeezerTrackDetails(row.id);
        addDynamicTrackToCatalog({
          style,
          song: row.title,
          artist: row.artist?.name || artist,
          label: details?.label || row.album?.title || "Catálogo dinâmico",
          bpmExact: Number(details?.bpm) || 0,
          previewUrl: row.preview || details?.preview || "",
          releaseDate: details?.release_date || "Catálogo dinâmico",
          durationSec: Number(details?.duration) || Number(row.duration) || 0,
          artistProfileHint: row.album?.title || "",
          source: "deezer_artist_top"
        }, existingKeys);

        stats = stylePoolStats(style);
        if (stats.trackCount >= targetSize && (stats.artistCount >= coverageTarget.artists || hasLocalArtistDepth())) break;
      }
      if (stats.trackCount >= targetSize && (stats.artistCount >= coverageTarget.artists || hasLocalArtistDepth())) break;
    }
  }

  // SoundCloud API: fonte server-side para previews/links reais e cena underground.
  // Usamos poucos artistas-semente para ganhar variedade sem gastar chamadas demais.
  if (
    stats.trackCount < Math.max(MIN_TRACKS_PER_STYLE, coverageTarget.tracks) ||
    (!hasLocalArtistDepth() && stats.artistCount < coverageTarget.artists) ||
    stats.labels < coverageTarget.labels
  ) {
    for (const artist of selectedSeeds.slice(0, soundCloudArtistSeedCapForStyle(style))) {
      const rows = await fetchSoundCloudTracksByStyle(style, artist);
      for (const row of rows) {
        addSoundCloudApiTrackToCatalog(row, style, existingKeys);
        stats = stylePoolStats(style);
        if (stats.trackCount >= targetSize && (stats.artistCount >= coverageTarget.artists || hasLocalArtistDepth())) break;
      }
      if (stats.trackCount >= targetSize && (stats.artistCount >= coverageTarget.artists || hasLocalArtistDepth())) break;
    }
  }

  // Segunda fonte: iTunes Search para estilos que aceitam preview sem BPM exato.
  if (allowArtistItunesHydration) {
    for (const artist of selectedSeeds) {
      const rows = await fetchItunesTracksByStyle(style, artist);
      for (const row of rows) {
        addDynamicTrackToCatalog({
          style,
          song: row.trackName,
          artist: row.artistName,
          label: row.collectionName || row.artistName || "Catálogo dinâmico",
          bpmExact: 0,
          previewUrl: row.previewUrl || "",
          releaseDate: row.releaseDate ? String(row.releaseDate).slice(0, 10) : "Catálogo dinâmico",
          durationSec: Math.round((Number(row.trackTimeMillis) || 0) / 1000),
          artistCountry: "",
          artistGenre: row.primaryGenreName || "",
          artistProfileHint: row.collectionName || "",
          source: "itunes_artist_style"
        }, existingKeys);

        const stats = stylePoolStats(style);
        if (stats.trackCount >= targetSize) break;
      }
      const stats = stylePoolStats(style);
      if (stats.trackCount >= targetSize) break;
    }
  }

  stats = stylePoolStats(style);

  // Fallback por artista puro: usa base local de artistas quando o termo de estilo falha.
  if (allowArtistItunesHydration && stats.trackCount < targetSize) {
    for (const artist of selectedSeeds) {
      const rows = await fetchItunesTracksByArtist(artist, style);
      for (const row of rows) {
        addDynamicTrackToCatalog({
          style,
          song: row.trackName,
          artist: row.artistName,
          label: row.collectionName || row.artistName || "Catálogo dinâmico",
          bpmExact: 0,
          previewUrl: row.previewUrl || "",
          releaseDate: row.releaseDate ? String(row.releaseDate).slice(0, 10) : "Catálogo dinâmico",
          durationSec: Math.round((Number(row.trackTimeMillis) || 0) / 1000),
          artistCountry: "",
          artistGenre: row.primaryGenreName || "",
          artistProfileHint: row.collectionName || "",
          source: "itunes_artist"
        }, existingKeys);

        stats = stylePoolStats(style);
        if (stats.trackCount >= targetSize) break;
      }
      if (stats.trackCount >= targetSize) break;
    }
  }

  // Busca genérica por estilo para atingir cobertura mínima (20 artistas + 20 faixas).
  if (
    !skipBroadStyleHydration &&
    allowBroadItunesHydration &&
    (stats.trackCount < MIN_TRACKS_PER_STYLE || (!hasLocalArtistDepth() && stats.artistCount < coverageTarget.artists)) &&
    familyOf(style) !== "techno"
  ) {
    const genericRows = await fetchItunesTracksByStyle(style);
    for (const row of genericRows) {
      addDynamicTrackToCatalog({
        style,
        song: row.trackName,
        artist: row.artistName,
        label: row.collectionName || row.artistName || "Catálogo dinâmico",
        bpmExact: 0,
        previewUrl: row.previewUrl || "",
        releaseDate: row.releaseDate ? String(row.releaseDate).slice(0, 10) : "Catálogo dinâmico",
        durationSec: Math.round((Number(row.trackTimeMillis) || 0) / 1000),
        artistCountry: "",
        artistGenre: row.primaryGenreName || "",
        artistProfileHint: row.collectionName || "",
        source: "itunes_style"
      }, existingKeys);

      stats = stylePoolStats(style);
      if (stats.trackCount >= targetSize && (stats.artistCount >= coverageTarget.artists || hasLocalArtistDepth())) break;
    }
  }

  // Fallback real por subgenero: Deezer amplo quando os artistas-semente ainda nao bastaram.
  stats = stylePoolStats(style);
  if (!skipBroadStyleHydration && (stats.trackCount < MIN_TRACKS_PER_STYLE || (!hasLocalArtistDepth() && stats.artistCount < coverageTarget.artists))) {
    const deezerStyleRows = await fetchDeezerTracksByStyle(style);
    for (const row of deezerStyleRows) {
      const details = await fetchDeezerTrackDetails(row.id);
      addDynamicTrackToCatalog({
        style,
        song: row.title,
        artist: row.artist?.name || "",
        label: details?.label || row.album?.title || "Catálogo dinâmico",
        bpmExact: Number(details?.bpm) || 0,
        previewUrl: row.preview || details?.preview || "",
        releaseDate: details?.release_date || "Catálogo dinâmico",
        durationSec: Number(details?.duration) || Number(row.duration) || 0,
        artistProfileHint: row.album?.title || "",
        source: "deezer_style"
      }, existingKeys);

      stats = stylePoolStats(style);
      if (stats.trackCount >= targetSize && (stats.artistCount >= coverageTarget.artists || hasLocalArtistDepth())) break;
    }
  }

  stats = stylePoolStats(style);
  if (!skipBroadStyleHydration && (stats.trackCount < targetSize || stats.artistCount < coverageTarget.artists)) {
    const soundCloudRows = await fetchSoundCloudTracksByStyle(style);
    for (const row of soundCloudRows) {
      addSoundCloudApiTrackToCatalog(row, style, existingKeys);
      stats = stylePoolStats(style);
      if (stats.trackCount >= targetSize && (stats.artistCount >= coverageTarget.artists || hasLocalArtistDepth())) break;
    }
  }

  await ensureCatalogArtistDepthForStyle(style, {
    limit: ARTIST_CATALOG_DEPTH_STYLE_LIMIT,
    target: ARTIST_CATALOG_DEPTH_TARGET
  });

  dynamicCatalogByStyle.set(style, Date.now());
  saveDynamicCatalogCache();
}

function getAllSelectableStyles() {
  if (!styleEl) return [];
  return Array.from(styleEl.options)
    .map((option) => option.value)
    .filter(Boolean);
}

function familyLabelByValue(family = "") {
  const labels = {
    psytrance: currentLanguage === "en" ? "psy" : currentLanguage === "es" ? "psy" : "psy",
    trance: currentLanguage === "en" ? "trance" : currentLanguage === "es" ? "trance" : "trance",
    techno: "techno",
    house: "house",
    dnb: "DnB",
    bass_music: currentLanguage === "en" ? "bass" : currentLanguage === "es" ? "bass" : "bass",
    leftfield: currentLanguage === "en" ? "leftfield" : currentLanguage === "es" ? "leftfield" : "leftfield",
    hard_dance: currentLanguage === "en" ? "hard dance" : currentLanguage === "es" ? "hard dance" : "hard dance"
  };
  return labels[family] || family || "";
}

function styleBpmShortLabel(style = "") {
  const rule = STYLE_BPM_RULES[style];
  if (!rule) return t("bpm");
  const min = Number(rule.min) || 0;
  const max = Number(rule.max) || 0;
  if (!min || !max) return t("bpm");
  if (max >= 220) return `${min}+ BPM`;
  return `${min}-${max} BPM`;
}

function swipeDiscoveryRailStyles({ expanded = swipeStyleRailExpanded } = {}) {
  const availableStyles = new Set(getAllSelectableStyles());
  const priorityStyles = SWIPE_DISCOVERY_STYLE_DECK.filter((style) => availableStyles.has(style));
  const prioritySet = new Set(priorityStyles);
  const activeStyle = styleEl?.value || "";
  const activeFamily = familyOf(activeStyle);
  const remainingStyles = getAllSelectableStyles().filter((style) => style && !prioritySet.has(style));
  const allStyles = [activeStyle, ...priorityStyles, ...remainingStyles]
    .filter(Boolean)
    .filter((style, index, list) => list.indexOf(style) === index);
  if (expanded || allStyles.length <= SWIPE_STYLE_RAIL_COMPACT_LIMIT) return allStyles;

  const familyStyles = activeFamily ? allStyles.filter((style) => familyOf(style) === activeFamily) : [];
  const unseenStyles = allStyles.filter((style) => !(Number(swipeStyleExposureCounts.get(style)) || 0));
  const compactStyles = [
    activeStyle,
    ...familyStyles.slice(0, 7),
    ...priorityStyles,
    ...unseenStyles
  ].filter(Boolean)
    .filter((style, index, list) => list.indexOf(style) === index)
    .slice(0, SWIPE_STYLE_RAIL_COMPACT_LIMIT);

  return compactStyles.length ? compactStyles : allStyles.slice(0, SWIPE_STYLE_RAIL_COMPACT_LIMIT);
}

function renderSwipeStyleRail() {
  if (!swipeStyleRail) return;
  const styles = swipeDiscoveryRailStyles();
  const allStyles = swipeDiscoveryRailStyles({ expanded: true });
  swipeStyleRail.innerHTML = "";
  swipeStyleRail.setAttribute("aria-label", t("swipeStyleRailAria"));

  styles.forEach((style) => {
    const button = document.createElement("button");
    button.type = "button";
    button.className = "swipe-style-pill";
    button.dataset.swipeStyle = style;
    button.dataset.swipeFamily = familyOf(style);
    button.setAttribute("aria-pressed", styleEl?.value === style ? "true" : "false");
    if (styleEl?.value === style) button.classList.add("active");

    const label = document.createElement("span");
    label.textContent = styleLabelByValue(style);
    const meta = document.createElement("small");
    const familyLabel = familyLabelByValue(familyOf(style));
    meta.textContent = [styleBpmShortLabel(style), familyLabel].filter(Boolean).join(" • ");

    button.append(label, meta);
    swipeStyleRail.appendChild(button);
  });

  if (allStyles.length > SWIPE_STYLE_RAIL_COMPACT_LIMIT) {
    const toggle = document.createElement("button");
    toggle.type = "button";
    toggle.className = "swipe-style-pill swipe-style-toggle";
    toggle.dataset.swipeStyleToggle = swipeStyleRailExpanded ? "compact" : "all";
    toggle.setAttribute("aria-expanded", swipeStyleRailExpanded ? "true" : "false");

    const label = document.createElement("span");
    label.textContent = swipeStyleRailExpanded
      ? t("swipeShowFocusedStyles")
      : t("swipeShowAllStyles", { count: allStyles.length });
    const meta = document.createElement("small");
    meta.textContent = swipeStyleRailExpanded
      ? t("swipeDeckKicker")
      : `${styles.length}/${allStyles.length}`;

    toggle.append(label, meta);
    swipeStyleRail.appendChild(toggle);
  }
}

async function hydrateCatalogUntilCoverage(style, maxPasses = COVERAGE_MAX_PASSES) {
  const coverage = await ensureStyleCoverageWithTimeout(style, maxPasses);
  return coverage.stats || styleCoverageStats(style);
}

async function warmupCatalogInBackground() {
  if (catalogWarmupRunning) return;
  catalogWarmupRunning = true;
  const selectedStyle = styleEl?.value || "";
  const selectedFamily = familyOf(selectedStyle);
  const allStyles = getAllSelectableStyles();
  const styles = [
    selectedStyle,
    ...allStyles.filter((style) => selectedFamily && familyOf(style) === selectedFamily),
    ...allStyles
  ].filter(Boolean)
    .filter((style, index, list) => list.indexOf(style) === index)
    .slice(0, BACKGROUND_WARMUP_STYLE_LIMIT);

  for (const style of styles) {
    const stats = await hydrateCatalogUntilCoverage(style, 2);
    if (feedbackMessage && style === (styleEl?.value || "")) {
      feedbackMessage.textContent = t("catalogUpdateProgress", {
        style: styleLabelByValue(style),
        tracks: stats.tracks,
        artists: stats.artists
      });
    }
  }

  catalogWarmupRunning = false;
  showToast(t("warmupCatalogToast"));
}

function soundCloudPreviewUrlFromRow(row) {
  const direct = normalizePreviewUrl(row?.previewUrl || row?.preview || "");
  if (direct) return direct;
  if (Array.isArray(row?.previewCandidates)) {
    return row.previewCandidates.map((url) => normalizePreviewUrl(url)).find(Boolean) || "";
  }
  return "";
}

function canonicalExternalTrackUrl(url = "") {
  try {
    const parsed = new URL(String(url || "").trim());
    parsed.search = "";
    parsed.hash = "";
    return parsed.toString().replace(/\/+$/, "").toLowerCase();
  } catch (_err) {
    return String(url || "").trim().split("?")[0].replace(/\/+$/, "").toLowerCase();
  }
}

function shouldRefreshSoundCloudPreview(track, { force = false } = {}) {
  if (!track?.style || !track?.artist || !track?.song) return false;
  if (!force && trackHasReliableAudioPreview(track)) return false;
  if (track.soundcloudTrackUrl || track.soundcloudUrl || String(track.source || "").includes("soundcloud")) return true;
  return SOUNDCLOUD_PREVIEW_REFRESH_STYLES.has(track.style);
}

function soundCloudDirectUrlFromRow(row) {
  const url = String(row?.soundcloudTrackUrl || "").trim();
  return isDirectSoundCloudTrackUrl(url) ? url : "";
}

function rankedSoundCloudRowsForTrack(track, rows = []) {
  const currentDirectUrl = canonicalExternalTrackUrl(directSoundCloudTrackUrl(track));
  return rows
    .map((row) => {
      const directUrl = soundCloudDirectUrlFromRow(row);
      const rowUrl = canonicalExternalTrackUrl(directUrl);
      const previewUrl = soundCloudPreviewUrlFromRow(row);
      const candidateTitle = row.song || row.title || "";
      const sameDirectUrl = Boolean(currentDirectUrl && rowUrl && currentDirectUrl === rowUrl);
      const titleScore = titleConfidence(track.song, candidateTitle);
      const artistOk = isArtistMatch(row.artist || "", track.artist || "");
      const normalizedArtist = normalize(track.artist || "");
      const titleArtistOk = Boolean(normalizedArtist && normalize(candidateTitle).includes(normalizedArtist));
      const compactArtist = normalizedArtist.replace(/\s+/g, "");
      const compactTitleArtistOk = Boolean(compactArtist && normalize(candidateTitle).replace(/\s+/g, "").includes(compactArtist));
      const descriptionArtistOk = Boolean(
        normalizedArtist &&
        (
          normalize([row.description, row.tags, row.genre].filter(Boolean).join(" ")).includes(normalizedArtist) ||
          normalize([row.description, row.tags, row.genre].filter(Boolean).join(" ")).replace(/\s+/g, "").includes(compactArtist)
        )
      );
      const titleOk = strictTitleMatch(track.song, candidateTitle);
      const alternateVersionConflict = hasUnrequestedAlternateVersion(track.song, candidateTitle);
      const score =
        (directUrl ? 2.5 : 0) +
        (previewUrl ? 2.2 : 0) +
        (sameDirectUrl ? 2.4 : 0) +
        (artistOk ? 1.1 : 0) +
        (titleArtistOk || compactTitleArtistOk ? 0.9 : 0) +
        (descriptionArtistOk ? 0.55 : 0) +
        titleScore -
        (alternateVersionConflict ? 4 : 0);
      return { row, directUrl, previewUrl, sameDirectUrl, titleScore, artistOk, titleArtistOk, compactTitleArtistOk, descriptionArtistOk, titleOk, alternateVersionConflict, score };
    })
    .sort((a, b) => b.score - a.score);
}

function isTrustedSoundCloudMatch(candidate) {
  if (!candidate) return false;
  if (candidate.sameDirectUrl) return true;
  if (candidate.alternateVersionConflict) return false;
  return Boolean(
    candidate.titleOk &&
    candidate.titleScore >= 0.86 &&
    (candidate.artistOk || candidate.titleArtistOk || candidate.compactTitleArtistOk || candidate.descriptionArtistOk)
  );
}

function applySoundCloudMatchToTrack(track, candidate, { requirePreview = false, requireDirect = false } = {}) {
  if (!track || !isTrustedSoundCloudMatch(candidate)) return false;
  if (requirePreview && !candidate.previewUrl) return false;
  if (requireDirect && !candidate.directUrl) return false;

  if (candidate.directUrl) {
    track.soundcloudTrackUrl = candidate.directUrl;
    track.soundcloudUrl = candidate.directUrl;
  }
  if (candidate.previewUrl) {
    promotePreviewCandidate(track, candidate.previewUrl);
    track.previewChecked = true;
    track.previewMissing = false;
    track.previewLookupAttempted = true;
    track.previewSource = "soundcloud_api";
  }
  if (Array.isArray(candidate.row?.previewCandidates)) {
    candidate.row.previewCandidates.forEach((previewUrl) => registerPreviewCandidate(track, previewUrl));
  }
  track.soundcloudVerified = true;
  track.existenceVerified = true;
  return Boolean(candidate.directUrl || candidate.previewUrl);
}

async function refreshSoundCloudPreviewForTrack(track, { force = false } = {}) {
  if (!shouldRefreshSoundCloudPreview(track, { force })) return false;
  const rows = await fetchSoundCloudTracksByStyle(track.style, track.artist, { track, force });
  if (!rows.length) return false;

  const best =
    rankedSoundCloudRowsForTrack(track, rows).find((candidate) => candidate.previewUrl && isTrustedSoundCloudMatch(candidate)) ||
    rankedSoundCloudRowsForTrack(track, rows).find((candidate) => candidate.directUrl && isTrustedSoundCloudMatch(candidate));
  return applySoundCloudMatchToTrack(track, best);
}

async function resolveSoundCloudEmbedForTrack(track, { force = false } = {}) {
  if (!track?.style || !track?.artist || !track?.song) return false;
  if (trackHasDirectSoundCloudTrack(track)) {
    track.soundcloudVerified = true;
    return true;
  }
  if (!force && track.soundcloudEmbedLookupAttempted) return false;
  track.soundcloudEmbedLookupAttempted = true;

  const rows = await fetchSoundCloudTracksByStyle(track.style, track.artist, { track, force });
  if (!rows.length) return false;

  const best = rankedSoundCloudRowsForTrack(track, rows).find((candidate) => candidate.directUrl && isTrustedSoundCloudMatch(candidate));
  return applySoundCloudMatchToTrack(track, best, { requireDirect: true });
}

async function resolvePreviewForTrack(track, { forceLookup = false } = {}) {
  if (!track) return;
  const trustedSlambient = isTrustedSlambientCatalogTrack(track);
  const trustedCurated = isTrustedCuratedCatalogTrack(track);
  if (trustedCurated && track.existenceVerified === false && hasReliableBpmForTrack(track)) {
    track.existenceVerified = true;
  }
  if (trustedSlambient) normalizeTrustedSlambientCatalog();
  const rawPreviewUrl = String(track.previewUrl || "").trim();
  const previewExpired = Boolean(rawPreviewUrl && previewUrlIsExpired(rawPreviewUrl, 0));
  const currentPreview = normalizePreviewUrl(rawPreviewUrl);
  if (currentPreview) {
    track.previewUrl = currentPreview;
    registerPreviewCandidate(track, currentPreview);
  }
  if (currentPreview && track.existenceVerified !== false && !forceLookup && (trustedCurated || track.previewLookupAttempted)) {
    track.existenceVerified = true;
    track.previewChecked = true;
    track.previewMissing = false;
    return;
  }
  if (track.previewChecked && track.existenceVerified !== undefined && !forceLookup && !previewExpired && (trustedCurated || track.previewLookupAttempted)) return;

  let foundEvidence = Boolean(currentPreview);
  const strictStyle = hasStrictWhitelist(track.style) || STRICT_ARTIST_MATCH_STYLES.has(track.style);
  const minConfidence = track.style === "slambient" ? 0.97 : strictStyle ? 0.94 : 0.9;
  const ensureTrackMetadata = (releaseDate = "", durationSec = 0, catalogRef = "") => {
    const current = TRACK_METADATA[`${track.song}|${track.artist}`] || {};
    const duration =
      durationSec > 0
        ? `${String(Math.floor(durationSec / 60)).padStart(2, "0")}:${String(durationSec % 60).padStart(2, "0")}`
        : current.duration || "06:00";
    TRACK_METADATA[`${track.song}|${track.artist}`] = {
      releaseDate: releaseDate || current.releaseDate || "Catálogo local",
      duration,
      musicalKey: current.musicalKey || "N/A",
      catalogRef: catalogRef || current.catalogRef || "CATALOGO"
    };
  };

  try {
    const query = encodeURIComponent(`artist:"${track.artist}" track:"${track.song}"`);
    const data = await deezerJsonp(`https://api.deezer.com/search?q=${query}`);
    const ranked = (data?.data || [])
      .filter((item) => isArtistMatch(item?.artist?.name || "", track.artist))
      .map((item) => ({
        item,
        score: titleConfidence(track.song, item?.title || "")
      }))
      .sort((a, b) => b.score - a.score);

    const best = ranked[0];
    const candidateTitle = best?.item?.title || "";
    const deezerMatch =
      best &&
      best.score >= minConfidence &&
      strictTitleMatch(track.song, candidateTitle)
        ? best.item
        : null;

    if (deezerMatch) {
      foundEvidence = true;
      track.existenceVerified = true;
      track.spotifyVerified = true;
      track.youtubeVerified = true;
      track.previewConfidence = best.score;
      track.artistProfileHint = track.artistProfileHint || deezerMatch?.album?.title || "";
      const deezerArtistImage = String(
        deezerMatch?.artist?.picture_xl ||
        deezerMatch?.artist?.picture_big ||
        deezerMatch?.artist?.picture_medium ||
        ""
      ).trim();
      if (deezerArtistImage && !shouldSuppressUnverifiedArtistImage(track, "Deezer")) {
        track.artistImageUrl = deezerArtistImage;
        track.artistImageSource = "Deezer";
      }
      promotePreviewCandidate(track, deezerMatch.preview || "");
      track.spotifyTrackUrl = buildSpotifyTrackLink(track);
      track.youtubeTrackUrl = buildYouTubeTrackLink(track);

      const details = await fetchDeezerTrackDetails(deezerMatch.id);
      if (details?.bpm && !bpmFitsStyle(track.style, Number(details.bpm))) {
        track.previewUrl = "";
        track.previewCandidates = [];
        if (trustedCurated && hasReliableBpmForTrack(track)) {
          foundEvidence = true;
          track.existenceVerified = true;
          track.previewConfidence = 0;
        } else {
          track.existenceVerified = false;
          track.previewChecked = true;
          track.previewMissing = true;
          track.previewLookupAttempted = true;
          return;
        }
      } else {
        if (details?.bpm && bpmFitsStyle(track.style, Number(details.bpm))) {
          track.bpmExact = Number(details.bpm);
          track.bpm = mapBpmToRange(track.bpmExact);
          if (!track.energy) track.energy = energyFromBpm(track.bpmExact);
        }
        ensureTrackMetadata(details?.release_date || "", Number(details?.duration) || Number(deezerMatch?.duration) || 0, details?.isrc || "DEEZER");
      }
    }
  } catch (_err) {
    // tenta iTunes abaixo
  }

  try {
    const term = encodeURIComponent(`${track.artist} ${track.song}`);
    const data = await itunesJsonp(`https://itunes.apple.com/search?term=${term}&entity=song&limit=40`);
    const ranked = (data?.results || [])
      .filter((row) => isArtistMatch(row?.artistName || "", track.artist))
      .map((row) => ({
        row,
        score: titleConfidence(track.song, row?.trackName || "")
      }))
      .sort((a, b) => b.score - a.score);

    const best = ranked[0];
    const candidateTitle = best?.row?.trackName || "";
    const itunesMatch =
      best &&
      best.score >= (strictStyle ? 0.94 : 0.91) &&
      strictTitleMatch(track.song, candidateTitle)
        ? best.row
        : null;

    if (itunesMatch) {
      foundEvidence = true;
      track.existenceVerified = true;
      track.spotifyVerified = true;
      track.youtubeVerified = true;
      track.artistGenre = track.artistGenre || String(itunesMatch.primaryGenreName || "").trim();
      track.artistProfileHint = track.artistProfileHint || String(itunesMatch.collectionName || "").trim();
      promotePreviewCandidate(track, itunesMatch.previewUrl || "");
      track.previewConfidence = Math.max(Number(track.previewConfidence) || 0, best.score);
      if (!track.spotifyTrackUrl) {
        track.spotifyTrackUrl = buildSpotifyTrackLink(track);
      }
      if (!track.youtubeTrackUrl) {
        track.youtubeTrackUrl = buildYouTubeTrackLink(track);
      }
      ensureTrackMetadata(
        itunesMatch.releaseDate ? String(itunesMatch.releaseDate).slice(0, 10) : "",
        Math.round((Number(itunesMatch.trackTimeMillis) || 0) / 1000),
        String(itunesMatch.trackId || "ITUNES")
      );
    }
  } catch (_err) {
    // sem fallback adicional
  }

  try {
    const shouldTrySoundCloud =
      forceLookup ||
      !previewCandidatesForTrack(track).length ||
      Boolean(track.previewChecked && track.previewMissing);
    if (shouldTrySoundCloud) {
      const foundSoundCloudPreview = await refreshSoundCloudPreviewForTrack(track, { force: forceLookup });
      if (foundSoundCloudPreview) foundEvidence = true;
    }
  } catch (_err) {
    // SoundCloud fica como melhoria oportunista; se falhar, mantemos os outros fallbacks.
  }

  if (!foundEvidence && !trustedCurated) {
    track.existenceVerified = false;
  }
  if (track.existenceVerified === undefined) {
    track.existenceVerified = trustedCurated ? true : foundEvidence;
  }
  const previewCandidates = previewCandidatesForTrack(track);
  track.previewUrl = previewCandidates[0] || "";
  track.previewChecked = true;
  track.previewMissing = previewCandidates.length === 0 && !trackHasExternalPlayableFallback(track);
  track.previewLookupAttempted = true;
}

