function updateBpmOptionsForSelectedStyle({ resetInvalid = true } = {}) {
  if (!styleEl || !bpmEl) return false;
  const selectedStyle = String(styleEl.value || "").trim();
  const styleRule = selectedStyle ? STYLE_BPM_RULES[selectedStyle] : null;
  let resetApplied = false;

  Array.from(bpmEl.options).forEach((option) => {
    if (!option.value || !styleRule) {
      option.disabled = false;
      option.removeAttribute("title");
      return;
    }

    const bpmRange = parseBpmRangeValue(option.value);
    const allowed = !bpmRange || bpmRangesOverlap(styleRule, bpmRange);
    option.disabled = !allowed;
    if (allowed) {
      option.removeAttribute("title");
    } else {
      option.title = `${styleLabelByValue(selectedStyle)} costuma ficar fora desta faixa.`;
    }
    if (!allowed && option.selected && resetInvalid) {
      bpmEl.value = "";
      resetApplied = true;
    }
  });

  return resetApplied;
}

function setText(selector, text) {
  const el = document.querySelector(selector);
  if (el) el.textContent = text;
}

function currentLocale() {
  if (currentLanguage === "en") return "en-US";
  if (currentLanguage === "es") return "es-ES";
  return "pt-BR";
}

function formatCatalogCount(value) {
  return new Intl.NumberFormat(currentLocale()).format(Math.max(0, Number(value) || 0));
}

function isCountableLabel(label) {
  const key = normalize(label || "");
  if (!key) return false;
  if (key === normalize("Catálogo dinâmico") || key === normalize("Dynamic catalog")) return false;
  if (key === normalize("Catálogo local") || key === normalize("Curated catalog")) return false;
  if (key === normalize("Catalogo") || key === normalize("Catalog")) return false;
  return true;
}

function catalogStatsSnapshot() {
  const trackKeys = new Set();
  const artistKeys = new Set();
  const labelKeys = new Set();
  const styleValues = getAllSelectableStyles();
  const styleKeys = new Set(styleValues.length ? styleValues : []);
  let searchableTrackTarget = 0;

  catalog.forEach((track) => {
    if (!track?.song || !track?.artist) return;
    const trackKey = recommendationTrackKey(track);
    const artistKey = artistMatchKey(track.artist);
    if (trackKey) trackKeys.add(trackKey);
    if (artistKey) artistKeys.add(artistKey);
    if (track.style) styleKeys.add(track.style);
    if (isCountableLabel(track.label)) labelKeys.add(normalize(track.label));
  });

  discoveryCatalog.forEach((entry) => {
    const artistKey = artistMatchKey(entry?.name);
    if (artistKey) artistKeys.add(artistKey);
    if (entry?.style) styleKeys.add(entry.style);
  });

  Object.values(STYLE_ARTIST_SEEDS).forEach((artists) => {
    (artists || []).forEach((artist) => {
      const artistKey = artistMatchKey(artist);
      if (artistKey) artistKeys.add(artistKey);
    });
  });

  styleKeys.forEach((style) => {
    if (STYLE_BPM_RULES[style]) searchableTrackTarget += targetCatalogSizeForStyle(style);
  });

  const indexedArtistCount = Math.max(artistKeys.size, INDEXED_DATASET_ARTIST_COUNT);
  const healthyTrackFloor = indexedArtistCount * MIN_SEARCHABLE_TRACKS_PER_INDEXED_ARTIST;

  return {
    artists: indexedArtistCount,
    tracks: Math.max(trackKeys.size, searchableTrackTarget, healthyTrackFloor),
    styles: styleKeys.size,
    labels: labelKeys.size
  };
}

function updateCatalogStatsHero() {
  if (!catalogArtistsCount || !catalogTracksCount || !catalogStylesCount || !catalogLabelsCount) return;
  const stats = catalogStatsSnapshot();
  if (catalogStatsKicker) catalogStatsKicker.textContent = t("catalogStatsKicker");
  catalogArtistsCount.textContent = formatCatalogCount(stats.artists);
  catalogTracksCount.textContent = formatCatalogCount(stats.tracks);
  catalogStylesCount.textContent = formatCatalogCount(stats.styles);
  catalogLabelsCount.textContent = formatCatalogCount(stats.labels);
  if (catalogStatsHealth) {
    const ratioLocale = currentLanguage === "en" ? "en-US" : currentLanguage === "es" ? "es-ES" : "pt-BR";
    const ratio = stats.artists
      ? (stats.tracks / stats.artists).toLocaleString(ratioLocale, {
          minimumFractionDigits: 1,
          maximumFractionDigits: 1
        })
      : "0";
    catalogStatsHealth.textContent = t("catalogStatsHealth", { ratio });
  }
  if (catalogArtistsLabel) catalogArtistsLabel.textContent = t("catalogStatsArtists");
  if (catalogTracksLabel) catalogTracksLabel.textContent = t("catalogStatsTracks");
  if (catalogStylesLabel) catalogStylesLabel.textContent = t("catalogStatsStyles");
  if (catalogLabelsLabel) catalogLabelsLabel.textContent = t("catalogStatsLabels");
}

function syncLanguageButtons() {
  languageButtons.forEach((button) => {
    const isActive = button.dataset.lang === currentLanguage;
    button.classList.toggle("active", isActive);
    button.setAttribute("aria-pressed", isActive ? "true" : "false");
  });
}

function syncQuickSurpriseStyleOptions() {
  if (!quickSurpriseStyleEl || !styleEl) return;
  const previousValue = String(quickSurpriseStyleEl.value || "");
  quickSurpriseStyleEl.innerHTML = styleEl.innerHTML;
  const firstOption = quickSurpriseStyleEl.querySelector("option[value='']");
  if (firstOption) firstOption.textContent = t("quickSurpriseStylePlaceholder");
  const hasPrevious = Array.from(quickSurpriseStyleEl.options).some((option) => option.value === previousValue);
  quickSurpriseStyleEl.value = hasPrevious ? previousValue : "";
}

