function countryCodeToFlagEmoji(countryCode = "") {
  const code = String(countryCode || "").trim().toUpperCase();
  if (!/^[A-Z]{2}$/.test(code)) return "";
  return code
    .split("")
    .map((letter) => String.fromCodePoint(127397 + letter.charCodeAt(0)))
    .join("");
}

function countryNameToCode(countryName = "") {
  const raw = String(countryName || "").trim();
  if (!raw) return "";
  if (/^[A-Za-z]{2}$/.test(raw)) return raw.toUpperCase();
  const key = normalize(raw);
  if (COUNTRY_CODE_BY_NAME[key]) return COUNTRY_CODE_BY_NAME[key];
  if (typeof Intl !== "undefined" && typeof Intl.DisplayNames === "function") {
    const languages = [currentLanguage === "pt" ? "pt-BR" : currentLanguage || "en", "en", "pt-BR", "es"];
    for (const language of languages) {
      try {
        const displayNames = new Intl.DisplayNames([language], { type: "region" });
        for (let code = 65; code <= 90; code += 1) {
          for (let code2 = 65; code2 <= 90; code2 += 1) {
            const candidate = String.fromCharCode(code, code2);
            if (normalize(displayNames.of(candidate) || "") === key) return candidate;
          }
        }
      } catch (_err) {
        // Intl.DisplayNames is best-effort for country names.
      }
    }
  }
  return "";
}

function localizedCountryName(countryName = "") {
  const raw = String(countryName || "").trim();
  if (!raw) return "";
  const code = countryNameToCode(raw);
  if (!code || typeof Intl === "undefined" || typeof Intl.DisplayNames !== "function") return raw;
  try {
    const locale = currentLanguage === "pt" ? "pt-BR" : currentLanguage || "en";
    return new Intl.DisplayNames([locale], { type: "region" }).of(code) || raw;
  } catch (_err) {
    return raw;
  }
}

function parseOriginText(originText = "") {
  const raw = String(originText || "").replace(/[()]/g, ",").replace(/\s+/g, " ").trim();
  if (!raw) return { country: "", area: "" };
  const parts = raw
    .split(",")
    .map((part) => part.trim())
    .filter(Boolean);
  const candidates = parts.length ? parts : [raw];
  for (let index = candidates.length - 1; index >= 0; index -= 1) {
    const candidate = candidates[index];
    if (countryNameToCode(candidate)) {
      return {
        country: candidate,
        area: candidates.slice(0, index).join(", ")
      };
    }
  }
  if (countryNameToCode(raw)) return { country: raw, area: "" };
  const inferredCountry = COUNTRY_BY_ORIGIN_AREA[normalize(raw)] || "";
  return { country: inferredCountry, area: raw };
}

function artistOriginSignalForTrack(track) {
  const artist = String(track?.artist || "").trim();
  const canonical = canonicalOriginForArtist(artist);
  const parsedTrackArea = parseOriginText(track?.artistArea || "");
  const apiOrCatalogCountry = String(canonical?.country || track?.artistCountry || parsedTrackArea.country || "").trim();
  const apiOrCatalogArea = String(canonical?.area || (track?.artistCountry ? track?.artistArea : parsedTrackArea.area) || "").trim();
  if (apiOrCatalogCountry) return { country: apiOrCatalogCountry, area: apiOrCatalogArea };
  if (parsedTrackArea.area && parsedTrackArea.country) return parsedTrackArea;
  if (track?.style === "brazilian_funk") return { country: "Brazil", area: "" };
  return quizOriginSignalForArtist(artist);
}

function formatArtistOriginLabel(origin) {
  const country = String(origin?.country || "").trim();
  const area = String(origin?.area || "").trim();
  const localizedCountry = localizedCountryName(country);
  if (area && country && normalize(area) !== normalize(country)) return `${area}, ${localizedCountry}`;
  if (area && country) return localizedCountry;
  return area || localizedCountry;
}

function originCountryConsistentWithTrack(track, originText = "") {
  const parsedOrigin = parseOriginText(originText);
  const parsedCountryCode = countryNameToCode(parsedOrigin.country || "");
  if (!parsedCountryCode) return true;
  const displayedOrigin = artistOriginSignalForTrack(track);
  const displayedCountryCode = countryNameToCode(displayedOrigin?.country || "");
  return !displayedCountryCode || displayedCountryCode === parsedCountryCode;
}

function updateArtistOriginFlags(track) {
  const origin = artistOriginSignalForTrack(track);
  const country = String(origin?.country || "").trim();
  const flag = countryCodeToFlagEmoji(countryNameToCode(country));
  const label = formatArtistOriginLabel(origin);
  [artistOriginFlag, artistPhotoFlag].forEach((element) => {
    if (!element) return;
    if (!flag) {
      element.textContent = "";
      element.classList.add("hidden");
      element.removeAttribute("title");
      element.removeAttribute("aria-label");
      return;
    }
    element.textContent = flag;
    element.classList.remove("hidden");
    element.title = label || country;
    element.setAttribute("aria-label", label ? `${label}` : country);
  });
}

function renderArtistVisualFallback(track, sourceText = "") {
  const artist = String(track?.artist || "").trim();
  if (!artistVisualCard || !artist) return;
  artistVisualCard.classList.remove("hidden");
  if (artistPhotoName) artistPhotoName.textContent = artist;
  updateArtistOriginFlags(track);
  if (artistPhotoKicker) artistPhotoKicker.textContent = t("artistVisualKicker");
  if (artistPhotoSource) artistPhotoSource.textContent = sourceText || t("artistImageLoading");
  if (artistPhotoFallback) artistPhotoFallback.textContent = artistInitials(artist);
  if (artistPhoto) {
    artistPhoto.classList.add("hidden");
    artistPhoto.removeAttribute("src");
    artistPhoto.alt = "";
  }
  renderTopSwipeArtwork(track);
}

function applyArtistPhoto(track, imageUrl = "", source = "") {
  const artist = String(track?.artist || "").trim();
  const url = String(imageUrl || "").trim();
  if (!artistVisualCard || !artist) return false;
  if (!url || shouldSuppressUnverifiedArtistImage(track, source)) {
    if (shouldSuppressUnverifiedArtistImage(track, source)) {
      track.artistImageUrl = "";
      track.artistImageSource = "";
    }
    renderArtistVisualFallback(track, t("artistImageFallback"));
    return false;
  }
  artistVisualCard.classList.remove("hidden");
  if (artistPhotoName) artistPhotoName.textContent = artist;
  updateArtistOriginFlags(track);
  if (artistPhotoKicker) artistPhotoKicker.textContent = t("artistVisualKicker");
  if (artistPhotoSource) artistPhotoSource.textContent = source ? `${t("artistImageLoaded")} - ${source}` : t("artistImageLoaded");
  if (artistPhotoFallback) artistPhotoFallback.textContent = artistInitials(artist);
  if (artistPhoto) {
    artistPhoto.src = url;
    artistPhoto.alt = artist;
    artistPhoto.classList.remove("hidden");
  }
  track.artistImageUrl = url;
  track.artistImageSource = source || "Deezer";
  renderTopSwipeArtwork(track);
  return true;
}

async function fetchArtistImageFromDeezer(artistName = "") {
  const artist = sanitizeArtistLookupName(artistName);
  const key = normalize(artist);
  if (!key) return null;
  if (isAmbiguousArtistImageName(artist)) {
    artistImageCache.set(key, null);
    return null;
  }
  if (artistImageCache.has(key)) return artistImageCache.get(key);
  try {
    const data = await deezerJsonp(`https://api.deezer.com/search/artist?q=${encodeURIComponent(artist)}&limit=8`);
    const rows = Array.isArray(data?.data) ? data.data : [];
    const best = rows.find((row) => isArtistMatch(row?.name || "", artist));
    const imageUrl = String(best?.picture_xl || best?.picture_big || best?.picture_medium || "").trim();
    const result = imageUrl ? { imageUrl, source: "Deezer" } : null;
    artistImageCache.set(key, result);
    return result;
  } catch (_err) {
    artistImageCache.set(key, null);
    return null;
  }
}

async function hydrateArtistVisual(track) {
  const artist = String(track?.artist || "").trim();
  if (!artist) return;
  const requestToken = (artistImageRequestToken += 1);
  if (track.artistImageUrl && !shouldSuppressUnverifiedArtistImage(track, track.artistImageSource || "Catálogo")) {
    applyArtistPhoto(track, track.artistImageUrl, track.artistImageSource || "Catálogo");
    return;
  }
  if (track.artistImageUrl && shouldSuppressUnverifiedArtistImage(track, track.artistImageSource || "Catálogo")) {
    track.artistImageUrl = "";
    track.artistImageSource = "";
  }
  const result = await fetchArtistImageFromDeezer(artist);
  if (requestToken !== artistImageRequestToken) return;
  if (!currentRecommendation || !isArtistMatch(currentRecommendation.artist, artist)) return;
  if (result?.imageUrl) {
    applyArtistPhoto(track, result.imageUrl, result.source);
  } else {
    renderArtistVisualFallback(track, t("artistImageFallback"));
  }
}

function renderArtistSocialLinks(track) {
  if (!artistSocialsPanel || !artistSocialLinks) return;
  const artist = String(track?.artist || "").trim();
  if (!artist) {
    artistSocialsPanel.classList.add("hidden");
    artistSocialLinks.innerHTML = "";
    return;
  }

  const profiles = buildArtistSocialProfiles(artist);
  if (!profiles.length) {
    artistSocialsPanel.classList.add("hidden");
    artistSocialLinks.innerHTML = "";
    return;
  }

  artistSocialLinks.innerHTML = "";
  profiles.forEach((profile) => {
    const link = document.createElement("a");
    link.className = "social-link";
    link.href = profile.url;
    link.target = "_blank";
    link.rel = "noopener noreferrer";
    link.textContent = profile.platform;
    link.title = `${profile.platform} - ${artist}`;
    artistSocialLinks.appendChild(link);
  });
  artistSocialsPanel.classList.remove("hidden");
}

function renderDiscogsArtistPanel(track) {
  if (!discogsArtistPanel || !discogsArtistLink) return;
  const artist = String(track?.artist || "").trim();
  if (!artist) {
    discogsArtistPanel.classList.add("hidden");
    discogsArtistLink.href = "#";
    return;
  }
  const discogsProfileUrl = safeExternalUrl(track?.discogsArtistUrl || track?.artistDiscogsUrl || "");
  if (discogsArtistTitle) discogsArtistTitle.textContent = t("discogsArtistTitle");
  if (discogsArtistHint) discogsArtistHint.textContent = t("discogsArtistHint");
  discogsArtistLink.href = discogsProfileUrl || buildDiscogsArtistSearchUrl(artist);
  discogsArtistLink.textContent = discogsProfileUrl ? t("discogsArtistOpen") : t("discogsArtistLink");
  discogsArtistLink.title = `${discogsProfileUrl ? t("discogsArtistOpen") : t("discogsArtistLink")} - ${artist}`;
  discogsArtistPanel.classList.remove("hidden");
}

function isStrictLinkStyle(style) {
  return hasStrictWhitelist(style) || STRICT_ARTIST_MATCH_STYLES.has(style);
}

function isDirectYouTubeUrl(url) {
  const value = String(url || "").trim();
  if (!value) return false;
  return /^(https?:\/\/)?(www\.)?(youtube\.com\/watch\?v=|youtu\.be\/)[\w-]{6,}/i.test(value);
}

function extractYouTubeVideoId(url = "") {
  const value = String(url || "").trim();
  if (!value) return "";
  try {
    const normalized = /^https?:\/\//i.test(value) ? value : `https://${value}`;
    const parsed = new URL(normalized);
    const host = normalize(parsed.hostname || "");
    if (host.includes("youtu.be")) {
      const directId = String(parsed.pathname || "").replace(/^\/+/, "").split("/")[0] || "";
      return /^[\w-]{6,}$/.test(directId) ? directId : "";
    }
    if (host.includes("youtube.com")) {
      const watchId = parsed.searchParams.get("v") || "";
      if (/^[\w-]{6,}$/.test(watchId)) return watchId;
      const pathParts = String(parsed.pathname || "")
        .split("/")
        .map((part) => String(part || "").trim())
        .filter(Boolean);
      const embedIndex = pathParts.findIndex((part) => part === "embed" || part === "shorts" || part === "live");
      if (embedIndex >= 0 && pathParts[embedIndex + 1] && /^[\w-]{6,}$/.test(pathParts[embedIndex + 1])) {
        return pathParts[embedIndex + 1];
      }
    }
    return "";
  } catch (_err) {
    return "";
  }
}

function trackHasDirectYouTubeVideo(track) {
  if (!track) return false;
  if (youtubeVideoCandidatesForTrack(track).length > 0) return true;
  return Boolean(
    extractYouTubeVideoId(track.youtubeTrackUrl) ||
    extractYouTubeVideoId(track.youtubeUrl)
  );
}

function isDirectSoundCloudTrackUrl(value = "") {
  const raw = String(value || "").trim();
  if (!raw) return false;
  try {
    const parsed = new URL(raw);
    const host = parsed.hostname.replace(/^www\./, "").toLowerCase();
    if (!host.endsWith("soundcloud.com")) return false;
    const parts = parsed.pathname
      .split("/")
      .map((part) => part.trim())
      .filter(Boolean);
    if (parts.length < 2) return false;
    const blocked = new Set(["search", "discover", "you", "stream", "charts", "upload", "pages", "settings"]);
    if (blocked.has(parts[0])) return false;
    if (parts[0] === "sets") return false;
    if (parts[1] === "sets") return false;
    return true;
  } catch (_err) {
    return false;
  }
}

function directSoundCloudTrackUrl(track) {
  const candidates = [track?.soundcloudTrackUrl, track?.soundcloudUrl]
    .map((url) => String(url || "").trim())
    .filter(Boolean);
  return candidates.find((url) => isDirectSoundCloudTrackUrl(url)) || "";
}

function trackHasDirectSoundCloudTrack(track) {
  return Boolean(directSoundCloudTrackUrl(track));
}

function trackHasDirectBandcampTrack(track) {
  return Boolean(String(track?.bandcampTrackUrl || track?.bandcampUrl || "").trim());
}

function bandcampTrackIdForEmbed(track) {
  return String(track?.bandcampTrackId || "")
    .replace(/[^\d]/g, "")
    .trim();
}

function trackHasEmbeddableBandcampTrack(track) {
  return Boolean(bandcampTrackIdForEmbed(track));
}

function youtubeSearchQueryVariants(track) {
  const artist = String(track?.artist || "").trim();
  const song = String(track?.song || "").trim();
  const styleTerm = String(STYLE_SEARCH_TERMS[track?.style] || styleLabelByValue(track?.style || "") || "").trim();
  const baseVariants = [
    `${artist} ${song} official audio`,
    `${artist} ${song} topic`,
    `"${artist}" "${song}" audio`,
    `${artist} ${song} ${styleTerm} audio`
  ]
    .map((item) => String(item || "").replace(/\s+/g, " ").trim())
    .filter(Boolean);
  const unique = [];
  const seen = new Set();
  baseVariants.forEach((entry) => {
    const key = normalize(entry);
    if (!key || seen.has(key)) return;
    seen.add(key);
    unique.push(entry);
  });
  if (unique.length) return unique;

  const fallback = `${artist} ${song}`.replace(/\s+/g, " ").trim() || `${song} ${styleTerm}`.replace(/\s+/g, " ").trim();
  if (!fallback) return [];
  return [fallback];
}

function youtubePreviewStateTrackKey(track) {
  return recommendationTrackKey(track) || normalize(`${track?.artist || ""}::${track?.song || ""}`);
}

function syncYouTubePreviewAttemptForTrack(track) {
  const trackKey = youtubePreviewStateTrackKey(track);
  if (!trackKey) return;
  if (youtubePreviewTrackKey !== trackKey) {
    youtubePreviewTrackKey = trackKey;
    youtubePreviewSearchAttempt = 0;
  }
}

function youtubePreviewCanRetry(track) {
  return youtubeVideoCandidatesForTrack(track).length > 1;
}

function youtubePreviewSearchAttemptCount(track) {
  const candidateCount = youtubeVideoCandidatesForTrack(track).length;
  if (candidateCount > 0) return candidateCount;
  return trackHasDirectYouTubeVideo(track) ? 1 : 0;
}

function youtubeSearchPlanForAttempt(track, attempt = 0) {
  const variants = youtubeSearchQueryVariants(track);
  if (!variants.length) return null;

  const totalAttempts = Math.max(1, variants.length * YOUTUBE_SEARCH_RESULTS_PER_QUERY);
  const safeAttempt = Math.max(0, Number(attempt) || 0) % totalAttempts;
  const variantIndex = Math.floor(safeAttempt / YOUTUBE_SEARCH_RESULTS_PER_QUERY);
  const resultIndex = (safeAttempt % YOUTUBE_SEARCH_RESULTS_PER_QUERY) + 1;

  return {
    query: variants[variantIndex] || variants[0],
    resultIndex,
    totalAttempts
  };
}

function syncPreviewSourceActionsVisibility() {
  if (!youtubePreviewActions) return;
  const hasVisibleAction = [
    youtubePreviewToggleBtn,
    youtubePreviewRetryBtn,
    soundcloudPreviewToggleBtn,
    bandcampPreviewToggleBtn,
    soundcloudPreviewSearchLink
  ].some((item) => Boolean(item && !item.classList.contains("hidden")));
  youtubePreviewActions.classList.toggle("hidden", !hasVisibleAction);
}

function setYouTubePreviewActionState({ visible = false, canToggle = false, canRetry = false, expanded = false } = {}) {
  if (youtubePreviewToggleBtn) {
    youtubePreviewToggleBtn.classList.toggle("hidden", !visible || !canToggle);
    youtubePreviewToggleBtn.disabled = !canToggle;
    youtubePreviewToggleBtn.textContent = expanded
      ? t("previewYoutubeCloseInlineBtn")
      : t("previewYoutubeOpenInlineBtn");
  }
  if (youtubePreviewRetryBtn) {
    youtubePreviewRetryBtn.classList.toggle("hidden", !visible || !canRetry);
    youtubePreviewRetryBtn.disabled = !canRetry;
    youtubePreviewRetryBtn.textContent = t("previewYoutubeRetryBtn");
  }
  syncPreviewSourceActionsVisibility();
}

function setSoundCloudPreviewActionState({ visible = false, canToggle = false, canSearch = false, expanded = false, href = "" } = {}) {
  if (soundcloudPreviewToggleBtn) {
    soundcloudPreviewToggleBtn.classList.toggle("hidden", !visible || !canToggle);
    soundcloudPreviewToggleBtn.disabled = !canToggle;
    soundcloudPreviewToggleBtn.textContent = expanded
      ? t("previewSoundcloudCloseInlineBtn")
      : t("previewSoundcloudOpenInlineBtn");
  }
  if (soundcloudPreviewSearchLink) {
    const safeHref = String(href || "").trim();
    soundcloudPreviewSearchLink.classList.toggle("hidden", !visible || !canSearch || !safeHref);
    if (safeHref) soundcloudPreviewSearchLink.href = safeHref;
    else soundcloudPreviewSearchLink.href = "#";
    soundcloudPreviewSearchLink.textContent = t("previewSoundcloudSearchBtn");
    soundcloudPreviewSearchLink.setAttribute("aria-disabled", safeHref ? "false" : "true");
  }
  syncPreviewSourceActionsVisibility();
}

function setBandcampPreviewActionState({ visible = false, canToggle = false, expanded = false } = {}) {
  if (bandcampPreviewToggleBtn) {
    bandcampPreviewToggleBtn.classList.toggle("hidden", !visible || !canToggle);
    bandcampPreviewToggleBtn.disabled = !canToggle;
    bandcampPreviewToggleBtn.textContent = expanded
      ? t("previewBandcampCloseInlineBtn")
      : t("previewBandcampOpenInlineBtn");
  }
  syncPreviewSourceActionsVisibility();
}

function syncBandcampPreviewActionForTrack(track, { expanded = false } = {}) {
  const embeddable = trackHasEmbeddableBandcampTrack(track);
  setBandcampPreviewActionState({
    visible: embeddable,
    canToggle: embeddable,
    expanded
  });
}

function syncSoundCloudPreviewActionForTrack(track, { expanded = false } = {}) {
  const direct = trackHasDirectSoundCloudTrack(track);
  const href = buildSoundCloudTrackLink(track);
  setSoundCloudPreviewActionState({
    visible: Boolean(direct || href),
    canToggle: direct,
    canSearch: !direct && Boolean(href),
    expanded,
    href
  });
}

function buildYouTubeEmbedUrl(track, { autoplay = false, attempt = 0 } = {}) {
  if (!track) return "";
  const autoplayParam = autoplay ? "&autoplay=1&mute=1" : "";
  const commonParams = `rel=0&modestbranding=1&playsinline=1${autoplayParam}`;
  const safeAttempt = Math.max(0, Number(attempt) || 0);
  const candidates = youtubeVideoCandidatesForTrack(track);
  const candidate = candidates.length ? candidates[safeAttempt % candidates.length] : null;
  const directVideoId =
    candidate?.videoId ||
    extractYouTubeVideoId(track.youtubeTrackUrl) ||
    extractYouTubeVideoId(track.youtubeUrl);
  if (directVideoId) {
    return `https://www.youtube-nocookie.com/embed/${directVideoId}?${commonParams}&retry=${safeAttempt}`;
  }
  return "";
}

function resetYouTubePreviewEmbed() {
  if (!youtubePreviewWrap || !youtubePreviewFrame) return;
  youtubePreviewWrap.classList.add("hidden");
  if (youtubePreviewFrame.getAttribute("src")) {
    youtubePreviewFrame.removeAttribute("src");
  }
  setYouTubePreviewActionState({ visible: false, canToggle: false, canRetry: false, expanded: false });
}

function buildSoundCloudEmbedUrl(track, { autoplay = false } = {}) {
  const directUrl = directSoundCloudTrackUrl(track);
  if (!directUrl) return "";
  const params = new URLSearchParams({
    url: directUrl,
    color: "#66d8ff",
    auto_play: autoplay ? "true" : "false",
    hide_related: "true",
    show_comments: "false",
    show_user: "true",
    show_reposts: "false",
    show_teaser: "false",
    visual: "false"
  });
  return `https://w.soundcloud.com/player/?${params.toString()}`;
}

function resetSoundCloudPreviewEmbed({ keepActions = false, track = null } = {}) {
  if (!soundcloudPreviewWrap || !soundcloudPreviewFrame) return;
  soundcloudPreviewWrap.classList.add("hidden");
  if (soundcloudPreviewFrame.getAttribute("src")) {
    soundcloudPreviewFrame.removeAttribute("src");
  }
  if (keepActions && track) {
    syncSoundCloudPreviewActionForTrack(track, { expanded: false });
  } else if (!keepActions) {
    setSoundCloudPreviewActionState({ visible: false, canToggle: false, canSearch: false, expanded: false, href: "" });
  }
}

function showSoundCloudPreviewEmbed(track, { autoplay = false } = {}) {
  if (!soundcloudPreviewWrap || !soundcloudPreviewFrame || !track) return false;
  const embedUrl = buildSoundCloudEmbedUrl(track, { autoplay });
  if (!embedUrl) return false;
  if (soundcloudPreviewFrame.getAttribute("src") !== embedUrl) {
    soundcloudPreviewFrame.setAttribute("src", embedUrl);
  }
  soundcloudPreviewWrap.classList.remove("hidden");
  syncSoundCloudPreviewActionForTrack(track, { expanded: true });
  return true;
}

function buildBandcampEmbedUrl(track) {
  const trackId = bandcampTrackIdForEmbed(track);
  if (!trackId) return "";
  return `https://bandcamp.com/EmbeddedPlayer/v=2/track=${trackId}/size=large/bgcol=0b1220/linkcol=66d8ff/tracklist=false/artwork=small/transparent=true/`;
}

function resetBandcampPreviewEmbed({ keepActions = false, track = null } = {}) {
  if (!bandcampPreviewWrap || !bandcampPreviewFrame) return;
  bandcampPreviewWrap.classList.add("hidden");
  if (bandcampPreviewFrame.getAttribute("src")) {
    bandcampPreviewFrame.removeAttribute("src");
  }
  if (keepActions && track) {
    syncBandcampPreviewActionForTrack(track, { expanded: false });
  } else if (!keepActions) {
    setBandcampPreviewActionState({ visible: false, canToggle: false, expanded: false });
  }
}

function showBandcampPreviewEmbed(track) {
  if (!bandcampPreviewWrap || !bandcampPreviewFrame || !track) return false;
  const embedUrl = buildBandcampEmbedUrl(track);
  if (!embedUrl) return false;
  if (bandcampPreviewFrame.getAttribute("src") !== embedUrl) {
    bandcampPreviewFrame.setAttribute("src", embedUrl);
  }
  bandcampPreviewWrap.classList.remove("hidden");
  syncBandcampPreviewActionForTrack(track, { expanded: true });
  return true;
}

function showYouTubePreviewEmbed(track, { autoplay = false, attempt = 0 } = {}) {
  if (!youtubePreviewWrap || !youtubePreviewFrame || !track) return false;
  const embedUrl = buildYouTubeEmbedUrl(track, { autoplay, attempt });
  if (!embedUrl) return false;
  if (youtubePreviewFrame.getAttribute("src") !== embedUrl) {
    youtubePreviewFrame.setAttribute("src", embedUrl);
  }
  youtubePreviewWrap.classList.remove("hidden");
  return true;
}

function previewSourceListLabel(sources = []) {
  const unique = [...new Set(sources.map((source) => String(source || "").trim()).filter(Boolean))];
  return unique.join(" + ");
}

function fixedPreviewStatusMessage({ audioReady = false, sources = [], fallbackKey = "" } = {}) {
  const sourceLabel = previewSourceListLabel(sources);
  if (sourceLabel) {
    return audioReady
      ? t("previewAudioWithFixedSources", { sources: sourceLabel })
      : t("previewFixedSources", { sources: sourceLabel });
  }
  return fallbackKey ? t(fallbackKey) : t("previewReady");
}

function showFixedPreviewPlayers(track, {
  includeYoutubeSearch = false,
  autoplayYoutube = false,
  autoplaySoundCloud = false
} = {}) {
  const sources = [];
  const hasDirectYoutube = trackHasDirectYouTubeVideo(track);
  const canRetryYoutube = youtubePreviewCanRetry(track);
  const youtubeAttempt = hasDirectYoutube ? 0 : youtubePreviewSearchAttempt;

  const soundcloudReady = trackHasDirectSoundCloudTrack(track)
    ? showSoundCloudPreviewEmbed(track, { autoplay: autoplaySoundCloud })
    : false;
  if (soundcloudReady) {
    sources.push("SoundCloud");
  } else {
    syncSoundCloudPreviewActionForTrack(track, { expanded: false });
  }

  const bandcampReady = showBandcampPreviewEmbed(track);
  if (bandcampReady) {
    sources.push("Bandcamp");
  } else {
    syncBandcampPreviewActionForTrack(track, { expanded: false });
  }

  const shouldShowYoutube = hasDirectYoutube;
  const youtubeReady = shouldShowYoutube
    ? showYouTubePreviewEmbed(track, { autoplay: autoplayYoutube, attempt: youtubeAttempt })
    : false;
  if (youtubeReady) sources.push("YouTube");

  setYouTubePreviewActionState({
    visible: hasDirectYoutube,
    canToggle: hasDirectYoutube,
    canRetry: canRetryYoutube,
    expanded: youtubeReady
  });

  return {
    sources,
    soundcloudReady,
    bandcampReady,
    youtubeReady,
    anyReady: Boolean(soundcloudReady || bandcampReady || youtubeReady)
  };
}

function artistOriginLookupKeys(artistName = "") {
  const raw = String(artistName || "").replace(/\([^)]*\)/g, " ").replace(/\s+/g, " ").trim();
  const direct = normalize(raw);
  if (!direct) return [];
  const keys = [direct];
  [
    /\s+(?:feat\.?|ft\.?|featuring)\s+/i,
    /\s+(?:&|x|vs\.?|versus)\s+/i,
    /\s*\+\s*/i,
    /\s*,\s*/i
  ].forEach((splitter) => {
    const primary = raw.split(splitter)[0]?.trim();
    const key = normalize(primary);
    if (key && !keys.includes(key)) keys.push(key);
  });
  return keys;
}

function canonicalOriginForArtist(artistName) {
  const keys = artistOriginLookupKeys(artistName);
  for (const key of keys) {
    if (ARTIST_CANONICAL_ORIGINS[key]) return ARTIST_CANONICAL_ORIGINS[key];
    const normalizedMatch = Object.entries(ARTIST_CANONICAL_ORIGINS).find(
      ([originKey]) => normalize(originKey) === key
    );
    if (normalizedMatch) return normalizedMatch[1];
  }
  return null;
}

function applyCanonicalOriginToProfile(artistName, profile) {
  const canonical = canonicalOriginForArtist(artistName);
  if (!canonical) return profile;
  const merged = {
    ...(profile || {}),
    country: canonical.country || profile?.country || "",
    area: canonical.area || profile?.area || "",
    disambiguation: canonical.disambiguation || profile?.disambiguation || ""
  };
  const sources = Array.isArray(merged.sources) ? [...merged.sources] : [];
  if (!sources.includes("CuratedOrigin")) sources.push("CuratedOrigin");
  merged.sources = sources;
  return merged;
}

function youtubeLinkTrusted(track) {
  if (!track) return false;
  if (track.youtubeVerified === true) return true;
  if (isDirectYouTubeUrl(track.youtubeTrackUrl)) return true;
  if (isDirectYouTubeUrl(track.youtubeUrl)) return true;
  return Boolean(buildYouTubeTrackLink(track));
}

function soundCloudLinkTrusted(track) {
  if (!track) return false;
  if (track.soundcloudVerified === true) return true;
  if (track.soundcloudTrackUrl || track.soundcloudUrl) return true;
  return Boolean(buildSoundCloudTrackLink(track));
}

function bandcampLinkTrusted(track) {
  if (!track) return false;
  if (track.bandcampTrackUrl || track.bandcampUrl) return true;
  return false;
}

function isGenericArtistBioText(rawText = "") {
  const text = normalize(rawText || "");
  if (!text) return true;
  return [
    "apareceu na busca dinamica",
    "appears in the",
    "aparece como destacado",
    "complete com origem",
    "fill in origin",
    "ver fontes",
    "see sources",
    "bpm guia",
    "bpm guide",
    "entrou no radar",
    "pista nova dentro",
    "use esta faixa",
    "porta de entrada",
    "garimpei esta faixa",
    "faixa localizada via",
    "catálogo dinâmico",
    "catalogo dinamico"
  ].some((signal) => text.includes(normalize(signal)));
}

function meaningfulArtistBioText(rawText = "", minLength = 36) {
  const text = normalizeInlineText(rawText);
  if (!text || text.length < minLength) return "";
  if (isGenericArtistBioText(text)) return "";
  return text;
}

function localizedArtistNarrativeFallback(track) {
  const safeTrack = {
    song: track?.song || "Track",
    artist: track?.artist || "Artist",
    label: track?.label || "Catalogo",
    style: track?.style || "house"
  };
  const style = styleLabelByValue(safeTrack.style);
  const label = sanitizeLabel(safeTrack.label, safeTrack.artist, safeTrack.song);
  const origin = artistOriginSignalForTrack(track);
  const originLabel = formatArtistOriginLabel(origin);
  const canonical = canonicalOriginForArtist(safeTrack.artist);
  const genre = String(track?.artistGenre || localizedArtistGenreHint(safeTrack.artist, safeTrack.style) || "").trim();
  const hint = String(track?.artistProfileHint || "").trim();
  const styleSummary = styleInfoSummaryByLanguage(safeTrack.style);
  const identity = meaningfulArtistBioText(canonical?.disambiguation || "", 20) ||
    meaningfulArtistBioText(hint, 36) ||
    meaningfulArtistBioText(track?.artistBio || "", 45);
  const knownLabel = isUnknownLabel(label);
  const genreOrStyle = genre || style;
  const artistName = safeTrack.artist;
  const songLine = safeTrack.song ? `"${safeTrack.song}"` : "";
  if (currentLanguage === "en") {
    const identityLine = identity || `${artistName} is connected to ${genreOrStyle}.`;
    const originLine = originLabel ? `Origin: ${originLabel}.` : "Origin: not confirmed in the local catalog yet.";
    const catalogLine = knownLabel
      ? "Albums, formation year, and festival history still need a reliable source before the app states them as facts."
      : `Catalog trail: start with ${label}, then check Discogs or the artist links for albums, aliases, and live history.`;
    const entryLine = songLine ? `Track entry here: ${songLine}.` : "";
    return `${identityLine} ${originLine} Sound lane: ${genreOrStyle}; ${styleSummary} ${entryLine} ${catalogLine}`.trim();
  }
  if (currentLanguage === "es") {
    const identityLine = identity || `${artistName} está conectado con ${genreOrStyle}.`;
    const originLine = originLabel ? `Origen: ${originLabel}.` : "Origen: aún no confirmado en el catálogo local.";
    const catalogLine = knownLabel
      ? "Álbumes, año de formación e historial de festivales todavía necesitan una fuente fiable antes de aparecer como hechos."
      : `Ruta de catálogo: empieza por ${label} y sigue en Discogs o en los enlaces del artista para álbumes, alias e historial en vivo.`;
    const entryLine = songLine ? `Pista de entrada aquí: ${songLine}.` : "";
    return `${identityLine} ${originLine} Línea sonora: ${genreOrStyle}; ${styleSummary} ${entryLine} ${catalogLine}`.trim();
  }
  const identityLine = identity || `${artistName} e um nome/projeto ligado a ${genreOrStyle}.`;
  const originLine = originLabel ? `Origem: ${originLabel}.` : "Origem: ainda nao confirmada no catalogo local.";
  const catalogLine = knownLabel
    ? "Albuns, ano de formacao e historico de festivais ainda precisam de fonte confiavel antes de aparecerem como fato."
    : `Trilha de catalogo: comece pela gravadora ${label} e siga no Discogs ou nos links do artista para ver albuns, aliases e historico ao vivo.`;
  const entryLine = songLine ? `Faixa de entrada aqui: ${songLine}.` : "";
  return `${identityLine} ${originLine} Linha sonora: ${genreOrStyle}; ${styleSummary} ${entryLine} ${catalogLine}`.trim();
}

function detailedArtistBio(track) {
  const key = normalize(track?.artist || "");
  const profile = ARTIST_EXTENDED_PROFILES[key];
  if (profile) {
    return humanizeStructuredBioText(profile[currentLanguage] || profile.pt || localizedArtistNarrativeFallback(track), track);
  }

  const sourceBio = String(track?.artistBio || "").trim();
  const isGenericDynamicBio = isGenericArtistBioText(sourceBio);
  if (sourceBio && sourceBio.length > 80 && !isGenericDynamicBio) {
    return `${humanizeStructuredBioText(sourceBio, track)} ${localizedArtistNarrativeFallback(track)}`.trim();
  }
  return localizedArtistNarrativeFallback(track);
}

function activeRecommendationKey() {
  return recommendationTrackKey(currentRecommendation);
}

function trackStillActive(track) {
  const activeKey = activeRecommendationKey();
  const trackKey = recommendationTrackKey(track);
  return Boolean(activeKey && trackKey && activeKey === trackKey);
}

function renderArtistHub(track, { hydrate = true } = {}) {
  if (!track) return;
  if (detailsPanel) detailsPanel.dataset.trackKey = recommendationTrackKey(track);
  if (artistBio) {
    artistBio.textContent = detailedArtistBio(track);
    if (artistBioAiMeta) {
      artistBioAiMeta.textContent = t("artistBioLocalSource");
      artistBioAiMeta.classList.remove("hidden");
    }
  }
  renderDiscogsArtistPanel(track);
  renderArtistSocialLinks(track);
  if (labelBio) {
    labelBio.textContent = detailedLabelBio(track);
  }
  if (hydrate && artistBio && trackStillActive(track)) {
    void hydrateArtistBioFromApis(track);
    void hydrateArtistBioFromAi(track);
  }
}

function supportsArtistBioApi() {
  return aiTextEnabled() && Boolean(resolveAiEndpoint("NEONPULSE_ARTIST_BIO_URL", "/api/artist-bio"));
}

function artistBioAiCacheKey(track) {
  const trackKey = recommendationTrackKey(track) || normalize(`${track?.artist || ""}::${track?.song || ""}`);
  if (!trackKey) return "";
  return `verified-v2|${currentLanguage}|${trackKey}|${normalize(track?.style || "")}|${normalize(track?.label || "")}`;
}

function artistBioApiSourceCandidates(track) {
  const artist = encodeURIComponent(sanitizeArtistLookupName(track?.artist || ""));
  const candidates = [
    { name: "MusicBrainz", url: artist ? `https://musicbrainz.org/search?query=${artist}&type=artist` : "" },
    { name: "Discogs", url: artist ? `https://www.discogs.com/search/?q=${artist}&type=artist` : "" },
    { name: "SoundCloud", url: artist ? `https://soundcloud.com/search?q=${artist}` : "" },
    { name: "YouTube", url: artist ? `https://www.youtube.com/results?search_query=${artist}` : "" }
  ];
  if (track?.spotifyUrl) candidates.push({ name: "Spotify", url: track.spotifyUrl });
  if (track?.bandcampUrl || track?.bandcampTrackUrl) candidates.push({ name: "Bandcamp", url: track.bandcampTrackUrl || track.bandcampUrl });
  return candidates.filter((source) => source.name);
}

function buildArtistBioAiPayload(track) {
  const bpmData = resolveBpmDisplay(track || {});
  const origin = artistOriginSignalForTrack(track);
  const originLabel = origin
    ? [origin.area, origin.country].filter(Boolean).join(", ")
    : "";
  const styleSummary = styleInfoSummaryByLanguage(track?.style || "");
  const contextLabel = lastPrefs?.context ? contextLabelByValue(lastPrefs.context) : t("freeContext");
  return {
    language: currentLanguage,
    track: {
      artist: track?.artist || "",
      song: track?.song || "",
      style: track?.style || "",
      styleLabel: styleLabelByValue(track?.style || ""),
      label: sanitizeLabel(track?.label || "", track?.artist || "", track?.song || ""),
      bpm: bpmData.aiText || "",
      energy: energyLabelByValue(track?.energy || ""),
      origin: originLabel,
      genre: track?.artistGenre || localizedArtistGenreHint(track?.artist || "", track?.style || "") || "",
      currentBio: artistBio?.textContent || detailedArtistBio(track),
      profileHint: track?.artistProfileHint || track?.vibe || "",
      styleSummary,
      recommendationContext: `${contextLabel}. ${buildListeningNarrative(track, lastPrefs || {})}`
    },
    sources: artistBioApiSourceCandidates(track)
  };
}

async function requestArtistBioFromApi(track) {
  const endpoint = resolveAiEndpoint("NEONPULSE_ARTIST_BIO_URL", "/api/artist-bio");
  if (!endpoint || !track || !aiTextEnabled()) return null;
  const cacheKey = artistBioAiCacheKey(track);
  const cached = cacheKey ? aiTextCacheGet("artist-bio", cacheKey) : null;
  if (cached?.bio) return cached;
  if (!canRequestAiText()) return null;
  const token = String(window?.NEONPULSE_ARTIST_BIO_TOKEN || "").trim();
  const headers = {
    "Content-Type": "application/json",
    Accept: "application/json"
  };
  if (token) headers.Authorization = `Bearer ${token}`;

  const controller = typeof AbortController !== "undefined" ? new AbortController() : null;
  let timeoutId = 0;
  try {
    if (controller) timeoutId = window.setTimeout(() => controller.abort(), 45000);
    const response = await fetch(endpoint, {
      method: "POST",
      headers,
      body: JSON.stringify(buildArtistBioAiPayload(track)),
      signal: controller?.signal
    });
    if (!response.ok) return null;
    const payload = await response.json();
    const bio = String(payload?.bio || "").trim();
    if (!bio) return null;
    recordAiTextCall();
    const result = {
      bio: bio.slice(0, 900),
      sourceSummary: String(payload?.sourceSummary || "").trim(),
      sources: Array.isArray(payload?.sources) ? payload.sources : [],
      verification: payload?.verification && typeof payload.verification === "object" ? payload.verification : null,
      confidence: String(payload?.confidence || "").trim(),
      origin: String(payload?.origin || "").trim(),
      genre: String(payload?.genre || "").trim()
    };
    if (cacheKey) aiTextCacheSet("artist-bio", cacheKey, result);
    return result;
  } catch (_error) {
    return null;
  } finally {
    if (timeoutId) window.clearTimeout(timeoutId);
  }
}

function sanitizeArtistLookupName(artistName) {
  return String(artistName || "")
    .replace(/\([^)]*\)/g, " ")
    .replace(/\b(ft|feat|featuring|vs)\b.*$/i, " ")
    .replace(/\s+/g, " ")
    .trim();
}

const BIO_LANGUAGE_SIGNAL_WORDS = {
  pt: new Set(["de", "do", "da", "dos", "das", "com", "para", "uma", "um", "foi", "desde", "origem", "contexto", "fontes"]),
  en: new Set(["the", "and", "from", "is", "was", "with", "for", "project", "group", "formed", "sources", "origin", "context"]),
  es: new Set(["de", "del", "la", "el", "con", "para", "una", "un", "fue", "desde", "origen", "contexto", "fuentes"])
};

function detectBioTextLanguage(text) {
  const normalized = normalize(text || "");
  if (!normalized) return "";
  const tokens = normalized.split(/[^a-z0-9]+/).filter(Boolean);
  if (!tokens.length) return "";

  const scores = {
    pt: 0,
    en: 0,
    es: 0
  };
  tokens.forEach((token) => {
    if (BIO_LANGUAGE_SIGNAL_WORDS.pt.has(token)) scores.pt += 1;
    if (BIO_LANGUAGE_SIGNAL_WORDS.en.has(token)) scores.en += 1;
    if (BIO_LANGUAGE_SIGNAL_WORDS.es.has(token)) scores.es += 1;
  });

  const ranked = Object.entries(scores).sort((a, b) => b[1] - a[1]);
  const [topLang, topScore] = ranked[0];
  const secondScore = ranked[1]?.[1] || 0;
  if (topScore < 2) return "";
  if (topScore <= secondScore) return "";
  return topLang;
}

function textMatchesCurrentBioLanguage(text) {
  if (!text) return true;
  if (currentLanguage === "en") return true;
  const detected = detectBioTextLanguage(text);
  if (!detected) return true;
  return detected === currentLanguage;
}

function wikipediaLanguagePriority(preferredLanguage = currentLanguage) {
  if (preferredLanguage === "pt") return ["pt", "en"];
  if (preferredLanguage === "es") return ["es", "en"];
  return ["en"];
}

