    tracksPresented: Math.max(0, Number(seenTrackKeysMemory?.size) || 0),
    knownArtists: Math.max(0, Number(knownUnion.size) || 0),
    ratingCount: Math.max(0, Number(userStats.ratingCount) || 0),
