async function buildSpiritStoryShareVideo({
  baseImageDataUrl = "",
  spiritImageDataUrl = "",
  spiritText = {},
  snapshot = {},
  likes = 0,
  milestoneLikes = 0,
  detailsLine = "",
  genreSummary = null
} = {}) {
  const safeBaseImage = String(baseImageDataUrl || "").trim();
  const safeSpiritImage = String(spiritImageDataUrl || "").trim();
  if (!safeBaseImage && !safeSpiritImage) return null;
  if (
    typeof window === "undefined" ||
    typeof document === "undefined" ||
    typeof window.MediaRecorder !== "function" ||
    typeof HTMLCanvasElement === "undefined" ||
    typeof HTMLCanvasElement.prototype.captureStream !== "function"
  ) {
    return null;
  }

  let baseImage = null;
  if (safeBaseImage) {
    try {
      baseImage = await loadImageElementFromSource(safeBaseImage);
    } catch (_err) {
      baseImage = null;
    }
  }

  let spiritImage = null;
  if (safeSpiritImage) {
    try {
      spiritImage = await loadImageElementFromSource(safeSpiritImage);
    } catch (_err) {
      spiritImage = null;
    }
  }
  const heroImage = spiritImage || baseImage;
  if (!heroImage) return null;

  const mimeCandidates = [
    "video/mp4;codecs=h264",
    "video/mp4",
    "video/webm;codecs=vp9",
    "video/webm;codecs=vp8",
    "video/webm"
  ];
  let selectedMime = "";
  if (typeof window.MediaRecorder.isTypeSupported === "function") {
    selectedMime = mimeCandidates.find((candidate) => {
      try {
        return window.MediaRecorder.isTypeSupported(candidate);
      } catch (_err) {
        return false;
      }
    }) || "";
  }

  const canvas = document.createElement("canvas");
  canvas.width = STORY_SHARE_WIDTH;
  canvas.height = STORY_SHARE_HEIGHT;
  const ctx = canvas.getContext("2d");
  if (!ctx) return null;

  const stream = canvas.captureStream(30);
  const chunks = [];
  const stopPromise = new Promise((resolve) => {
    let recorder;
    try {
      recorder = selectedMime
        ? new window.MediaRecorder(stream, { mimeType: selectedMime, videoBitsPerSecond: 7000000 })
        : new window.MediaRecorder(stream, { videoBitsPerSecond: 7000000 });
    } catch (_err) {
      resolve(null);
      return;
    }

    recorder.ondataavailable = (event) => {
      if (event?.data?.size) chunks.push(event.data);
    };
    recorder.onerror = () => resolve(null);
    recorder.onstop = () => resolve(recorder.mimeType || selectedMime || "video/webm");

    try {
      recorder.start(220);
    } catch (_err) {
      resolve(null);
      return;
    }

    const rankLabel = t(resolveSpiritRank(likes).current.key);
    const storyTitle = t("spiritCollectibleShareStoryTitle");
    const spiritTitle = spiritText?.name || "Sonic Spirit";
    const spiritSub = spiritText?.archetype || "";
    const spiritTitleLines = splitIntoSvgLines(spiritTitle, 20, 2);
    const spiritSubLines = splitIntoSvgLines(spiritSub, 34, 2);
    const statusLine = buildSpiritShareStatusLine(snapshot);
    const statusLines = splitIntoSvgLines(statusLine, 48, 2);
    const detailText = normalizeInlineText(detailsLine);
    const detailLines = splitIntoSvgLines(detailText, 48, 2);
    const genreHeadline = normalizeInlineText(genreSummary?.headline || "");
    const genreNarrative = normalizeInlineText(genreSummary?.narrative || "");
    const genreHeadlineLine = splitIntoSvgLines(genreHeadline, 48, 1);
    const genreNarrativeLines = splitIntoSvgLines(genreNarrative, 48, 2);
    const symbols = ["☠", "⚡", "🔊", "🎛", "▁▃▆█", "▂▄▇"];
    const startedAt = (typeof performance !== "undefined" && typeof performance.now === "function")
      ? performance.now()
      : Date.now();
    const durationMs = 5000;

    const drawFrame = (elapsedMs) => {
      const elapsed = Math.max(0, elapsedMs) / 1000;
      const pulse = 0.5 + 0.5 * Math.sin(elapsed * 3.2);
      const floatY = Math.sin(elapsed * 2.4) * 13;
      const tilt = Math.sin(elapsed * 1.9) * 0.033;

      const bg = ctx.createLinearGradient(0, 0, STORY_SHARE_WIDTH, STORY_SHARE_HEIGHT);
      bg.addColorStop(0, "#050a1e");
      bg.addColorStop(0.5, "#0b2145");
      bg.addColorStop(1, "#27124a");
      ctx.fillStyle = bg;
      ctx.fillRect(0, 0, STORY_SHARE_WIDTH, STORY_SHARE_HEIGHT);

      const glow = ctx.createRadialGradient(200, 180, 90, 260, 230, 760);
      glow.addColorStop(0, "rgba(105, 255, 224, 0.42)");
      glow.addColorStop(1, "rgba(105, 255, 224, 0)");
      ctx.fillStyle = glow;
      ctx.fillRect(0, 0, STORY_SHARE_WIDTH, STORY_SHARE_HEIGHT);

      const heroPanel = ctx.createLinearGradient(64, 116, 1016, 1144);
      heroPanel.addColorStop(0, "rgba(5, 16, 38, 0.9)");
      heroPanel.addColorStop(1, "rgba(10, 34, 74, 0.64)");
      ctx.fillStyle = heroPanel;
      canvasRoundedRectPath(ctx, 64, 116, 952, 1028, 46);
      ctx.fill();
      ctx.strokeStyle = "rgba(122, 226, 255, 0.62)";
      ctx.lineWidth = 3;
      canvasRoundedRectPath(ctx, 64, 116, 952, 1028, 46);
      ctx.stroke();

      if (baseImage) {
        ctx.save();
        canvasRoundedRectPath(ctx, 64, 116, 952, 1028, 46);
        ctx.clip();
        ctx.globalAlpha = 0.16;
        drawImageCover(ctx, baseImage, 64, 116, 952, 1028);
        ctx.globalAlpha = 1;
        ctx.restore();
      }

      const halo = ctx.createRadialGradient(540, 616, 80, 540, 616, 408);
      halo.addColorStop(0, "rgba(111, 255, 226, 0.34)");
      halo.addColorStop(1, "rgba(111, 255, 226, 0)");
      ctx.fillStyle = halo;
      ctx.beginPath();
      ctx.arc(540, 616, 388, 0, Math.PI * 2);
      ctx.fill();

      ctx.save();
      canvasRoundedRectPath(ctx, 122, 214, 836, 836, 42);
      ctx.clip();
      ctx.fillStyle = "rgba(7, 20, 47, 0.74)";
      ctx.fillRect(122, 214, 836, 836);
      ctx.restore();
      const heroStroke = ctx.createLinearGradient(122, 214, 958, 1050);
      heroStroke.addColorStop(0, "rgba(115,255,226,0.72)");
      heroStroke.addColorStop(1, "rgba(123,196,255,0.45)");
      ctx.strokeStyle = heroStroke;
      ctx.lineWidth = 2.4;
      canvasRoundedRectPath(ctx, 122, 214, 836, 836, 42);
      ctx.stroke();

      const skullBaseX = 540;
      const skullBaseY = 632 + floatY;
      const skullSize = 812 + pulse * 10;
      ctx.save();
      ctx.translate(skullBaseX, skullBaseY);
      ctx.rotate(tilt);
      const skullGlow = ctx.createRadialGradient(0, 0, 20, 0, 0, 360 + pulse * 30);
      skullGlow.addColorStop(0, "rgba(126, 255, 231, 0.48)");
      skullGlow.addColorStop(1, "rgba(126, 255, 231, 0)");
      ctx.fillStyle = skullGlow;
      ctx.beginPath();
      ctx.arc(0, 0, 356 + pulse * 24, 0, Math.PI * 2);
      ctx.fill();
      const skullX = -skullSize / 2;
      const skullY = -skullSize / 2;
      canvasRoundedRectPath(ctx, skullX, skullY, skullSize, skullSize, 40);
      ctx.clip();
      if (spiritImage) {
        drawImageContain(ctx, spiritImage, skullX, skullY, skullSize, skullSize, 26);
      } else if (baseImage) {
        drawImageCover(ctx, baseImage, skullX, skullY, skullSize, skullSize);
      } else {
        ctx.fillStyle = "#0a1730";
        ctx.fillRect(skullX, skullY, skullSize, skullSize);
        ctx.fillStyle = "#dcf8ff";
        ctx.font = "700 220px Chakra Petch, Arial, sans-serif";
        ctx.textAlign = "center";
        ctx.fillText("☠", 0, 76);
      }
      ctx.restore();

      ctx.strokeStyle = "rgba(112, 255, 228, 0.34)";
      ctx.lineWidth = 4;
      ctx.beginPath();
      ctx.arc(540, 632, 350, 0, Math.PI * 2);
      ctx.stroke();
      ctx.strokeStyle = "rgba(106, 157, 255, 0.34)";
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.arc(540, 632, 272, 0, Math.PI * 2);
      ctx.stroke();
      ctx.strokeStyle = "rgba(133, 78, 255, 0.26)";
      ctx.lineWidth = 2.4;
      ctx.beginPath();
      ctx.arc(540, 632, 196, 0, Math.PI * 2);
      ctx.stroke();

      for (let i = 0; i < 8; i += 1) {
        const barHeight = 26 + Math.abs(Math.sin(elapsed * 4 + i * 0.86)) * 82;
        const x = 318 + i * 50;
        const y = 1058 - barHeight;
        const barGradient = ctx.createLinearGradient(x, y, x, 1058);
        barGradient.addColorStop(0, "rgba(125, 246, 255, 0.95)");
        barGradient.addColorStop(1, "rgba(125, 246, 255, 0.42)");
        ctx.fillStyle = barGradient;
        canvasRoundedRectPath(ctx, x, y, 34, barHeight, 10);
        ctx.fill();
      }

      ctx.fillStyle = "#7adfff";
      ctx.font = "700 30px Chakra Petch, Arial, sans-serif";
      ctx.textAlign = "left";
      ctx.fillText(`${rankLabel} • ${milestoneLikes} likes`, 104, 1098);

      symbols.forEach((symbol, index) => {
        const x = 754 + Math.sin(elapsed * 0.9 + index * 0.82) * 146;
        const y = 272 + index * 118 + Math.cos(elapsed * 1.2 + index) * 24;
        const alpha = 0.18 + 0.24 * (0.5 + 0.5 * Math.sin(elapsed * 1.4 + index));
        ctx.globalAlpha = alpha;
        ctx.fillStyle = "#95dfff";
        ctx.font = `${38 - index * 3}px Chakra Petch, Arial, sans-serif`;
        ctx.fillText(symbol, x, y);
      });
      ctx.globalAlpha = 1;

      const panel = ctx.createLinearGradient(64, 1188, 1016, 1816);
      panel.addColorStop(0, "rgba(7, 18, 40, 0.94)");
      panel.addColorStop(1, "rgba(9, 28, 56, 0.84)");
      ctx.fillStyle = panel;
      canvasRoundedRectPath(ctx, 64, 1148, 952, 708, 42);
      ctx.fill();
      ctx.strokeStyle = "rgba(122, 222, 255, 0.56)";
      ctx.lineWidth = 2;
      canvasRoundedRectPath(ctx, 64, 1148, 952, 708, 42);
      ctx.stroke();

      ctx.fillStyle = "#9fd8ff";
      ctx.font = "700 40px Chakra Petch, Arial, sans-serif";
      ctx.fillText(storyTitle, 104, 1236);
      ctx.fillStyle = "#f1fbff";
      ctx.font = "700 64px Syne, Arial, sans-serif";
      ctx.fillText(spiritTitleLines[0] || "", 104, 1308);
      ctx.fillText(spiritTitleLines[1] || "", 104, 1370);
      ctx.fillStyle = "#bfe9ff";
      ctx.font = "600 34px Chakra Petch, Arial, sans-serif";
      ctx.fillText(spiritSubLines[0] || "", 104, 1426);
      ctx.fillText(spiritSubLines[1] || "", 104, 1468);
      ctx.fillStyle = "#d2ecff";
      ctx.font = "29px Chakra Petch, Arial, sans-serif";
      ctx.fillText(`${milestoneLikes} likes | ${likes} total`, 104, 1524);
      ctx.fillStyle = "#d4ebff";
      ctx.font = "25px Chakra Petch, Arial, sans-serif";
      ctx.fillText(detailLines[0] || "", 104, 1576);
      ctx.fillText(detailLines[1] || "", 104, 1614);
      ctx.fillStyle = "#9ee8ff";
      ctx.font = "25px Chakra Petch, Arial, sans-serif";
      ctx.fillText(genreHeadlineLine[0] || "", 104, 1662);
      ctx.fillStyle = "#d6ecff";
      ctx.font = "24px Chakra Petch, Arial, sans-serif";
      ctx.fillText(genreNarrativeLines[0] || "", 104, 1704);
      ctx.fillText(genreNarrativeLines[1] || "", 104, 1740);
      ctx.fillStyle = "#d7eaff";
      ctx.font = "25px Chakra Petch, Arial, sans-serif";
      ctx.fillText(statusLines[0] || "", 104, 1792);
      ctx.fillText(statusLines[1] || "", 104, 1828);
      ctx.fillStyle = "#82d8ff";
      ctx.font = "24px Chakra Petch, Arial, sans-serif";
      ctx.fillText("Sonic Search • Music Sommelier", 104, 1848);
    };

    const renderLoop = (timestamp) => {
      const elapsed = Number(timestamp || 0) - startedAt;
      drawFrame(elapsed);
      if (elapsed >= durationMs) {
        if (recorder.state !== "inactive") recorder.stop();
        return;
      }
      if (typeof window.requestAnimationFrame === "function") {
        window.requestAnimationFrame(renderLoop);
      } else {
        window.setTimeout(() => renderLoop(Date.now()), 34);
      }
    };

    if (typeof window.requestAnimationFrame === "function") {
      window.requestAnimationFrame(renderLoop);
    } else {
      renderLoop(Date.now());
    }
  });

  const mimeType = await stopPromise;
  stream.getTracks().forEach((track) => track.stop());
  if (!mimeType || !chunks.length) return null;

  const normalizedMime = String(mimeType || "video/webm").split(";")[0] || "video/webm";
  const blob = new Blob(chunks, { type: normalizedMime });
  if (!blob.size) return null;

  return {
    url: URL.createObjectURL(blob),
    mime: normalizedMime,
    extension: normalizedMime.includes("mp4") ? "mp4" : "webm"
  };
}

async function prepareSpiritStoryAsset({ imageUrl = "", baseFilename = "", preferStatic = false } = {}) {
  const safeImageUrl = String(imageUrl || "").trim();
  if (!safeImageUrl || safeImageUrl === "#") return null;

  const likes = totalPositiveLikes();
  const milestone = collectibleMilestoneForLikes(likes);
  const spirit = spiritById(currentSpiritId || "");
  const snapshot = spiritShareProfileSnapshot();
  const spiritText = localizedSpiritCopy(spirit) || buildProfileStoryText(snapshot);
  const genreSummary = spirit ? buildSpiritStoryGenreSummary(spirit) : buildProfileStoryGenreSummary();
  const fallbackDetailsLine = spirit
    ? buildSpiritShareDetailsLine(spirit, spiritText, likes, milestone.likes)
    : buildProfileStoryDetailsLine(snapshot);
  const detailsLine = normalizeInlineText(
    spirit ? spiritCollectibleDetails?.textContent || fallbackDetailsLine : fallbackDetailsLine
  );
  const statusLine = buildSpiritShareStatusLine(snapshot);
  const spiritImageSource = resolveRuntimeAssetUrl(spirit?.image || "");
  const { mime: spiritMime } = collectibleImageMeta(spiritImageSource);
  const spiritImageDataUrl = await collectibleImageAsDataUrl(spiritImageSource, spiritMime);
  const { mime } = collectibleImageMeta(safeImageUrl);
  const sourceImageDataUrl = await collectibleImageAsDataUrl(safeImageUrl, mime);
  const storyVideo = preferStatic
    ? null
    : await buildSpiritStoryShareVideo({
      baseImageDataUrl: sourceImageDataUrl || safeImageUrl,
      spiritImageDataUrl,
      spiritText,
      snapshot,
      likes,
      milestoneLikes: milestone.likes,
      detailsLine,
      genreSummary
    });
  const shareCaption = t("spiritCollectibleShareCaption", {
    spirit: spiritText?.name || t("spiritBadge")
  });
  const shareText = [shareCaption, detailsLine, genreSummary?.headline, genreSummary?.narrative, statusLine]
    .filter(Boolean)
    .join("\n");

  if (storyVideo?.url && storyVideo?.mime) {
    return {
      storyAssetUrl: storyVideo.url,
      storyAssetMime: storyVideo.mime,
      filename: spiritStoryFilename(baseFilename, storyVideo.extension || "webm"),
      shareText,
      animated: true
    };
  }

  const storyImageUrl =
    buildSpiritStoryShareImage(
      sourceImageDataUrl || safeImageUrl,
      spiritImageDataUrl,
      spiritText,
      snapshot,
      likes,
      milestone.likes,
      detailsLine,
      genreSummary
    ) ||
    sourceImageDataUrl ||
    safeImageUrl;

  const storyImagePng = await renderImageDataUrlToPng(
    storyImageUrl,
    STORY_SHARE_WIDTH,
    STORY_SHARE_HEIGHT
  );
  const fallbackPng = storyImagePng
    ? ""
    : await renderImageDataUrlToPng(
      sourceImageDataUrl || safeImageUrl,
      STORY_SHARE_WIDTH,
      STORY_SHARE_HEIGHT
    );
  const storyAssetUrl = storyImagePng || fallbackPng || storyImageUrl;
  const filename = spiritStoryFilename(baseFilename, "png");

  return {
    storyAssetUrl,
    storyAssetMime: "image/png",
    filename,
    shareText,
    animated: false
  };
}

function profileStoryFallbackImageUrl() {
  return resolveRuntimeAssetUrl(SPIRIT_COLLECTIBLE_FALLBACK);
}

function resolveStoryShareImageUrl(preferredImageUrl = "") {
  const candidates = [
    preferredImageUrl,
    spiritCollectibleShareInstagramBtn?.dataset.imageUrl,
    spiritCollectibleImage?.getAttribute("src"),
    spiritCollectibleDownload?.getAttribute("href"),
    profileStoryFallbackImageUrl()
  ];
  for (const candidate of candidates) {
    const value = String(candidate || "").trim();
    if (value && value !== "#") return value;
  }
  return "";
}

function resolveStoryShareBaseFilename(imageUrl = "", preferredFilename = "") {
  const safeFilename = String(preferredFilename || "").trim();
  if (safeFilename) return safeFilename;
  return String(
    spiritCollectibleDownload?.getAttribute("download") ||
      spiritCollectibleShareInstagramBtn?.dataset.filename ||
      spiritCollectibleFilename(
        currentSpiritId || "status",
        collectibleMilestoneForLikes(totalPositiveLikes()).likes,
        imageUrl
      )
  );
}

function resetStoryShareButtonLabel(button) {
  if (!button) return;
  button.textContent = button === summaryShareInstagramBtn
    ? t("summaryShareStoryBtn")
    : t("spiritCollectibleShareInstagram");
}

function restoreStoryShareButtons() {
  if (summaryShareInstagramBtn) {
    summaryShareInstagramBtn.disabled = false;
    resetStoryShareButtonLabel(summaryShareInstagramBtn);
  }
  if (spiritCollectibleShareInstagramBtn) {
    const imageIsReady = spiritCollectibleImage?.dataset.assetReady === "true";
    const collectibleImageUrl = String(
      spiritCollectibleShareInstagramBtn.dataset.imageUrl ||
        spiritCollectibleDownload?.getAttribute("href") ||
        (imageIsReady ? spiritCollectibleImage?.getAttribute("src") : "") ||
        ""
    ).trim();
    const hasCollectibleAsset = Boolean(
      collectibleImageUrl && collectibleImageUrl !== "#"
    );
    spiritCollectibleShareInstagramBtn.disabled = !hasCollectibleAsset;
    resetStoryShareButtonLabel(spiritCollectibleShareInstagramBtn);
  }
}

function storyShareCacheKey(imageUrl = "", baseFilename = "") {
  const imageSignature = String(hashString(String(imageUrl || ""))).trim();
  return [
    imageSignature,
    String(baseFilename || ""),
    currentLanguage,
    currentSpiritId || "",
    totalPositiveLikes(),
    userStats.likedSongs,
    userStats.likedArtists,
    userStats.alreadyKnew,
    userStats.skipped,
    discoveredArtistsInApp.size,
    seenTrackKeysMemory.size,
    ratingAverageText()
  ].join("::");
}

function isLikelyIosShareTarget() {
  const ua = typeof navigator !== "undefined" ? String(navigator.userAgent || "") : "";
  const platform = typeof navigator !== "undefined" ? String(navigator.platform || "") : "";
  const touchMac = platform === "MacIntel" && typeof navigator !== "undefined" && Number(navigator.maxTouchPoints || 0) > 1;
  return /iPad|iPhone|iPod/i.test(ua) || touchMac;
}

async function prepareStaticStoryShareAsset(imageUrl = "", baseFilename = "", cacheKey = "") {
  const preparedKey = cacheKey || storyShareCacheKey(imageUrl, baseFilename);
  if (spiritStoryPreparedAsset && spiritStoryPreparedKey === preparedKey) return spiritStoryPreparedAsset;
  if (spiritStoryPreparePromise && spiritStoryPreparedKey === preparedKey) return spiritStoryPreparePromise;

  spiritStoryPreparedKey = preparedKey;
  spiritStoryPreparePromise = prepareSpiritStoryAsset({
    imageUrl,
    baseFilename,
    preferStatic: true
  })
    .then(async (asset) => {
      if (asset?.storyAssetUrl) {
        try {
          asset.preparedFile = await storyAssetFileFromPreparedAsset(asset);
        } catch (error) {
          console.warn("Story share file prewarm failed.", error);
        }
      }
      if (spiritStoryPreparedKey === preparedKey) spiritStoryPreparedAsset = asset || null;
      return asset || null;
    })
    .catch((error) => {
      console.warn("Story share prewarm failed.", error);
      if (spiritStoryPreparedKey === preparedKey) spiritStoryPreparedAsset = null;
      return null;
    })
    .finally(() => {
      if (spiritStoryPreparedKey === preparedKey) spiritStoryPreparePromise = null;
    });

  return spiritStoryPreparePromise;
}

function scheduleStorySharePrewarm(imageUrl = "", baseFilename = "", delay = 500) {
  const resolvedImageUrl = resolveStoryShareImageUrl(imageUrl);
  if (!resolvedImageUrl || resolvedImageUrl === "#") return;
  const resolvedBaseFilename = resolveStoryShareBaseFilename(resolvedImageUrl, baseFilename);
  const cacheKey = storyShareCacheKey(resolvedImageUrl, resolvedBaseFilename);
  if (spiritStoryPreparedAsset && spiritStoryPreparedKey === cacheKey) return;
  if (spiritStoryPrepareTimer) window.clearTimeout(spiritStoryPrepareTimer);
  spiritStoryPrepareTimer = window.setTimeout(() => {
    spiritStoryPrepareTimer = 0;
    void prepareStaticStoryShareAsset(resolvedImageUrl, resolvedBaseFilename, cacheKey);
  }, Math.max(0, Number(delay) || 0));
}

async function storyAssetFileFromPreparedAsset(storyAsset) {
  if (storyAsset?.preparedFile) return storyAsset.preparedFile;
  if (!storyAsset?.storyAssetUrl || typeof window.File !== "function") return null;
  const blob = await spiritCollectibleBlobFromUrl(storyAsset.storyAssetUrl, storyAsset.storyAssetMime);
  const fileType = blob.type || storyAsset.storyAssetMime || "image/png";
  const file = new File([blob], storyAsset.filename, { type: fileType });
  storyAsset.preparedFile = file;
  return file;
}

async function tryNativeStoryAssetShare(storyAsset, { includeTextFallback = true } = {}) {
  if (!storyAsset?.storyAssetUrl) return false;
  const canUseNativeFileShare =
    typeof navigator !== "undefined" &&
    typeof navigator.share === "function" &&
    typeof window.File === "function";

  if (!canUseNativeFileShare) return false;

  try {
    let file = storyAsset.preparedFile || null;
    if (!file) file = await storyAssetFileFromPreparedAsset(storyAsset);
    if (!file) return false;
    const canShareFiles =
      typeof navigator.canShare !== "function" || navigator.canShare({ files: [file] });

    if (!canShareFiles) return false;

    // iOS Safari is much more reliable when file sharing uses the minimal payload.
    await navigator.share({ files: [file] });
    return true;
  } catch (error) {
    if (error && error.name === "AbortError") throw error;
    if (!includeTextFallback) return false;
    try {
      let file = storyAsset.preparedFile || null;
      if (!file) file = await storyAssetFileFromPreparedAsset(storyAsset);
      if (!file) return false;
      await navigator.share({
        title: "Sonic Search",
        text: storyAsset.shareText,
        files: [file]
      });
      return true;
    } catch (fallbackError) {
      if (fallbackError && fallbackError.name === "AbortError") throw fallbackError;
    }
    return false;
  }
}

async function shareSpiritCollectibleToInstagram({
  triggerButton = spiritCollectibleShareInstagramBtn,
  imageUrl = "",
  baseFilename = ""
} = {}) {
  if (spiritStoryShareBusy) {
    showToast(t("spiritCollectibleSharePreparing"));
    return;
  }
  if (spiritCollectibleBusy) {
    showToast(t("spiritCollectibleGenerating"));
    return;
  }

  const resolvedImageUrl = resolveStoryShareImageUrl(imageUrl);

  if (!resolvedImageUrl || resolvedImageUrl === "#") {
    showToast(t("spiritCollectibleShareNoAsset"));
    return;
  }

  const resolvedBaseFilename = resolveStoryShareBaseFilename(resolvedImageUrl, baseFilename);
  const cacheKey = storyShareCacheKey(resolvedImageUrl, resolvedBaseFilename);
  const preferredStaticAsset =
    spiritStoryPreparedAsset && spiritStoryPreparedKey === cacheKey
      ? spiritStoryPreparedAsset
      : null;
  spiritStoryShareBusy = true;
  if (summaryShareInstagramBtn) summaryShareInstagramBtn.disabled = true;
  if (spiritCollectibleShareInstagramBtn) spiritCollectibleShareInstagramBtn.disabled = true;
  if (triggerButton) triggerButton.textContent = t("spiritCollectibleSharePreparing");

  const shouldPreferStatic = isLikelyIosShareTarget();
  const storyAsset = preferredStaticAsset || await prepareSpiritStoryAsset({
    imageUrl: resolvedImageUrl,
    baseFilename: resolvedBaseFilename,
    preferStatic: shouldPreferStatic
  });
  if (!storyAsset?.storyAssetUrl) {
    showToast(t("spiritCollectibleShareNoAsset"));
    spiritStoryShareBusy = false;
    restoreStoryShareButtons();
    return;
  }

  try {
    let shared = await tryNativeStoryAssetShare(storyAsset, { includeTextFallback: !shouldPreferStatic });

    if (!shared && storyAsset.animated) {
      const staticStoryAsset = await prepareStaticStoryShareAsset(resolvedImageUrl, resolvedBaseFilename, cacheKey);
      shared = await tryNativeStoryAssetShare(staticStoryAsset, { includeTextFallback: false });
    }

    if (shared) {
      showToast(t("spiritCollectibleShareNativeDone"));
      return;
    }

    scheduleStorySharePrewarm(resolvedImageUrl, resolvedBaseFilename, 0);
    showToast(t("spiritCollectibleShareFallback"));
  } catch (error) {
    const canceled = error && error.name === "AbortError";
    if (canceled) {
      showToast(t("spiritCollectibleShareCanceled"));
      return;
    }
    scheduleStorySharePrewarm(resolvedImageUrl, resolvedBaseFilename, 0);
    showToast(t("spiritCollectibleShareFallback"));
  } finally {
    spiritStoryShareBusy = false;
    restoreStoryShareButtons();
  }
}

function escapeSvgText(value) {
  return String(value || "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

function isStaticPreviewHost() {
  return isLocalStaticPreviewEnvironment();
}

function canUseRelativeApiEndpoint() {
  return ["http:", "https:"].includes(String(window?.location?.protocol || "")) && !isStaticPreviewHost();
}

function resolveAiEndpoint(globalName, fallbackPath) {
  const configured = String(window?.[globalName] || "").trim();
  if (configured) return configured;
  if (globalName === "NEONPULSE_IMAGE_API_URL" && fallbackPath === "/api/spirit-image" && isStaticPreviewHost()) {
    return REMOTE_SPIRIT_IMAGE_API_URL;
  }
  return canUseRelativeApiEndpoint() ? fallbackPath : "";
}

function aiConfigFlag(key, fallback = false) {
  const value = AI_FEATURE_CONFIG?.[key];
  if (typeof value === "boolean") return value;
  if (typeof value === "number") return value > 0;
  const normalized = String(value ?? "").trim().toLowerCase();
  if (!normalized) return Boolean(fallback);
  return ["1", "true", "yes", "on", "enabled"].includes(normalized);
}

function aiConfigInt(key, fallback = 0, min = 0, max = 10000) {
  const parsed = Number.parseInt(String(AI_FEATURE_CONFIG?.[key] ?? ""), 10);
  if (!Number.isFinite(parsed)) return fallback;
  return Math.max(min, Math.min(max, parsed));
}

function aiTodayKey() {
  return new Date().toISOString().slice(0, 10);
}

function aiUsageStoreKey() {
  return storageKeyForSession(AI_USAGE_STORAGE_KEY) || AI_USAGE_STORAGE_KEY;
}

function readAiUsage() {
  const fallback = {
    day: aiTodayKey(),
    textCalls: 0,
    imageCallsByProfile: {}
  };
  try {
    const raw = localStorage.getItem(aiUsageStoreKey());
    const parsed = raw ? JSON.parse(raw) : null;
    if (!parsed || parsed.day !== fallback.day) return fallback;
    return {
      day: fallback.day,
      textCalls: Math.max(0, Number(parsed.textCalls) || 0),
      imageCallsByProfile: parsed.imageCallsByProfile && typeof parsed.imageCallsByProfile === "object"
        ? parsed.imageCallsByProfile
        : {}
    };
  } catch (_err) {
    return fallback;
  }
}

function saveAiUsage(usage) {
  try {
    localStorage.setItem(aiUsageStoreKey(), JSON.stringify(usage || readAiUsage()));
  } catch (_err) {
    // ignore storage failures
  }
}

function aiTextEnabled() {
  return aiConfigFlag("textEnabled", true);
}

function aiPremiumUnlocked() {
  return aiConfigFlag("premiumUnlocked", false);
}

function aiImageEnabled() {
  return aiConfigFlag("imageEnabled", false);
}

function aiTextCallsRemaining() {
  if (!aiTextEnabled()) return 0;
  const limit = aiConfigInt("dailyTextLimit", AI_DEFAULT_CONFIG.dailyTextLimit, 0, 500);
  if (!limit) return Number.POSITIVE_INFINITY;
  return Math.max(0, limit - readAiUsage().textCalls);
}

function canRequestAiText() {
  return aiTextEnabled() && aiTextCallsRemaining() > 0;
}

function recordAiTextCall() {
  const usage = readAiUsage();
  usage.textCalls += 1;
  saveAiUsage(usage);
}

function dailyProductUsageStoreKey() {
  return storageKeyForSession(DAILY_PRODUCT_USAGE_STORAGE_KEY) || DAILY_PRODUCT_USAGE_STORAGE_KEY;
}

function readDailyProductUsage() {
  const fallback = {
    day: aiTodayKey(),
    musicActions: 0,
    musicTrackKeys: {}
  };
  try {
    const raw = localStorage.getItem(dailyProductUsageStoreKey());
    const parsed = raw ? JSON.parse(raw) : null;
    if (!parsed || parsed.day !== fallback.day) return fallback;
    const trackKeys = parsed.musicTrackKeys && typeof parsed.musicTrackKeys === "object"
      ? parsed.musicTrackKeys
      : {};
    return {
      day: fallback.day,
      musicActions: Math.max(0, Number(parsed.musicActions) || 0),
      musicTrackKeys: trackKeys
    };
  } catch (_err) {
    return fallback;
  }
}

function saveDailyProductUsage(usage) {
  try {
    localStorage.setItem(dailyProductUsageStoreKey(), JSON.stringify(usage || readDailyProductUsage()));
  } catch (_err) {
    // ignore storage failures
  }
}

function dailyFreeDiscoveryLimit() {
  return aiConfigInt("dailyFreeDiscoveryLimit", AI_DEFAULT_CONFIG.dailyFreeDiscoveryLimit, 0, 1000);
}

function dailyMusicDiscoveryCount() {
  return readDailyProductUsage().musicActions;
}

function musicDiscoveryPremiumLocked() {
  if (isLocalDevelopmentHost()) return false;
  if (aiPremiumUnlocked()) return false;
  const limit = dailyFreeDiscoveryLimit();
  return Boolean(limit) && dailyMusicDiscoveryCount() >= limit;
}

function premiumDiscoveryLimitMessage() {
  const limit = dailyFreeDiscoveryLimit();
  return t("premiumDiscoveryLimitReached", { limit });
}

function showPremiumDiscoveryLimit() {
  const message = premiumDiscoveryLimitMessage();
  if (feedbackMessage) feedbackMessage.textContent = message;
  showToast(message);
}

function canUseMusicDiscovery() {
  return !musicDiscoveryPremiumLocked();
}

function recordDailyMusicAction(track, source = "discovery") {
  const usage = readDailyProductUsage();
  const trackKey = recommendationTrackKey(track) || normalize(`${track?.artist || ""}::${track?.song || track?.title || ""}`);
  if (trackKey) {
    const entryKey = `track:${trackKey}`;
    if (usage.musicTrackKeys[entryKey]) return;
    usage.musicTrackKeys[entryKey] = source || "music";
  }
  usage.musicActions += 1;
  saveDailyProductUsage(usage);
}

function aiImageProfileKey() {
  return spiritCollectibleUserSignature();
}

function aiImageCallsForProfile() {
  const usage = readAiUsage();
  const profileKey = aiImageProfileKey();
  return Math.max(0, Number(usage.imageCallsByProfile?.[profileKey]) || 0);
}

function hasApiSpiritImageForCurrentProfile() {
  const userSignature = spiritCollectibleUserSignature();
  const store = readSpiritCollectibleStore();
  return Object.values(store).some((item) => (
    item &&
    item.source === "api" &&
    item.userSignature === userSignature
  ));
}

function aiImageLimitForCurrentPlan() {
  if (aiPremiumUnlocked()) {
    return aiConfigInt("premiumImageLimitPerProfile", AI_DEFAULT_CONFIG.premiumImageLimitPerProfile, 0, 1000);
  }
  return aiConfigInt("imageLimitPerProfile", AI_DEFAULT_CONFIG.imageLimitPerProfile, 0, 100);
}

function aiImageLimitReachedForProfile() {
  if (totalPositiveLikes() < PREMIUM_ART_PROMPT_MIN_LIKES) return false;
  const limit = aiImageLimitForCurrentPlan();
  const allowRegeneration = aiConfigFlag("allowImageRegeneration", false);
  if (!limit) return false;
  return aiImageCallsForProfile() >= limit || (!allowRegeneration && hasApiSpiritImageForCurrentProfile());
}

function aiImagePremiumLockedByLimit() {
  return aiImageEnabled() && !aiPremiumUnlocked() && aiImageLimitReachedForProfile();
}

function premiumAvatarLimitMessage() {
  const limit = aiImageLimitForCurrentPlan();
  return t("premiumAvatarLimitReached", { limit });
}

function aiImageAccessUnlockedForRequest() {
  return aiPremiumUnlocked() || !aiImagePremiumLockedByLimit();
}

function canRequestAiImage() {
  return aiImageEnabled() &&
    aiImageAccessUnlockedForRequest() &&
    !aiImageLimitReachedForProfile() &&
    Boolean(resolveAiEndpoint("NEONPULSE_IMAGE_API_URL", "/api/spirit-image"));
}

function recordAiImageCall() {
  const usage = readAiUsage();
  const profileKey = aiImageProfileKey();
  usage.imageCallsByProfile[profileKey] = Math.max(0, Number(usage.imageCallsByProfile[profileKey]) || 0) + 1;
  saveAiUsage(usage);
}

function aiTextCacheStoreKey() {
  return storageKeyForSession(AI_TEXT_CACHE_STORAGE_KEY) || AI_TEXT_CACHE_STORAGE_KEY;
}

function readAiTextCache() {
  try {
    const raw = localStorage.getItem(aiTextCacheStoreKey());
    const parsed = raw ? JSON.parse(raw) : null;
    return parsed && typeof parsed === "object" ? parsed : {};
  } catch (_err) {
    return {};
  }
}

function saveAiTextCache(cache) {
  const maxEntries = aiConfigInt("textCacheMaxEntries", AI_DEFAULT_CONFIG.textCacheMaxEntries, 20, 400);
  const entries = Object.entries(cache || {})
    .filter(([, item]) => item && typeof item === "object")
    .sort((a, b) => (Number(b[1].createdAt) || 0) - (Number(a[1].createdAt) || 0))
    .slice(0, maxEntries);
  try {
    localStorage.setItem(aiTextCacheStoreKey(), JSON.stringify(Object.fromEntries(entries)));
  } catch (_err) {
    // ignore storage failures
  }
}

function aiTextCacheGet(kind, key) {
  const cacheKey = `${kind}:${key}`;
  const cached = readAiTextCache()[cacheKey];
  return cached && typeof cached === "object" ? cached : null;
}

function aiTextCacheSet(kind, key, payload) {
  if (!kind || !key || !payload) return;
  const cache = readAiTextCache();
  cache[`${kind}:${key}`] = {
    ...payload,
    createdAt: Date.now()
  };
  saveAiTextCache(cache);
}

function supportsAiCollectibleApi() {
  return canRequestAiImage();
}

function normalizeInlineText(value = "") {
  return String(value || "")
    .replace(/\s+/g, " ")
    .trim();
}

function truncateByWordBoundary(text = "", maxChars = 150) {
  const normalized = normalizeInlineText(text);
  if (normalized.length <= maxChars) return normalized;
  const sliced = normalized.slice(0, maxChars);
  const cutAt = sliced.lastIndexOf(" ");
  const safe = cutAt > 24 ? sliced.slice(0, cutAt) : sliced;
  return `${safe.trim()}...`;
}

function splitIntoSvgLines(text = "", maxCharsPerLine = 56, maxLines = 2) {
  const normalized = normalizeInlineText(text);
  if (!normalized || maxLines <= 0 || maxCharsPerLine <= 0) return [];

  const expandedTokens = [];
  normalized.split(" ").filter(Boolean).forEach((word) => {
    if (word.length <= maxCharsPerLine) {
      expandedTokens.push(word);
      return;
    }
    let cursor = 0;
    while (cursor < word.length) {
      const remaining = word.length - cursor;
      if (remaining <= maxCharsPerLine) {
        expandedTokens.push(word.slice(cursor));
        break;
      }
      const chunkSize = Math.max(1, maxCharsPerLine - 1);
      expandedTokens.push(`${word.slice(cursor, cursor + chunkSize)}-`);
      cursor += chunkSize;
    }
  });

  const lines = [];
  let current = "";
  let consumed = 0;

  for (let i = 0; i < expandedTokens.length; i += 1) {
    const token = expandedTokens[i];
    const candidate = current ? `${current} ${token}` : token;
    if (candidate.length <= maxCharsPerLine) {
      current = candidate;
      consumed = i + 1;
      continue;
    }

    if (current) {
      lines.push(current);
      if (lines.length >= maxLines) break;
      current = token;
      consumed = i + 1;
    } else {
      lines.push(token.slice(0, maxCharsPerLine));
      consumed = i + 1;
      if (lines.length >= maxLines) break;
      current = "";
    }
  }

  if (lines.length < maxLines && current) {
    lines.push(current);
  }

  const hasOverflow = consumed < expandedTokens.length;
  if (hasOverflow && lines.length) {
    const lastIndex = Math.min(maxLines, lines.length) - 1;
    let last = lines[lastIndex];
    if (last.length > maxCharsPerLine - 3) {
      last = last.slice(0, Math.max(1, maxCharsPerLine - 3)).trimEnd();
    }
    lines[lastIndex] = `${last.replace(/[.\-…\s]+$/g, "")}...`;
  }

  return lines.slice(0, maxLines);
}

function spiritPrimaryStyleKeys(spirit, limit = 6) {
  return Object.entries(spirit?.styleWeights || {})
    .sort((a, b) => b[1] - a[1])
    .slice(0, limit)
    .map(([style]) => style)
    .filter(Boolean);
}

function spiritVisualFamilyKey(spirit) {
  const styles = new Set(spiritPrimaryStyleKeys(spirit, 8));
  const has = (...values) => values.some((value) => styles.has(value));
  if (has("psycore", "hi_tech")) return "psy_extreme";
  if (has("dark_psy", "forest_psy", "dark_experimental", "slambient", "dark_progressive")) return "psy_dark";
  if (has("psytrance", "goa_trance", "full_on", "full_on_night", "full_on_morning", "progressive_psy", "psy_comercial")) return "psy_bright";
  if (has("trance_uplifting", "tech_trance", "hard_trance")) return "trance";
  if (has("hardstyle", "hardcore", "frenchcore", "speedcore", "rawstyle", "gabber", "schranz")) return "hard_dance";
  if (has("acid_techno", "techno", "hard_techno", "industrial_techno", "minimal_techno", "peak_time_techno", "melodic_techno")) return "techno";
  if (has("ambient", "downtempo")) return "organic";
  if (has("tech_house", "house", "deep_house", "afro_house", "organic_house", "bass_house", "progressive_house", "electro_house")) return "house";
  if (has("drum_and_bass", "liquid_dnb", "neurofunk", "jump_up", "jungle", "dubstep", "riddim", "halftime_bass")) return "bass";
  if (has("breakbeat", "uk_garage", "future_garage", "footwork_juke", "wave")) return "breaks";
  if (has("trap", "future_bass", "experimental_bass", "brazilian_funk")) return "bass";
  if (has("idm", "electro", "uk_garage", "future_garage")) return "experimental";
  return "hybrid";
}

